-- Poems batch 293
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6d38c27c-b71b-438a-a8d3-4268f6c90b7c','訪别成獻甫經歷時新拜西臺御史之命二首  其二','王珪','宋','宋诗','song-poetry','','[]','寒露迎風一段冰，高標孤映宛之濱。',64,'全唐诗/poet.song.28000.json','["寒露迎風一段冰，高標孤映宛之濱。", "人言飈擊須鷹隼，我喜時清覩鳯麟。", "佇看仙班朝北極，暫移星節照西秦。", "皇華禮樂君恩重，好訪巔崖慰遠民。"]'),
('534556df-6813-4f1c-a67b-c51d73a33224','又上監察御史','王珪','宋','宋诗','song-poetry','','[]','一札興賢聖化新，觀光上國已彬彬。',64,'全唐诗/poet.song.28000.json','["一札興賢聖化新，觀光上國已彬彬。", "右文幸際休明世，奉詔猶須牧守臣。", "鵜鴂不爲芳草計，鷦鷯似畏罻羅人。", "軺車到處天恩遍，祗有儒林欠得春。"]'),
('0fe0d549-a754-40fd-a51c-1e5138f0a5cc','普净院避暑呈陸子履學士','王珪','宋','宋诗','song-poetry','','[]','九衢車馬囂囂地，偶過禪房得暫閒。',64,'全唐诗/poet.song.28000.json','["九衢車馬囂囂地，偶過禪房得暫閒。", "畏景未移天正午，凉風己到殿中閒。", "瓜餘玉筯蠲煩肺，冰滿銀壺照病顔。", "元和以前張榜南，院東墻向晚斗城。"]'),
('1c255c88-cc87-4ec6-bf38-13a8fdde8275','東樓','王珪','宋','宋诗','song-poetry','','[]','漢家宫省青槐下，信斷鰲峰日易斜。',64,'全唐诗/poet.song.28000.json','["漢家宫省青槐下，信斷鰲峰日易斜。", "應爲能言鏁鸚鵡，翻愁無思學楊花。", "風波滚滚驚人事，文字孳孳老歲華。", "偶向東樓望春色，歸心不覺到天涯。"]'),
('2226398b-bb98-43be-b3cc-8d7a14c5eac0','呈永叔書事','王珪','宋','宋诗','song-poetry','','[]','詔書初捧下西廂，重棘連催暮鑰忙。',64,'全唐诗/poet.song.28000.json','["詔書初捧下西廂，重棘連催暮鑰忙。", "綠繡珥貂留帝詔，紫衣鋪案拜宸香。", "卷如驟雨收聲急，筆似飛泉落勢長。", "十五年前出門下，最榮今日預東堂。"]'),
('0b6d41b9-c471-4c02-955a-32222d27b16d','再召至龍圖閣觀書','王珪','宋','宋诗','song-poetry','','[]','君王又詔蓬莱宴，三閣崔嵬壓海鼇。',64,'全唐诗/poet.song.28000.json','["君王又詔蓬莱宴，三閣崔嵬壓海鼇。", "翠玉装輿容扈蹕，黄金塗紙看揮毫。", "堯文自與星辰爛，漢殿常依日月高。", "四十年来無此會，恩深不覺醉仙醪。"]'),
('c464445f-2acf-4810-9076-b031f200f2e6','較藝書事','王珪','宋','宋诗','song-poetry','','[]','日薄寒雲下結鱗，忽馳詔騎絕飛塵。',64,'全唐诗/poet.song.28000.json','["日薄寒雲下結鱗，忽馳詔騎絕飛塵。", "麻衣半犯秦關雪，魚鑰横催漢署春。", "黄紙貼名書案密，堂梨雕字賦題新。", "高材頃刻聞天下，誰是墻東冠榜人。"]'),
('bc298b12-693f-4fea-8cae-f8cf7cac2ab5','仁字卷子','王珪','宋','宋诗','song-poetry','','[]','文昌清曉漏聲疏，曾看飛泉落筆初。',64,'全唐诗/poet.song.28000.json','["文昌清曉漏聲疏，曾看飛泉落筆初。", "詩入池塘似靈運，賦傳宫殿學相如。", "春官不下真朱點，陰注將成淡墨書。", "見說丹臺名第一，蘂章須詔侍嚴徐。"]'),
('f96495bf-c451-451a-b511-aff1f04a0649','信字卷子','王珪','宋','宋诗','song-poetry','','[]','春闈只恐有遺材，據案重將信字開。',64,'全唐诗/poet.song.28000.json','["春闈只恐有遺材，據案重將信字開。", "白石謾應歌寗角，黄金枉是起燕臺。", "侵更競看倉惶筆，薄晚誰啣毷氉杯。", "文字須從勤苦得，莫霑雙淚向塵埃。"]'),
('4cc5036a-a5db-491a-bd72-1f08d260ec61','較藝將畢呈諸公','王珪','宋','宋诗','song-poetry','','[]','文昌宮裏柳依依，誰折長條贈我歸。',64,'全唐诗/poet.song.28000.json','["文昌宮裏柳依依，誰折長條贈我歸。", "雨潤紫泥昏詔墨，風吹紅蘂上朝衣。", "玉堂燕子應先入，朱閣楊花已半飛。", "寒食未過春景熟，好同天陌去騑騑。"]'),
('23368fe4-85a4-4632-9586-2e4ff7ea585b','較藝書事再呈永叔并同院諸公','王珪','宋','宋诗','song-poetry','','[]','小雨班班拂曉除，新禽格磔静相呼。',64,'全唐诗/poet.song.28000.json','["小雨班班拂曉除，新禽格磔静相呼。", "眼窺夜卷千花碧，肺渇春盤幾露珠。", "只見樓頭飄落絮，不知門外長青蕪。", "玉階未放金書榜，誰識秦關舊棄繻。"]'),
('efa70823-f1e8-44f9-96dd-42b83d8ac23d','聞喜燕上贈狀元葉祖洽','王珪','宋','宋诗','song-poetry','','[]','黼座親臨唱第初，宴嬉猶及苑花餘。',64,'全唐诗/poet.song.28000.json','["黼座親臨唱第初，宴嬉猶及苑花餘。", "清廂特訪安危策，紫府應將姓字書。", "御酒連傾金鑿落，宫牀曾賜玉蟾蜍。", "從來晁董多奇論，三日英豪亦未疏。"]'),
('e7950cae-6826-476c-b4aa-94a78a4d97f3','呈景仁偶書','王珪','宋','宋诗','song-poetry','','[]','昔對芳樽常感慨，今同華髪半蕭疏。',64,'全唐诗/poet.song.28000.json','["昔對芳樽常感慨，今同華髪半蕭疏。", "唐家一代成青史，漢殿多年誦子虛。", "丹鳳春裁西掖詔，白麻夜草北門書。", "幾時却奉承明謁，玉蘂花邊並直廬。"]'),
('8ed29056-07b5-4045-8d14-92eee50e6298','呈景彝偶書','王珪','宋','宋诗','song-poetry','','[]','一從奉詔銀臺路，下馬成詩奪鳯毫。',64,'全唐诗/poet.song.28000.json','["一從奉詔銀臺路，下馬成詩奪鳯毫。", "東觀已陪窺秘籙，南宫又接較羣髦。", "芝封紫掖文章貴，星近端門氣象高。", "今是漢廷三獨坐，夜吟猶許醉春醪。"]'),
('66cb49d7-b8f7-4eda-b73f-1b2c4fec264c','舟行述懷寄公儀','王珪','宋','宋诗','song-poetry','','[]','昔陪畫省對春菲，今日逢春未得歸。',64,'全唐诗/poet.song.28000.json','["昔陪畫省對春菲，今日逢春未得歸。", "灼灼海棠誰復折，差差燕子又還飛。", "清尊須惜良辰共，白髪俄驚萬事非。", "昨夜淮山好風月，爲君中夕促瑤徽。"]'),
('71668aef-a3d7-46f6-81f5-3fac39bb467a','又寄公儀四首  其一','王珪','宋','宋诗','song-poetry','','[]','紫掖新書換使符，春晴紅旆照行艫。',64,'全唐诗/poet.song.28000.json','["紫掖新書換使符，春晴紅旆照行艫。", "曾持白簡風何厲，更伏青規論益孤。", "月露清吟應到骨，江山别夢欲成圖。", "聞教雙鶴先歸去，還到遼城似舊無。"]'),
('558fdc79-07af-4708-89ed-da6fca34e6ea','又寄公儀四首  其二','王珪','宋','宋诗','song-poetry','','[]','又擁雙旌去守蒲，波從天上泛歸艫。',64,'全唐诗/poet.song.28000.json','["又擁雙旌去守蒲，波從天上泛歸艫。", "青雲慷慨逢辰早，白髪逶迤事主孤。", "薄宦多端非我素，清吟終日是君圖。", "錦江春色年年好，憶把遊人醉袖無。"]'),
('da39fe46-ca66-4c2b-a2b9-86a46dfd3eef','又寄公儀四首  其三','王珪','宋','宋诗','song-poetry','','[]','千里行行近帝都，拍堤新浪喜衘艫。',64,'全唐诗/poet.song.28000.json','["千里行行近帝都，拍堤新浪喜衘艫。", "天涯芳草春過盡，樓北浮雲客望孤。", "醉倚東風輕萬事，夢留滄海阻歸圖。", "爲憐何遜多才思，還信休文带減無。"]'),
('eb29b7f6-f2db-42cc-8b98-64867ad27f11','又寄公儀四首  其四','王珪','宋','宋诗','song-poetry','','[]','花撲行人柳蔭渠，每逢嘉趣爲停艫。',64,'全唐诗/poet.song.28000.json','["花撲行人柳蔭渠，每逢嘉趣爲停艫。", "留連一水風光暮，悵望今宵月影孤。", "漢槖暫持来法從，臯禽還引上仙圖。", "中條侯騎知非遠，肯盡都門别酒無。"]'),
('5b55e2bd-3186-4fc1-b3d8-804ed2e95794','新城寄瓦橋郭太傅','王珪','宋','宋诗','song-poetry','','[]','冰天行絕駕歸軺，十里清烟望界橋。',64,'全唐诗/poet.song.28000.json','["冰天行絕駕歸軺，十里清烟望界橋。", "此夕離音留使節，一心上苑看晴霄。", "燕雲逐馬逢春斷，朔雪霑衣入塞銷。", "寄語當時四并客，東風應已徧柔條。"]'),
('121c386f-147f-439a-993c-640588080aba','寄公闢','王珪','宋','宋诗','song-poetry','','[]','念昔都門手一携，春禽争向苧蘿啼。',64,'全唐诗/poet.song.28000.json','["念昔都門手一携，春禽争向苧蘿啼。", "夢回金殿風光别，吟到銀河月影低。", "舞急錦腰迎十八，酒酣玉醆照東西。", "何時得遂扁舟去，雪棹同君訪剡溪。"]'),
('d50e2bfe-fea8-4cc1-a0a0-4ac1242688d7','上元','王珪','宋','宋诗','song-poetry','','[]','昔年今日從宸遊，綵仗紛紛已御樓。',64,'全唐诗/poet.song.28000.json','["昔年今日從宸遊，綵仗紛紛已御樓。", "半夜衆星來紫極，一春萬火縱丹丘。", "玉欄曾侍看山久，翠醁仍酣賜醴優。", "錦帳宵寒薰易歇，夢魂直欲到天頭。"]'),
('a4e74da8-0d5c-49d2-8e4e-82eb8effba83','自述','王珪','宋','宋诗','song-poetry','','[]','少從客路千波轉，老入流年萬事疏。',64,'全唐诗/poet.song.28000.json','["少從客路千波轉，老入流年萬事疏。", "野鶴定知乘寵誤，春冰多愧踐名虚。", "幾思漢殿金盤露，恣閲蓬山綠字書。", "未報君恩成白髪，翻然江海羡吾廬。"]'),
('f3aa2f46-fbee-4637-a712-0f9c7f38b286','恭和御製上元觀燈','王珪','宋','宋诗','song-poetry','','[]','雲消華月滿仙臺，萬燭當樓寶扇開。',64,'全唐诗/poet.song.28000.json','["雲消華月滿仙臺，萬燭當樓寶扇開。", "雙鳳雲中扶輦下，六鼇海上駕山來。", "鎬京春酒霑周燕，汾水秋風陋漢材。", "一曲昇平人共樂，君王又進紫霞杯。"]'),
('fc962668-ddbf-4145-a30b-1a77ddf328f2','依韻和章樞密景靈宫奉安列聖神御','王珪','宋','宋诗','song-poetry','','[]','清都鐃吹犯宵寒，寶帳雲龍度帝關。',64,'全唐诗/poet.song.28000.json','["清都鐃吹犯宵寒，寶帳雲龍度帝關。", "禁蹕忽傳天直北，仙山元在海中間。", "九門日月蒙嘉氣，六殿衣冠繪晬顔。", "翠輦歸來朝獻罷，千官齊拜未央班。"]'),
('a389075d-d2fa-41fe-aa24-1c8ae773efba','依韻和賈直孺舍人初春祠左太乙二首  其一','王珪','宋','宋诗','song-poetry','','[]','嚴祠初綴漢墀班，爚爚珠熉照幄寛。',64,'全唐诗/poet.song.28000.json','["嚴祠初綴漢墀班，爚爚珠熉照幄寛。", "玉殿威神来帝福，紫垣風骨敵春寒。", "芝華擁盖陰猶合，桂醑流觴飲欲殘。", "拂曉東風迎馬首，鳴珂歸背月珊珊。"]'),
('c426e94f-4611-4074-941f-03ab8f90fffc','依韻和賈直孺舍人初春祠左太乙二首  其二','王珪','宋','宋诗','song-poetry','','[]','太乙靈宫近帝都，夕迎丹節下層虚。',64,'全唐诗/poet.song.28000.json','["太乙靈宫近帝都，夕迎丹節下層虚。", "方從宣室承釐後，更約浮邱把袂初。", "文藻自高鵷掖詔，姓名應冠蘂臺書。", "我慚昔預祠春客，曾夢鈞天侍燕胥。"]'),
('dece0b6a-7e4a-4ec8-9193-aa78a31b76d4','依韻和梅聖俞從登東樓三首  其一','王珪','宋','宋诗','song-poetry','','[]','萬燈初燒寶龍山，御路先迎綵仗還。',64,'全唐诗/poet.song.28000.json','["萬燈初燒寶龍山，御路先迎綵仗還。", "紫極躔星來帝所，仙風逓管落人間。", "芳醪欲泥追嘉節，紅燭翻驚照病顔。", "曾從宸遊燕雙闕，夢魂通夕繞嚴關。"]'),
('c177e990-1e20-4afe-92f1-d83043e5b173','依韻和梅聖俞從登東樓三首  其二','王珪','宋','宋诗','song-poetry','','[]','五雲扶闕對南山，風獵丹邱燒影還。',64,'全唐诗/poet.song.28000.json','["五雲扶闕對南山，風獵丹邱燒影還。", "鳯盖斗回天北畔，瑤臺直到海中間。", "漏寒錦帳遲歸夢，波暖金鍾艷醉顔。", "誰在玉樓歌未足，林梢春鳥已關關。"]'),
('210e9b5e-7acf-4c44-9ed1-f2f59acf2cc8','依韻和梅聖俞從登東樓三首  其三','王珪','宋','宋诗','song-poetry','','[]','雲日暉暉下碧山，誰從滄海宴初還。',64,'全唐诗/poet.song.28000.json','["雲日暉暉下碧山，誰從滄海宴初還。", "香車轣轆紅塵裏，紫闕岧嶤瑞氣間。", "午夜笙歌移法曲，滿城桃李鬭朱顔。", "金吾不禁天街鼓，獨有文闈已上關。"]'),
('a4526423-646c-4196-b915-a20472acd994','和林喬年學士普净院避暑','王珪','宋','宋诗','song-poetry','','[]','汩汩紅塵倦往還，偶來偷得似僧閒。',64,'全唐诗/poet.song.28000.json','["汩汩紅塵倦往還，偶來偷得似僧閒。", "一心自别清凉處，萬事如經夢寐間。", "盡日禪房揮玉麈，幾時仙嶺對冰顔。", "知君有術消煩暑，旋琢瓊瑤出道山。"]'),
('11630fd3-95e5-4ce8-8584-fcaaf808b3e6','和聖俞春雨','王珪','宋','宋诗','song-poetry','','[]','雲飛寒影欲千層，暝雨兼風斷復增。',64,'全唐诗/poet.song.28000.json','["雲飛寒影欲千層，暝雨兼風斷復增。", "羃羃池臺空鏁樹，蕭蕭簾幕更飄燈。", "歸將春晚花應笑，老入年來酒易凌。", "溝水東西人悵望，錦書雖襞爲誰憑。"]'),
('32ccc2d1-0680-4bce-acc3-5b0dca4372fa','依韻和元參政喜雨四首  其一','王珪','宋','宋诗','song-poetry','','[]','歲旱連春與俗憂，忽興嘉雨徧羣州。',64,'全唐诗/poet.song.28000.json','["歲旱連春與俗憂，忽興嘉雨徧羣州。", "郊禾薿薿青如積，宫瓦差差翠欲流。", "良弼爲霖辜宿望，神僧作霧應精求。", "西成喜有登年候，况此新晴見麥秋。"]'),
('bf5e53b7-1858-4d5e-b3e5-d1063e247687','依韻和元參政喜雨四首  其二','王珪','宋','宋诗','song-poetry','','[]','瑤津禱雨見皇憂，誰約金仙下帝州。',64,'全唐诗/poet.song.28000.json','["瑤津禱雨見皇憂，誰約金仙下帝州。", "樓閣繞雲千地湧，魚龍噓水五天流。", "至精自與三靈契，殊例終緣萬宇求。", "柄國老臣無異術，但將嘉蔭續陽秋。"]'),
('1005b747-f815-424f-9972-01a4f0b3161b','依韻和元參政喜雨四首  其三','王珪','宋','宋诗','song-poetry','','[]','紫殿宵祈感聖憂，玉毫曾降梵王州。',64,'全唐诗/poet.song.28000.json','["紫殿宵祈感聖憂，玉毫曾降梵王州。", "慈深三界雲常聚，法徧諸天雨自流。", "襏襫趂耕皆帝力，汙邪滿載爲民求。", "年年睿澤霑羣物，愧未酬恩鬢已秋。"]'),
('bce49ee1-b5aa-4b3e-9186-bd6e8867bc73','依韻和元參政喜雨四首  其四','王珪','宋','宋诗','song-poetry','','[]','君心常與下民憂，嘉應爲霖詎一州。',64,'全唐诗/poet.song.28000.json','["君心常與下民憂，嘉應爲霖詎一州。", "夢繞金人雲氣滿，笑回玉女電光流。", "己成沃野千箱望，豈事靈壇屢舞求。", "邊粟定儲三百萬，臯蘭何必預防秋。"]'),
('6065abc0-4b00-44e8-a2a9-0ec6752b1a8b','和元参政喜雪','王珪','宋','宋诗','song-poetry','','[]','千里同雲向夕繁，風迎嘉雪臘前翻。',64,'全唐诗/poet.song.28000.json','["千里同雲向夕繁，風迎嘉雪臘前翻。", "紫壇轉仗回馳道，玉律驚灰入奉元。", "半夜桂花飄碧海，先春柳絮撲朱門。", "萬方巳有豐年號，不惜當筵醉御樽。"]'),
('ff4a1c29-84cb-47e8-bb32-21afde165628','次胡則大賦雪韻','王珪','宋','宋诗','song-poetry','','[]','凍雀無聲風葉乾，坐來飛霰灑窗寒。',64,'全唐诗/poet.song.28000.json','["凍雀無聲風葉乾，坐來飛霰灑窗寒。", "梅花歲歲如相待，瓊樹朝朝不厭看。", "邑犬倉皇驚越俗，崖松偃亞老秦官。", "衰顔不作安仁様，一任斜吹上鬢端。"]'),
('2787719f-a76d-4acc-9043-8ca9f726d775','又次韻','王珪','宋','宋诗','song-poetry','','[]','吟邊莫放酒杯乾，玉樹瓊樓不奈寒。',64,'全唐诗/poet.song.28000.json','["吟邊莫放酒杯乾，玉樹瓊樓不奈寒。", "授簡誰當梁苑賦，泛舟聊作剡溪看。", "但知盈尺占豐歲，豈爲無氊笑冷官。", "想得題詩呵凍硯，固應清興入毫端。"]'),
('0e89b35c-1612-4f5b-8ac2-b2531097c185','和石昌言舍人酬王景彝學士雪霽有懷','王珪','宋','宋诗','song-poetry','','[]','寒霙飛斷九門深，日上扶桑海氣沈。',64,'全唐诗/poet.song.28000.json','["寒霙飛斷九門深，日上扶桑海氣沈。", "初見雲端浮紫闕，忽驚塵外列瑤林。", "芝封詔墨春生潤，綺結官錢夕帯陰。", "官職聲名君自有，何妨更絕郢中吟。"]'),
('be986010-9087-4f9f-b853-3338aa83661d','和劉原父舍人雪霽早朝','王珪','宋','宋诗','song-poetry','','[]','琪樹無聲粉蘂圓，岧嶤雙闕射雲鮮。',64,'全唐诗/poet.song.28000.json','["琪樹無聲粉蘂圓，岧嶤雙闕射雲鮮。", "寒交玉珮趨三殿，曉拜珠旒下九天。", "仙仗影翻初照月，高門塵絕欲生烟。", "燕餘寶陌騰歸馭，更爲都人賦有年。"]'),
('a8a8b713-49d9-4bf9-8e1a-495769709f4b','依韻和宋次道龍圖館閣暴書','王珪','宋','宋诗','song-poetry','','[]','五雲迎曉禁廬開，不及華衣曳老萊。',64,'全唐诗/poet.song.28000.json','["五雲迎曉禁廬開，不及華衣曳老萊。", "寶藏發函金作界，仙醪傳羽玉爲臺。", "己逢天上非常景，更約人間第一材。", "白首廟堂終乞去，明年此會定應來。"]'),
('5204f8d1-dca0-4fad-9f64-6acad221c905','依韻和張文裕龍圖賀執政入東西府詩','王珪','宋','宋诗','song-poetry','','[]','微生巾褐本蒿萊，叨遇優賢府第開。',64,'全唐诗/poet.song.28000.json','["微生巾褐本蒿萊，叨遇優賢府第開。", "雲繞連甍依象闕，玉調清管下鈞臺。", "幾年憶共鵷鴻侣，今日慚非柱石材。", "莫訝門庭光采盛，金輿親屈帝尊來。"]'),
('ff75040a-a669-4f9c-aa92-b4381842432b','又依韻和吳樞密上史館王相公西府偶成','王珪','宋','宋诗','song-poetry','','[]','潭潭相對府中居，見說論交二紀餘。',64,'全唐诗/poet.song.28000.json','["潭潭相對府中居，見說論交二紀餘。", "喜賜御花新燕後，憶乘天馬並遊初。", "公期異日還伊水，我合窮年老石渠。", "早晚相從掛雙紱，午橋春雨看園蔬。"]'),
('311a2f5d-db98-40cd-a509-8f1a2511d382','依韻和吳樞密上王相公同召赴資政殿聽讀詩義感事','王珪','宋','宋诗','song-poetry','','[]','清曉陳經秘殿中，關睢首化屬周公。',64,'全唐诗/poet.song.28000.json','["清曉陳經秘殿中，關睢首化屬周公。", "人穿豹尾班初上，日轉螭頭講未終。", "述作雖尋前聖遠，討論猶待後賢通。", "漢廷無更矜他說，自有匡衡發帝聰。"]'),
('b1d1d2ae-a57d-4442-9cdb-b860d6dbbea4','依韻和吳樞密正月二日留題曾侍中齋閣','王珪','宋','宋诗','song-poetry','','[]','昨日春風變舊年，連珂來訪紫芝仙。',64,'全唐诗/poet.song.28000.json','["昨日春風變舊年，連珂來訪紫芝仙。", "三朝元仗鴻鈞手，萬里今同不繫船。", "壽酒一傾人共醉，賜書千軸子多賢。", "從前身退如公少，莫把長竿憶渭川。"]'),
('4751e9ce-a6ad-4aac-baa6-2800fcd92938','和景彝正月二十八日偶書','王珪','宋','宋诗','song-poetry','','[]','樹含春色明兼暗，雲带朝寒去復還。',64,'全唐诗/poet.song.28000.json','["樹含春色明兼暗，雲带朝寒去復還。", "未有燕回羅幕上，不知人在玉樓間。", "吟魂幾遶青山曲，醉夢多遊紫府關。", "待得歸時花未老，莫因寥落起愁顔。"]'),
('2ce0a7e2-8395-420e-b426-2a3404eeb2a7','和景彝對花','王珪','宋','宋诗','song-poetry','','[]','林梢拂暁禽初哢，門外經春柳自搖。',64,'全唐诗/poet.song.28000.json','["林梢拂暁禽初哢，門外經春柳自搖。", "可嘆流年催白髪，便将幽意屬芳條。", "玉杯放酒成蕭索，錦帳留燈照寂寥。", "任是名園更風雨，殘枝須插醉明朝。"]'),
('b0e72c9f-d806-4643-8f12-d0aab8e91644','依韻和景彝觀刑部廳燕侍郎畫山水二首  其一','王珪','宋','宋诗','song-poetry','','[]','昔人曾此憐幽壁，醇墨今留隱約間。',64,'全唐诗/poet.song.28000.json','["昔人曾此憐幽壁，醇墨今留隱約間。", "猶帯驚波下滄海，常迎爽氣入朝山。", "苔文半染風霜古，鳥影時過歲月閒。", "誰更瀟湘移雨竹，滿軒疏灑翠成斑。"]'),
('3978c8d6-12b1-40d3-82a7-b319dcff545a','依韻和景彝觀刑部廳燕侍郎畫山水二首  其二','王珪','宋','宋诗','song-poetry','','[]','秋曹壁上奇山水，官冷尤將野趣宜。',64,'全唐诗/poet.song.28000.json','["秋曹壁上奇山水，官冷尤將野趣宜。", "翠竹忽逢行盡處，白雲相伴看多時。", "于今絕筆誰還識，當日清吟亦欠詩。", "猶喜一来重拂拭，慚無佳句續君辭。"]'),
('ba5cfffa-98ba-4ec8-8ef9-c56dea1f79fb','和三司蔡君謨內翰麞猿蘆雁屏二首  其一','王珪','宋','宋诗','song-poetry','','[]','麞猿未省京華見，畫筆新傳思入神。',64,'全唐诗/poet.song.28000.json','["麞猿未省京華見，畫筆新傳思入神。", "綠野春深将戱子，空山月午掛吟身。", "只應有夢須懷土，却爲無機不避人。", "我愛林泉舊時景，常来此處暫相親。"]'),
('65aa7c11-ccf8-4eb3-abb4-792871311114','和三司蔡君謨內翰麞猿蘆雁屏二首  其二','王珪','宋','宋诗','song-poetry','','[]','江蘆初老渡新鴻，誰把高情托畫工。',64,'全唐诗/poet.song.28000.json','["江蘆初老渡新鴻，誰把高情托畫工。", "索索西風尉寒羽，蕭蕭殘日伴疏叢。", "漁舟欲下灘聲急，談麈重揮暑氣空。", "身在計庭歸未得，毎将秋思入圖中。"]'),
('fc95c32c-a3eb-410d-9798-af1b36fbe4a2','依韻和蔡參政導洛','王珪','宋','宋诗','song-poetry','','[]','浩浩洪河一派收，亘山回洛駭陰虬。',64,'全唐诗/poet.song.28000.json','["浩浩洪河一派收，亘山回洛駭陰虬。", "錦張客幔從隋去，龜負神書入宋流。", "波急滿川跳萬鯉，氣温銷凍運千舟。", "誰言伯禹能行水，不見當時爲帝謀。"]'),
('e2f4e8fc-1820-4402-97e5-57f674c7466e','依韻和蔡樞密山藥','王珪','宋','宋诗','song-poetry','','[]','鳳池春晚綠生烟，曾見高枝蔓正延。',64,'全唐诗/poet.song.28000.json','["鳳池春晚綠生烟，曾見高枝蔓正延。", "常伴兔絲留我篋，幾隨竹葉泛君筵。", "誰言御水傳名久，須信睢園得地偏。", "纔獲靈根便親植，一番新葉已森然。"]'),
('896e77bc-44cb-4ae2-83b2-cc07016d104d','依韻和蔡相公宣賜金橘','王珪','宋','宋诗','song-poetry','','[]','翠芳亭畔曉霜寒，朱實離離覆御欄。',64,'全唐诗/poet.song.28000.json','["翠芳亭畔曉霜寒，朱實離離覆御欄。", "况是園林都未有，初無塵土略相干。", "黄欺晚菊垂金砌，圓並明珠落鈿盤。", "珍重九霄新賜得，好同仙露薦朝餐。"]'),
('c24ddcb1-3fbe-43c5-8fbd-0b51fdf8b6b0','依韻和蔡相公侍燕集英殿詩','王珪','宋','宋诗','song-poetry','','[]','春風又侍瑤池宴，帝子初臨黼座傍。',64,'全唐诗/poet.song.28000.json','["春風又侍瑤池宴，帝子初臨黼座傍。", "花覆衣冠多喜氣，雲扶宫殿滿榮光。", "仙人來獻重輪曲，丞相仍裁湛露章。", "身老太平殊未報，年年更得奉君觴。"]'),
('5586f590-b81e-47d4-b57b-c068e6450aac','依韻和景仁聞喜席上作兼呈司馬君實內翰','王珪','宋','宋诗','song-poetry','','[]','奉詔華林事最榮，門前幾度放門生。',64,'全唐诗/poet.song.28000.json','["奉詔華林事最榮，門前幾度放門生。", "三朝遇主惟文翰，十榜傳家有姓名。", "碧海蟠桃和露重，丹山雛鳳入雲清。", "詩書教子終須立，篋裏黄金一顧輕。"]'),
('51c5383c-d106-450b-abd0-1adabab86bf4','依韻和景仁寄河中公儀龍圖','王珪','宋','宋诗','song-poetry','','[]','錦江回日應迢遞，聞道秋來已到城。',64,'全唐诗/poet.song.28000.json','["錦江回日應迢遞，聞道秋來已到城。", "南省深沉春又鎖，東樓悵望雨中情。", "河聲欲轉吞鼙鼓，山色初明照旆旌。", "别後新詩有多少，鍾嶸那得爲君評。"]'),
('c47f5597-bdfd-4de3-b5c3-9b3216e8880e','和公儀上馬','王珪','宋','宋诗','song-poetry','','[]','太微星畔鏁中臺，五歲重叨第衆材。',64,'全唐诗/poet.song.28000.json','["太微星畔鏁中臺，五歲重叨第衆材。", "桃李更饒當日盛，詠觴尤喜一春陪。", "賦成英俊無過漯，詩似神仙並姓梅。", "拂曉便隨新榜出，九門風景馬前來。"]'),
('d113cfa0-fcba-4a9b-bf7c-16ace88b46c9','和公儀飲茶','王珪','宋','宋诗','song-poetry','','[]','北焙和香飲最真，綠芽未雨带旗新。',64,'全唐诗/poet.song.28000.json','["北焙和香飲最真，綠芽未雨带旗新。", "煎須卧石無塵客，摘是臨溪欲曉人。", "雲疊亂花爭一水，鳯團雙影貢先春。", "清風未到蓬莱路，且把吟甌伴醉巾。"]'),
('0ba8fd4c-abe6-4e50-823d-6c17402f8496','和公儀送白鷴于永叔','王珪','宋','宋诗','song-poetry','','[]','清風樓古琴三尺，玉蘂花飛酒幾缸。',64,'全唐诗/poet.song.28000.json','["清風樓古琴三尺，玉蘂花飛酒幾缸。", "月窟憐君霜兔獨，金莖誇我露禽雙。", "白鷴浴雪來春檻，古瓦涵星送曉窗。", "悵望紫微池上鳯，主人才品自經邦。"]'),
('d7542afa-69e3-4568-aba1-d745833569c3','和永叔出省有日書事','王珪','宋','宋诗','song-poetry','','[]','青葱嘉樹鎻連甍，閒憶東樓望遠情。',64,'全唐诗/poet.song.28000.json','["青葱嘉樹鎻連甍，閒憶東樓望遠情。", "禁壘曉烟浮舊色，御溝春水潄新聲。", "杯盤冷落留芳草，簾幕陰沉聽亂鶯。", "漢殿未傳紅蠟燭，到家猶得趁清明。"]'),
('26979719-5e2a-43c0-882f-9e6c2bf131b8','依韻和永叔戱書','王珪','宋','宋诗','song-poetry','','[]','良辰并與賞心難，偶對清樽且共歡。',64,'全唐诗/poet.song.28000.json','["良辰并與賞心難，偶對清樽且共歡。", "夢憶江湖無奈遠，吟牽月露不勝寒。", "曲逢郢雪須歌盡，漏繞宫花幾聽殘。", "朝鎻樓臺空悵望，欲將春恨託飛翰。"]'),
('3edc5bae-27fe-4674-baa4-cbf143b8d5d6','依韻和王宣徽冬燕','王珪','宋','宋诗','song-poetry','','[]','丞相華堂燕斝飛，君恩自與衆心期。',64,'全唐诗/poet.song.28000.json','["丞相華堂燕斝飛，君恩自與衆心期。", "魯臺况值書雲後，漢殿仍經喜雪時。", "便有東風來翠幕，别翻新曲度瑤池。", "可傷衰病無才思，欲續高吟愧色絲。"]'),
('f6af88be-49bc-408a-87b9-dd9eb845e081','劉損齋主簿見示遊廣教和劉朔齋詩次韻','王珪','宋','宋诗','song-poetry','','[]','紅葉村邊白板扉，林間剥啄愧新知。',64,'全唐诗/poet.song.28000.json','["紅葉村邊白板扉，林間剥啄愧新知。", "離居自信難同俗，載酒何時許問奇。", "黄蘖人亡空有寺，錦袍仙去更無詩。", "知君此日登臨意，不比兒曹飽腹嬉。"]'),
('992c758d-0b62-482d-b230-0bfb4222171d','依韻和曾侍中謝二府相顧','王珪','宋','宋诗','song-poetry','','[]','年年常過平津館，解組歸来苦未羸。',64,'全唐诗/poet.song.28000.json','["年年常過平津館，解組歸来苦未羸。", "曉日初臨金闕動，春風正與玉杯期。", "三公就第誰同壽，丞相傳經自有兒。", "感舊不辭今日醉，江湖思去已多時。"]'),
('c2108073-6be7-4684-b6c6-80aa590ca5af','聞种諤米脂川大捷','王珪','宋','宋诗','song-poetry','','[]','神兵十萬忽乘秋，西磧妖氛一夕收。',64,'全唐诗/poet.song.28000.json','["神兵十萬忽乘秋，西磧妖氛一夕收。", "疋馬不嘶榆塞外，長城自起玉關頭。", "君王别繪凌烟閣，将帥今輕定遠侯。", "莫道無人能報國，紅旗行去取凉州。"]'),
('5e767d44-fc5c-459d-9c54-8aa69c93f716','依韻和蔡樞密岷洮恢復部落迎降','王珪','宋','宋诗','song-poetry','','[]','河湟形勝厭西陲，忽覺連營列漢旂。',64,'全唐诗/poet.song.28000.json','["河湟形勝厭西陲，忽覺連營列漢旂。", "天子坐籌星兩兩，將軍歸旆印纍纍。", "稱觴别殿傳新曲，衘璧名王按舊儀。", "江漢一篇猶未美，周宣方事伐淮夷。"]'),
('f3e866b8-8226-4aa1-90a2-812371df13c0','和元厚之平羌','王珪','宋','宋诗','song-poetry','','[]','詔收新土鳯林東，四百年來一戰功。',64,'全唐诗/poet.song.28000.json','["詔收新土鳯林東，四百年來一戰功。", "葱嶺自横秦塞上，金城還落漢圖中。", "輕裘坐款無遺策，折箭來庭有舊風。", "零雨未濛音已捷，不勞歸旅咏周公。"]'),
('c8811bce-9341-47c6-9a44-860961cc8aff','滕學士移河朔','王珪','宋','宋诗','song-poetry','','[]','五鼓聲沈曉色回，北馳馬首望燕臺。',64,'全唐诗/poet.song.28000.json','["五鼓聲沈曉色回，北馳馬首望燕臺。", "舊趨武帳清光近，新會仙山秘典開。", "人惜憇棠餘愛遠，帝忻借箸密謀來。", "邊城消盡還兵喜，誰敵陽關决勝才。"]'),
('62d9e4b2-a306-4485-9374-0df8fa683959','送陸子履修撰出守澶淵','王珪','宋','宋诗','song-poetry','','[]','金門學士富才華，又擁雙旌照水涯。',64,'全唐诗/poet.song.28000.json','["金門學士富才華，又擁雙旌照水涯。", "海日三竿隨放仗，春風五馬去如花。", "帳兵夜握龍泉濕，舞女朝垂錦带斜。", "君看有唐賢太守，風流常是屬詩家。"]'),
('75f025fd-06b7-4b45-8967-386b01af1bad','送富郎中守蘇州','王珪','宋','宋诗','song-poetry','','[]','綠綈傳詔下天畿，驛馭駸駸擁使麾。',64,'全唐诗/poet.song.28000.json','["綠綈傳詔下天畿，驛馭駸駸擁使麾。", "境上人瞻司馬節，里中晝耀買臣衣。", "賓帷華履侵宵會，農野朱轓带雨歸。", "方有壯圖深許國，庾園無計戀芳菲。"]'),
('48c3300b-9083-466e-bc12-9ce1cfdd9678','送富郎中守蘇州','王珪','宋','宋诗','song-poetry','','[]','綠綈傳詔下天畿，驛馭駸駸擁使騑。',64,'全唐诗/poet.song.28000.json','["綠綈傳詔下天畿，驛馭駸駸擁使騑。", "境上人瞻司馬節，里中晝耀買臣衣。", "賓帷華履侵宵會，農野朱轓带雨歸。", "方有壯圖深許國，庾園無計戀芳菲。"]'),
('dbfb0088-1c61-4dd5-b2fc-7d03837503a0','送吳仲庶待制出守長沙','王珪','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','畫船催鼓送將行，一醉離觴下玉京。',64,'全唐诗/poet.song.28000.json','["畫船催鼓送將行，一醉離觴下玉京。", "延閣漏閒空紫槖，洞庭波起獵紅旌。", "曾冠獬廌姦回讋，却佩龍泉種落驚。", "莫向江城嘆卑濕，賈生不似使君榮。"]'),
('703b310f-1047-48dd-8380-118189ee5559','送元厚之待制出守福唐','王珪','宋','宋诗','song-poetry','','[]','南擁旌旗照海傍，甘泉新第從臣章。',64,'全唐诗/poet.song.28000.json','["南擁旌旗照海傍，甘泉新第從臣章。", "三休華閣窺天象，幾日朝衣带御香。", "溪水雙流隨畫楫，茘枝初綠映雕觴。", "頒春莫向常思嶺，歸夢先應到帝鄉。"]'),
('051286ca-17aa-423e-babd-c6e9c7b65f89','送向防禦出守淮陽','王珪','宋','宋诗','song-poetry','','[]','漢符新寄近天畿，便别晨班下曙扉。',64,'全唐诗/poet.song.28000.json','["漢符新寄近天畿，便别晨班下曙扉。", "金印旋成龜左顧，瑤箱嘗認燕雙歸。", "春風滿野紅旌駐，夜雨侵筵翠斝飛。", "况是韋平有家學，須將名譽敵恩輝。"]'),
('9127d127-3a76-4849-bfdd-b1d9413dcda8','送程公闢給事出守會稽','王珪','宋','宋诗','song-poetry','','[]','越州太守何瀟灑，應爲能吟住集仙。',64,'全唐诗/poet.song.28000.json','["越州太守何瀟灑，應爲能吟住集仙。", "雪急紫濛催玉勒，日長青瑣聽薰絃。", "一時冠盖傾離席，半醉珠璣落彩牋。", "自恨君恩渾未報，五湖終負釣魚船。"]'),
('e562e1fc-4e9f-426e-9846-a8016182e94f','送何聖從龍圖將漕河東','王珪','宋','宋诗','song-poetry','','[]','平明捧詔未央宫，全晉山河九曲東。',64,'全唐诗/poet.song.28000.json','["平明捧詔未央宫，全晉山河九曲東。", "官着繡衣驚曼倩，文傳錦里壓揚雄。", "紅旌照日鄰天上，玉劍横秋入塞中。", "每下銀臺南畔路，風塵那復舊時同。"]'),
('3d357feb-241f-49db-a058-ceb14ca10849','送汪叔志赴平江州同知','王珪','宋','宋诗','song-poetry','','[]','鵠袍纔卸便牙緋，笑我山中芰製衣。',64,'全唐诗/poet.song.28000.json','["鵠袍纔卸便牙緋，笑我山中芰製衣。", "姓字兩回香桂籍，聲華一日動天扉。", "政有霜螯須别駕，待呼巴菊壽慈闈。", "千古岳陽登覽地，好詩相寄莫相違。"]'),
('ef58bd53-a315-4cdb-b993-4b4487d8a6a1','奉詔赴瓊林苑燕餞太尉潞國文公出鎮西都','王珪','宋','宋诗','song-poetry','','[]','都門秋色滿旌旗，祖帳容陪醉御巵。',64,'全唐诗/poet.song.28000.json','["都門秋色滿旌旗，祖帳容陪醉御巵。", "功業特高嘉祐末，精神如破貝州時。", "匣中寶劍騰霜鍔，海上仙桃壓露枝。", "昨日更聞褒詔下，别刊名姓入烝彝。"]'),
('b8d9135e-490c-41ce-894d-73f612921f4b','瓊林苑御筵送致政太師潞國文公歸西洛','王珪','宋','宋诗','song-poetry','','[]','祖燕催移玉殿班，都人齊向苑傍看。',64,'全唐诗/poet.song.28000.json','["祖燕催移玉殿班，都人齊向苑傍看。", "古來少有三師退，天下曾將大器安。", "綠野春深花更好，石樓夜午月應寒。", "塵埃抖擻無餘事，却憶磻溪舊釣竿。"]'),
('e2e4f19b-f73c-4524-81e6-b05fce52acfc','和致政太師潞國文公以賜燕玉津園感恩述懷','王珪','宋','宋诗','song-poetry','','[]','玉符初解自逍遙，暫駕安車近九霄。',64,'全唐诗/poet.song.28000.json','["玉符初解自逍遙，暫駕安車近九霄。", "無限高名齊少室，不言休績在三朝。", "好披雲氅呼遼鶴，忽把仙巾換漢貂。", "御苑清明開特燕，莫辭仙醴勸金蕉。"]'),
('92305939-0612-4af6-94ee-bd1ccbf34c31','資善堂御筵送太子少保致仕李柬之歸西京','王珪','宋','宋诗','song-poetry','','[]','紫閣飛章謝寵名，離筵特地敞宫楹。',64,'全唐诗/poet.song.28000.json','["紫閣飛章謝寵名，離筵特地敞宫楹。", "杯深御酒先成醉，衣拂京塵頓覺清。", "少室舊遊窺玉霤，甘盤餘訓薄金籯。", "誰言疏傅東歸盛，不得君王一餞行。"]'),
('e1d24c94-2856-4919-9bd0-31369209a91d','資善堂御筵送尚書刑部侍郎致仕李受歸廬山','王珪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','都門車馬動行塵，詔集華堂寵退臣。',64,'全唐诗/poet.song.28000.json','["都門車馬動行塵，詔集華堂寵退臣。", "延閣带經爲舊老，商山擕杖作歸人。", "燕回天上還侵晚，夢入江南已見春。", "曾抱遺弓泣陵土，此生無復犯龍鱗。"]'),
('c065ec98-614a-471b-b396-1d95b1d68466','送范景仁正議致政歸潁昌','王珪','宋','宋诗','song-poetry','','[]','十年漢殿辭榮去，潁水今歸作故鄉。',64,'全唐诗/poet.song.28000.json','["十年漢殿辭榮去，潁水今歸作故鄉。", "曾賦洞簫真蜀客，能吟夜雨勝何郎。", "放懷雲外追黄鵠，别夢春深過玉堂。", "可惜當年挂冠早，華星不及到文昌。"]'),
('b887973d-3121-4b68-9d5d-afce93d40c23','送公闢給事自州致政歸吳中','王珪','宋','宋诗','song-poetry','','[]','青瑣仙人解玉符，秋風一夜滿江湖。',64,'全唐诗/poet.song.28000.json','["青瑣仙人解玉符，秋風一夜滿江湖。", "曾歌郢水非凡曲，未掃旄頭負壯圖。", "終日望君天欲盡，平生知我世應無。", "扁舟定約元宫保，瀟灑蓮涇二大夫。"]'),
('5c0a7e39-9207-4459-ac5f-d2a38ad0ac0c','送僧惠思歸錢塘','王珪','宋','宋诗','song-poetry','','[]','城邑喧喧非所依，忽生秋思滿巖扉。',64,'全唐诗/poet.song.28000.json','["城邑喧喧非所依，忽生秋思滿巖扉。", "晨跌未雨千花落，晚渡臨風一錫飛。", "定有魚龍窺供鉢，應無塵土上禪衣。", "寶文聖偈誰爲解，只恐林泉亦暫歸。"]'),
('39a6ee50-7e6e-4b14-a2bc-b4cc458a5f2f','送人東歸','王珪','宋','宋诗','song-poetry','','[]','會稽新綬振恩輝，故里人瞻晝錦歸。',64,'全唐诗/poet.song.28000.json','["會稽新綬振恩輝，故里人瞻晝錦歸。", "驪馬在門歌祖席，彩絲當膝戲親闈。", "霜天夕霽丹楓老，水國秋深紫蟹肥。", "遶閣雲山吟有助，高談終日訟筩稀。"]'),
('ba7a50f9-d3d3-4ae7-beec-4d8fd998125b','挽霸州文安縣主簿蘇明允','王珪','宋','宋诗','song-poetry','','[]','岷峨地僻少人行，一日西來譽滿京。',64,'全唐诗/poet.song.28000.json','["岷峨地僻少人行，一日西來譽滿京。", "白首只知聞道勝，青衫不及到家榮。", "元猿夜哭銘旌過，紫燕朝飛挽鐸迎。", "天祿校書多分薄，子雲那得葬鄉城。"]'),
('f6381e47-b54d-4a33-811b-22f3445dc150','贈太師中書令魯國曾宣靖公挽詞二首  其一','王珪','宋','宋诗','song-poetry','','[]','熠熠台符切太微，滿朝文物盡光輝。',64,'全唐诗/poet.song.28000.json','["熠熠台符切太微，滿朝文物盡光輝。", "曾扶聖日攀雲上，便向春風解組歸。", "一代衣冠矜閥閲，同時父子筦樞機。", "人生富貴誰難致，八十如公自古稀。"]'),
('7c2f3389-74ad-412c-a1a5-5dcb392fd73f','贈太師中書令魯國曾宣靖公挽詞二首  其二','王珪','宋','宋诗','song-poetry','','[]','璧宫人去水潺潺，帝輦空臨淚一潸。',64,'全唐诗/poet.song.28000.json','["璧宫人去水潺潺，帝輦空臨淚一潸。", "白玉薦樽陪廟食，黄金灑翰落碑顔。", "星辰掩靄移天上，桃李芬芳滿世間。", "門外沙堤何日盡，只應陰施在銀山。"]'),
('bbcdd197-b137-4465-ac5f-691e38e6a579','工部尚書致仕王懿敏公挽詞','王珪','宋','宋诗','song-poetry','','[]','慷慨當年論太平，諫書雖在已塵生。',64,'全唐诗/poet.song.28000.json','["慷慨當年論太平，諫書雖在已塵生。", "三秋勝氣横金甲，半夜離歌掩玉笙。", "庭下綠槐空自老，匣中長劍爲誰鳴。", "壯圖未就冠先掛，從此無由聽履聲。"]'),
('1edc0a66-8c34-4f07-aca8-56e6dec646aa','贈侍中李良定公挽詞','王珪','宋','宋诗','song-poetry','','[]','悲簫忽犯曉樓鐘，樽酒應非昔餞同。',64,'全唐诗/poet.song.28000.json','["悲簫忽犯曉樓鐘，樽酒應非昔餞同。", "家貴曾還金鉞寵，時清不見玉關功。", "佳城蔓草千年閉，後院繁絃一夕空。", "唯有平陽舊池館，依然芳樹倚東風。"]'),
('fcbbe6be-410a-4469-ad9a-18803b2a4453','贈太子少師元章簡公挽詞','王珪','宋','宋诗','song-poetry','','[]','天子思賢共政塗，中台前日得真儒。',64,'全唐诗/poet.song.28000.json','["天子思賢共政塗，中台前日得真儒。", "正看浴鳳來雖晚，不覺冥鴻去已孤。", "曉月猶臨千里梓，春風又卷五雲圖。", "誰過南蕩青山下，只恐高名自古無。"]'),
('dfa04f70-540f-4010-b92f-4ee90b7c142f','贈禮部尚書邵安簡公挽詞','王珪','宋','宋诗','song-poetry','','[]','獨騎箕尾去凌虚，枉駕追鋒作召車。',64,'全唐诗/poet.song.28000.json','["獨騎箕尾去凌虚，枉駕追鋒作召車。", "衣褐誰陳定羌冊，汗青猶載立儲書。", "春風澤國吟牋冷，夜雨溪堂燕豆疏。", "曾向江湖握君手，相從朝路一華胥。"]'),
('753a9d86-04f1-4f1d-8efd-35e657c2b626','贈太尉呂惠穆公挽詞','王珪','宋','宋诗','song-poetry','','[]','秦川歸騎照山紅，不覺悲簫起暮風。',64,'全唐诗/poet.song.28000.json','["秦川歸騎照山紅，不覺悲簫起暮風。", "天上紫樞深北斗，人間金印獨三公。", "漢庭樽俎奇謀在，隴首旌旂殺氣空。", "見說韋平有家學，莫將文字葬墳中。"]'),
