('c4f08a7d-db07-482f-92c6-b305828b534b','宮詞  其九五','王珪','宋','宋诗','song-poetry','','[]','萱草成窠杏子青，夜聞禁漏曉聞鶯。',32,'全唐诗/poet.song.29000.json','["萱草成窠杏子青，夜聞禁漏曉聞鶯。", "吹回一覺昭陽夢，帳外春風太薄情。"]'),
('ca45c453-456d-4ba5-b4c3-beff8fafe334','宮詞  其九六','王珪','宋','宋诗','song-poetry','','[]','翡翠盤龍裝繡額，真珠雙鳯蹙花球。',32,'全唐诗/poet.song.29000.json','["翡翠盤龍裝繡額，真珠雙鳯蹙花球。", "時聞玉女牽簾笑，箭躍銅壺不算籌。"]'),
('1795e052-72a5-471f-bffd-de7e10cbecf8','宮詞  其九七','王珪','宋','宋诗','song-poetry','','[]','迢遞金壺漏水長，輪更傳點報君王。',32,'全唐诗/poet.song.29000.json','["迢遞金壺漏水長，輪更傳點報君王。", "諸宮各進時新果，盡著龍床駐夜香。"]'),
('9fcb0ae7-a665-4a2b-b994-40f362ab96da','宮詞  其九八','王珪','宋','宋诗','song-poetry','','[]','殿下排塲擊土牛，君王玉仗久遲留。',32,'全唐诗/poet.song.29000.json','["殿下排塲擊土牛，君王玉仗久遲留。", "內人争卜宜春喜，奪得金泥各自收。"]'),
('40d1a51c-543e-4a35-9cc6-61136cfd153e','宮詞  其九九','王珪','宋','宋诗','song-poetry','','[]','千年一偶聖人生，豈特河清海亦清。',32,'全唐诗/poet.song.29000.json','["千年一偶聖人生，豈特河清海亦清。", "瑞應固宜流樂府，行看絲竹有新聲。"]'),
('4249f2c4-d956-4d41-9e16-8785ddebb757','宮詞  其一○○','王珪','宋','宋诗','song-poetry','','[]','沉烟搖碧透金鋪，密下珠簾鎮玉壺。',32,'全唐诗/poet.song.29000.json','["沉烟搖碧透金鋪，密下珠簾鎮玉壺。", "近賜趙昌花雀障，却嫌崔白芰荷圖。"]'),
('63b50810-8faf-4b73-8acd-3279e48f7522','宮詞  其一○一','王珪','宋','宋诗','song-poetry','','[]','小雨霏微潤綠苔，石欄紅杏傍池開。',32,'全唐诗/poet.song.29000.json','["小雨霏微潤綠苔，石欄紅杏傍池開。", "一枝插向銀瓶裏，捧進君王玉殿來。"]'),
('d3dd74aa-56ff-44c2-8659-a29c7cfdfa8f','集英殿乾元節大燕教坊樂語口號','王珪','宋','宋诗','song-poetry','','[]','清蹕傳音紫集來，逡巡萬玉擁鈞臺。',64,'全唐诗/poet.song.29000.json','["清蹕傳音紫集來，逡巡萬玉擁鈞臺。", "南山鎮地符辰算，北斗傾霞入宴杯。", "鎬飲篇中魚演漾，虞韶聲裏鳳徘徊。", "年年赤帝乘離月，長見雲龍帳殿開。"]'),
('2ad5cd3b-7712-4d9b-b888-aa00060de531','集英殿皇子降生大燕教坊樂語口號','王珪','宋','宋诗','song-poetry','','[]','忽覺祥煙繞禁門，寶慈宮裏見皇孫。',64,'全唐诗/poet.song.29000.json','["忽覺祥煙繞禁門，寶慈宮裏見皇孫。", "便令三洞張鈞樂，直許千官醉御樽。", "未曉清風生殿閣，經旬赤氣射乾坤。", "須知此會非常有，遙看天顔一倍溫。"]'),
('5103b80d-ffac-416a-a178-e204b0e4509a','集英殿秋燕教坊樂語口號','王珪','宋','宋诗','song-poetry','','[]','秋光紫翠動南山，天上傳呼御燕頒。',64,'全唐诗/poet.song.29000.json','["秋光紫翠動南山，天上傳呼御燕頒。", "一部梨園吹鳳曲，九重丹闕對龍顔。", "日華初駐金輿仗，霞彩猶浮玉筍班。", "欲識君臣同樂處，萬箱登歲五兵閑。"]'),
('a401bf4b-337d-4673-bfc6-80702bf01045','漁父','王珪','宋','宋诗','song-poetry','','[]','急景易如流水去，浮名終與白雲空。',32,'全唐诗/poet.song.29000.json','["急景易如流水去，浮名終與白雲空。", "何如幾曲秋溪上，醉泛一舟煙雨中。"]'),
('7cd80d1a-1fce-470e-845f-304c52c80a32','草','王珪','宋','宋诗','song-poetry','','[]','裊如垂線軟如茵，古渡蒙茸映燒痕。',90,'全唐诗/poet.song.29000.json','["裊如垂線軟如茵，古渡蒙茸映燒痕。", "解憾有情迷霧雨，恣生閑地雜蘭蓀。", "綠鋪春色圍荒寺，遠襯斜陽接釣村。", "盡，日下重樓望欲迷。", "獨鳥自飛煙漠漠，行人不駐雨凄凄。", "王孫何事征鞍晚，蘭澤空聞杜宇啼。"]'),
('a0a021d6-d919-46a4-b297-a61760d1df62','詩一首','王珪','宋','宋诗','song-poetry','','[]','種竹五七箇，結茅三兩間。',48,'全唐诗/poet.song.29000.json','["種竹五七箇，結茅三兩間。", "稍通溪上路，不礙屋頭山。", "黄葉水去住，白雲風往還。", "生涯只此是，道者少機關。"]'),
('6f523961-9b4f-4111-8c64-f6e85fda57a7','越王樓','王珪','宋','宋诗','song-poetry','','[]','跨險盤危壓古州，至今傳號越王樓。',32,'全唐诗/poet.song.29000.json','["跨險盤危壓古州，至今傳號越王樓。", "山分冷翠侵檐滴，水擘寒聲遶檻流。"]'),
('68b38a61-52cb-430f-90d7-159158a32587','新館','王珪','宋','宋诗','song-poetry','','[]','偏箱嶺惡莫摧輪，遊子思親淚滿巾。',64,'全唐诗/poet.song.29000.json','["偏箱嶺惡莫摧輪，遊子思親淚滿巾。", "萬里有塵遮白日，一行無樹識新春。", "幽禽纔囀已催客，狂石欲奔如避人。", "虜酒相邀絕峰飲，卻因高處望天津。"]'),
('c67638ec-fffd-4dd4-ad05-e5eb9747ae82','就日館','王珪','宋','宋诗','song-poetry','','[]','高原春霽蕩妖氛，使馹重來路始分。',64,'全唐诗/poet.song.29000.json','["高原春霽蕩妖氛，使馹重來路始分。", "雖遠長安初見日，漸親冀北已瞻雲。", "東風未破胡天凍，芳草應連紫陌薰。", "早晚旅魂還舊幹，晨鐘一到玉關聞。"]'),
('2347de1f-824e-48b5-a8d3-9ccc675ec7b2','望京館','王珪','宋','宋诗','song-poetry','','[]','一從絕漠返朱輪，便有東風逐去塵。',64,'全唐诗/poet.song.29000.json','["一從絕漠返朱輪，便有東風逐去塵。", "和氣旋成燕谷暖，使華重照蘇門新。", "山川如避中原執，天地應酣上國春。", "二月塞亭行欲盡，初花猶未識歸人。"]'),
('73178bb6-59d3-48e9-b5d1-2808adc37ca2','柳河館','王珪','宋','宋诗','song-poetry','','[]','柳河山外日暉暉，柳色猶枯草正腓。',64,'全唐诗/poet.song.29000.json','["柳河山外日暉暉，柳色猶枯草正腓。", "陰壑水聲多北注，晴峰雲影盡南飛。", "黄牛擁毳爭春耦，白馬彎弧落暮圍。", "路入隴塵誰與問，桑間胡女避人歸。"]'),
('ab31cf7a-8a2e-4d18-8673-4a3752b1ea90','長興館絕句','王珪','宋','宋诗','song-poetry','','[]','風霜守冢不知年，犬類那思母愛偏。',32,'全唐诗/poet.song.29000.json','["風霜守冢不知年，犬類那思母愛偏。", "卻謝漢恩頒五餌，載令梳洗向山前。"]'),
('d3ed182a-8442-42ca-9050-b0c0aa03383d','一題白馬館','王珪','宋','宋诗','song-poetry','','[]','白馬荒原非路歧，征夫未起雪侵肌。',64,'全唐诗/poet.song.29000.json','["白馬荒原非路歧，征夫未起雪侵肌。", "雁思水國猶南翥，人在冰天更北馳。", "狂吹欲號沙四作，凍雲無賴日西垂。", "平生可是嗟行役，一對胡觴亦自嗤。"]'),
('2ff931cb-559b-4aee-8b6c-30c4da421d1c','南海館中','王珪','宋','宋诗','song-poetry','','[]','嶺外經年逐斷蓬，孤吟廢館幾宵中。',64,'全唐诗/poet.song.29000.json','["嶺外經年逐斷蓬，孤吟廢館幾宵中。", "燈回秋壁耿鄉夢，雨送夜潮飄海風。", "靖節久拋三徑樂，子雲坐漢十金空。", "何時征棹一歸去，江有鱸蓴岸有風。"]'),
('8d52ddd2-d075-4a50-a95a-6a4776786bc6','詩一首','王珪','宋','宋诗','song-poetry','','[]','落日映山岊，萬峰蒼翠深。',48,'全唐诗/poet.song.29000.json','["落日映山岊，萬峰蒼翠深。", "風生九秋意，人動五湖心。", "溪曲半帆出，天遙孤鶩沉。", "白雲空滿目，無處問歸音。"]'),
('43606e6a-f0d7-4590-a4b8-ce07cb78c347','句  其一','王珪','宋','宋诗','song-poetry','','[]','未曉清風生殿閣，經旬赤氣照乾坤。',16,'全唐诗/poet.song.29000.json','["未曉清風生殿閣，經旬赤氣照乾坤。"]'),
('cbacd6d4-454e-4aad-99e5-00fe9f01c88b','句  其二','王珪','宋','宋诗','song-poetry','','[]','十字水中分島嶼，數重花外見樓臺。',16,'全唐诗/poet.song.29000.json','["十字水中分島嶼，數重花外見樓臺。"]'),
('e684579c-e37d-4acc-954e-3a4e7481a214','句  其三','王珪','宋','宋诗','song-poetry','','[]','澤國旅艎衝雨黑，都門祖廟照堤紅。',16,'全唐诗/poet.song.29000.json','["澤國旅艎衝雨黑，都門祖廟照堤紅。"]'),
('7274470b-cc4e-4ce3-934e-1361d4a8cbb9','句  其四','王珪','宋','宋诗','song-poetry','','[]','年年三祝候堯蓂，清曉焚香啟機扃。',16,'全唐诗/poet.song.29000.json','["年年三祝候堯蓂，清曉焚香啟機扃。"]'),
('7ff592fe-17ce-4505-927e-a6f0a9e81c04','句  其五','王珪','宋','宋诗','song-poetry','','[]','禁籞平明帳殿開，華芝初下未央來。',16,'全唐诗/poet.song.29000.json','["禁籞平明帳殿開，華芝初下未央來。"]'),
('c179c0db-ff9b-4464-b29e-a0b09ce221f6','句  其六','王珪','宋','宋诗','song-poetry','','[]','曾向艱危不愛身。',8,'全唐诗/poet.song.29000.json','["曾向艱危不愛身。"]'),
('0013db8c-5bd8-4b83-9078-a31f8beb2539','句  其七','王珪','宋','宋诗','song-poetry','','[]','朱門深鎖不知春，苒苒年光暗中換。',16,'全唐诗/poet.song.29000.json','["朱門深鎖不知春，苒苒年光暗中換。"]'),
('e649b7b3-15bc-4713-9aec-8e9997c66306','句  其八','王珪','宋','宋诗','song-poetry','','[]','柯同庭橘勁，色近御衣深。',12,'全唐诗/poet.song.29000.json','["柯同庭橘勁，色近御衣深。"]'),
('8f5b30bc-fc23-49ec-93e7-ebc22c256952','句  其九','王珪','宋','宋诗','song-poetry','','[]','搖搖牆頭花，脈脈含幽姿。',12,'全唐诗/poet.song.29000.json','["搖搖牆頭花，脈脈含幽姿。"]'),
('ca9ff10a-002d-457c-81e1-0fb8de2f07d2','春獵','司馬光','宋','宋诗','song-poetry','','[]','小苑微寒春鴈飛，石關宫外草萋萋。',64,'全唐诗/poet.song.29000.json','["小苑微寒春鴈飛，石關宫外草萋萋。", "漢家旌斾連圍合，秦國山川入望低。", "花色纔臨珠綴發，柳陰欲傍金堤齊。", "韓嫣承恩來視獸，飛塵遙出建章西。"]'),
('a4c84b75-489e-47a2-b658-39122d193303','八月十五日夜寄友人','司馬光','宋','宋诗','song-poetry','','[]','故人音信絕，對月動相思。',36,'全唐诗/poet.song.29000.json','["故人音信絕，對月動相思。", "清露滴紅葉，此懷當告誰。", "秋風廣陵郭，正是望濤時。"]'),
('d4ec1f55-d094-4a27-b67e-8e453e2de4b0','戲下歌','司馬光','宋','宋诗','song-poetry','','[]','項王初破函關兵，氣壓山河風火明。',128,'全唐诗/poet.song.29000.json','["項王初破函關兵，氣壓山河風火明。", "旌旗金鼓四十萬，夜泊鴻門期曉戰。", "關東席卷五諸侯，沛公君臣相視愁。", "幸因項伯謝前過，進謁不敢須臾留。", "椎牛高會召諸將，寶劍泠泠舞席上。", "咸陽灰燼義帝遷，分裂九州如指掌。", "功高意滿思東歸，韓生受誅不復疑。", "區區蜀漢遷謫地，縱使倒戈何足爲。"]'),
('f0482a36-9462-4fc0-abfc-c845908833cf','烏栖曲二首  其一','司馬光','宋','宋诗','song-poetry','','[]','風破金鋪結綺錢，穿簾入幌舞垂蓮。',32,'全唐诗/poet.song.29000.json','["風破金鋪結綺錢，穿簾入幌舞垂蓮。", "可憐無人夜不曉，起視西窗月華皎。"]'),
('1317c2cd-df65-488a-a976-9c338668f6d0','烏栖曲二首  其二','司馬光','宋','宋诗','song-poetry','','[]','星疏月明漏水長，羅帷翠帳華燈光。',32,'全唐诗/poet.song.29000.json','["星疏月明漏水長，羅帷翠帳華燈光。", "佳人起舞玉釵墮，門外烏棲鴈南過。"]'),
('aaf1e23b-b6c8-45f7-8987-54795317febd','海仙歌','司馬光','宋','宋诗','song-poetry','','[]','東望海波蒼茫浩渺無所極，高浪洪濤黯風色。',124,'全唐诗/poet.song.29000.json','["東望海波蒼茫浩渺無所極，高浪洪濤黯風色。", "翻星倒漢天地黑，陰靈出没互相索。", "東方曈曨景氣清，慶雲合沓吐赤精，蓬萊瀛洲杳如萍。", "遙觀五樓十二城，羣仙劍佩朝玉京。", "祥風縹渺鈞天聲，彩幢翠蓋煙霞生。", "鸞歌鳯舞入帝鄉，紫麟徐驅白鶴翔。", "餐芝茹朮飲玉漿，千年萬年樂未央。"]'),
('41ce40ef-97c1-42d3-86a8-288648f1d6a7','宮漏謠','司馬光','宋','宋诗','song-poetry','','[]','宮漏清高處處聞，六街寂寂夜將分。',176,'全唐诗/poet.song.29000.json','["宮漏清高處處聞，六街寂寂夜將分。", "南下河梁緬詰曲，北瞻禁闕鬰繽紛。", "黄金鎖閉斗城斜，白玉樓通上帝家。", "若木未光潛日月，神仙不動積煙霞。", "銅壺銀箭夜何長，杳杳亭亭未遽央。", "複道迴廊接西掖，千門萬戶遙相當。", "宛轉徘徊不能駐，復出宮城透宮樹。", "宮樹烏飛月欲西，燭光一道照沙堤。", "龍騎聯翩排閶闔，鳯帷岑寂對狻猊。", "廣庭肅肅延冠带，劍佩峥嶸百神會。", "施政發令四海春，廟堂垂衣天宇泰。"]'),
('5e85d8ff-2fe1-4985-8f31-77815de426d4','華州祗役往馮翊留别楚正叔','司馬光','宋','宋诗','song-poetry','','[]','芳菲不得駐，會取餘春還。',24,'全唐诗/poet.song.29000.json','["芳菲不得駐，會取餘春還。", "欲知回首處，渭曲蒼茫間。"]'),
('fd52dccc-8d11-4989-b422-92e32b80544d','孟嘗君歌','司馬光','宋','宋诗','song-poetry','','[]','君不見薛公在齊當路時，三千豪士相追隨。',67,'全唐诗/poet.song.29000.json','["君不見薛公在齊當路時，三千豪士相追隨。", "邑封萬戶無自入，椎牛釃酒不爲貲。", "門下紛紛如市人，雞鳴狗盗亦同塵。", "一朝失勢賓客落，唯有馮驩西入秦。"]'),
('a1482eb0-6913-49f9-9752-64210bb930e7','緱山引','司馬光','宋','宋诗','song-poetry','','[]','王子吹笙去不還，當時舊物唯緱山。',96,'全唐诗/poet.song.29000.json','["王子吹笙去不還，當時舊物唯緱山。", "山深樹老藏遺廟，春月秋風空自閑。", "轘轅左界連商雒，碧瓦朱欄露華薄。", "經時掩戶庭草深，永晝無人澗花落。", "徘徊未下日將西，遙望嵩陽煙景微。", "鶴馭飄颻向何許，林間空見白雲飛。"]'),
('61206792-dbd7-4023-8762-47358aa61912','洛陽少年行','司馬光','宋','宋诗','song-poetry','','[]','銅駝陌上桃花紅，洛陽無處無春風。',64,'全唐诗/poet.song.29000.json','["銅駝陌上桃花紅，洛陽無處無春風。", "青絲尾結連錢驄，相從射獵北邙東。", "流鞭縱鏑未云畢，青山團團載紅日。", "雲分電散無影迹，黄雞未鳴已復出。"]'),
('22ea5a9f-d44d-4455-a585-69ed801b59f7','將軍行','司馬光','宋','宋诗','song-poetry','','[]','赤光滿面脣激朱，虬鬚虎顙三十餘。',98,'全唐诗/poet.song.29000.json','["赤光滿面脣激朱，虬鬚虎顙三十餘。", "腰垂金印結紫綬，諸將不敢過庭除。", "羽林精卒二十萬，注聽鉦鼓觀麾旟。", "肥牛百頭酒萬石，爛漫一日供歡娛。", "自言不喜讀兵法，智略何必求孫吳。", "賀蘭山前烽火滿，誰令小虜驕慢延須臾。"]'),
('c9ecd8e1-8d60-4367-a139-6d611f7eff58','何秀才郊園五首  其一','司馬光','宋','宋诗','song-poetry','','[]','主人耽詩書，樂道深居久。',24,'全唐诗/poet.song.29000.json','["主人耽詩書，樂道深居久。", "挾策往來遊，東岡復南畝。"]'),
('f32eb973-103c-4160-b3e7-de54f221c37e','何秀才郊園五首  其二','司馬光','宋','宋诗','song-poetry','','[]','濁酒不取味，素琴無復絃。',24,'全唐诗/poet.song.29000.json','["濁酒不取味，素琴無復絃。", "何須更清論，相見自蕭然。"]'),
('3ce8a27e-61db-48e3-a814-5acf994846d3','何秀才郊園五首  其三','司馬光','宋','宋诗','song-poetry','','[]','蒼蒼竹林暝，鬰欝松氣寒。',24,'全唐诗/poet.song.29000.json','["蒼蒼竹林暝，鬰欝松氣寒。", "縱横興來筆，欹側醉中冠。"]'),
('591e0840-e1d3-4c87-91e2-ccfcb7c5c0e6','何秀才郊園五首  其四','司馬光','宋','宋诗','song-poetry','','[]','褰裳涉幽澗，日落煙巖空。',24,'全唐诗/poet.song.29000.json','["褰裳涉幽澗，日落煙巖空。", "躊躇待新月，長嘯来清風。"]'),
('6b014b89-cc2e-4415-8bdd-7982640cd8de','何秀才郊園五首  其五','司馬光','宋','宋诗','song-poetry','','[]','夏木繞茅廬，棋酒資清宴。',24,'全唐诗/poet.song.29000.json','["夏木繞茅廬，棋酒資清宴。", "密葉綠藏枝，空聞黄鳥囀。"]'),
('acf1ccd1-60c0-4831-b882-2e446de483a9','夏日過陳秀才園林','司馬光','宋','宋诗','song-poetry','','[]','桑蔭青青紫葚垂，鮮風蕩麥生漣漪。',96,'全唐诗/poet.song.29000.json','["桑蔭青青紫葚垂，鮮風蕩麥生漣漪。", "驅童策馬踏村路，乘興出遊當訪誰。", "槿花籬落圍叢竹，風日蕭疏滿園綠。", "到門下馬問主人，文籍先生其姓陳。", "高談浩浩究今古，不覺林間日將暮。", "茅廬蒿徑幸不遙，不厭頻煩數來去。"]'),
('2c66e597-36e0-45ec-af01-f10dadd9b436','陪同年吳沖卿登宿州北樓望梁楚之郊訪古建中作是詩','司馬光','宋','宋诗','song-poetry','','[]','大禹息洪潦，畫野經九州。',288,'全唐诗/poet.song.29000.json','["大禹息洪潦，畫野經九州。", "波沈露羣山，嶷嶷相嬰鉤。", "漩洄澹兹土，平敞誠寡仇。", "乘高極回望，坦坦無陵丘。", "先王崇皡濟，建祀邦諸侯。", "玉帛從會同，赴告書春秋。", "六雄方逐鹿，爲嬴弱姬周。", "兹爲會戰場，蹀血無時休。", "漢錯削七國，禍生東南陬。", "亞夫閉高壁，坐折彊吳謀。", "典午倒太阿，闢戶延旃裘。", "淮泗漫腥羶，房心掩旄頭。", "人移煙火絕，榛茂豺狼遊。", "唐綱日寖衰，盗起如螟蟊。", "相攜聚萑蒲，袒臂提鉏耰。", "蟠薄數千里，焚劫無餘留。", "聖朝定多壘，劍戟包貔貅。", "蓁蓁荆棘林，膴膴良田疇。", "耒耜趣時雨，黍稷豐歲秋。", "昔爲車騎利，今睹桑麻收。", "我來宦東土，莨菪乘春流。", "行行次符離，固爲親交留。", "樽罍且爲樂，攜手登高樓。", "是時新雨餘，風日方和柔。"]'),
('ff6049d8-e7ba-4e01-9fa7-d5acf15dbec3','燕臺歌','司馬光','宋','宋诗','song-poetry','','[]','萬古蒼茫空盛衰，燕臺賢客姓名誰。',48,'全唐诗/poet.song.29000.json','["萬古蒼茫空盛衰，燕臺賢客姓名誰。", "君看碣石巖中草，寧似昭王擁篲時。", "黄金散盡餘基没，易水蕭條烽火飛。"]'),
('3f13aff3-8805-4b62-bba6-2a6d14041230','楚宮行','司馬光','宋','宋诗','song-poetry','','[]','楚王宮中夜未央，清歌秘舞會華堂。',96,'全唐诗/poet.song.29000.json','["楚王宮中夜未央，清歌秘舞會華堂。", "木蘭爲柱桂爲梁，隨珠和璧爛同光。", "横吹乍鳴秋竹裂，繁絃初度春雨歇。", "九微火樹垂垂滅，羅衣紛紛玉纓絕。", "滿朝冠劍東方明，宮門未啓君朝醒。", "秦關日夜出奇兵，武安君火照夷陵。"]'),
('71889ea7-9589-4941-ad51-d583bfb304c7','塞上','司馬光','宋','宋诗','song-poetry','','[]','胡兵欲下陰山，寒烽遠過蕭關。',28,'全唐诗/poet.song.29000.json','["胡兵欲下陰山，寒烽遠過蕭關。", "將軍貴輕士卒，幾人回首生還。"]'),
('78e68423-db99-44ee-a917-7685688223b8','柳枝詞十三首  其一','司馬光','宋','宋诗','song-poetry','','[]','煙滿上林春未歸，三三兩兩雪花飛。',32,'全唐诗/poet.song.29000.json','["煙滿上林春未歸，三三兩兩雪花飛。", "柳條别得東皇意，映堤拂水已依依。"]'),
('fb9eebbc-a839-4318-9a4c-7eb5b9870dc3','柳枝詞十三首  其二','司馬光','宋','宋诗','song-poetry','','[]','依依高樹出宮牆，搖曳青絲百尺長。',32,'全唐诗/poet.song.29000.json','["依依高樹出宮牆，搖曳青絲百尺長。", "願與宣温萬年樹，年年歲歲奉君王。"]'),
('1d57f317-e9cc-4c19-ba9d-3ee451ca18dd','柳枝詞十三首  其三','司馬光','宋','宋诗','song-poetry','','[]','君王遊豫賞青春，折柳爲弮賜侍臣。',32,'全唐诗/poet.song.29000.json','["君王遊豫賞青春，折柳爲弮賜侍臣。", "莫怪長條低拂地，只緣供掃屬車塵。"]'),
('dc6f9ce7-6532-4f50-9572-9f341fa43b95','柳枝詞十三首  其四','司馬光','宋','宋诗','song-poetry','','[]','屬車隱隱遠如雷，陳后愁眉久不開。',32,'全唐诗/poet.song.29000.json','["屬車隱隱遠如雷，陳后愁眉久不開。", "楊花都不知人意，故入長門宮裏來。"]'),
('ed4ac225-ce4c-4d5a-883f-6e21dd3e2c92','柳枝詞十三首  其五','司馬光','宋','宋诗','song-poetry','','[]','長門宮曉未成粧，結雨縈風蔽瑣窗。',32,'全唐诗/poet.song.29000.json','["長門宮曉未成粧，結雨縈風蔽瑣窗。", "莫令透入華梁鷰，那堪負汝更雙雙。"]'),
('5ba0774c-ca42-4c5a-9fd5-16b2c17b7d55','柳枝詞十三首  其六','司馬光','宋','宋诗','song-poetry','','[]','雙雙春鷰颺雲霄，楚國宮深樂事饒。',32,'全唐诗/poet.song.29000.json','["雙雙春鷰颺雲霄，楚國宮深樂事饒。", "會待急管繁絃際，試取纖條並舞腰。"]'),
('859add03-ffce-457f-9f02-5de75a6cb6ef','柳枝詞十三首  其七','司馬光','宋','宋诗','song-poetry','','[]','舞腰繽紛長樂東，柳間悵飲送春風。',32,'全唐诗/poet.song.29000.json','["舞腰繽紛長樂東，柳間悵飲送春風。", "請君試望邯鄲道，青門裊裊徹新豐。"]'),
('73f59c25-6229-487a-82fb-cc7f345d2699','柳枝詞十三首  其八','司馬光','宋','宋诗','song-poetry','','[]','新豐道上灞陵頭，又送夫君去遠遊。',32,'全唐诗/poet.song.29000.json','["新豐道上灞陵頭，又送夫君去遠遊。", "借問柳枝能寄否，古今共有幾多愁。"]'),
('1ca9d890-1c12-45d6-942d-a137eb24d5c6','柳枝詞十三首  其九','司馬光','宋','宋诗','song-poetry','','[]','多愁尤是别離深，折條相贈各沾襟。',32,'全唐诗/poet.song.29000.json','["多愁尤是别離深，折條相贈各沾襟。", "留住不住居人意，欲去未去行人心。"]'),
('02605a10-6903-4b42-be83-08fedb3aeb4b','柳枝詞十三首  其一○','司馬光','宋','宋诗','song-poetry','','[]','行人白馬去遙遙，初上金堤欲過橋。',32,'全唐诗/poet.song.29000.json','["行人白馬去遙遙，初上金堤欲過橋。", "望塵不見遮人眼，苦怨無情萬萬條。"]'),
('e4b590ae-28f0-416f-b626-5af3d45b37de','柳枝詞十三首  其一一','司馬光','宋','宋诗','song-poetry','','[]','五柳先生門乍開，宅邊植杖久徘徊。',32,'全唐诗/poet.song.29000.json','["五柳先生門乍開，宅邊植杖久徘徊。", "陌頭遙認顔光祿，詰旦先乘瘦馬來。"]'),
('289c4b74-7584-4611-a407-e3f961363f5a','柳枝詞十三首  其一二','司馬光','宋','宋诗','song-poetry','','[]','白雪雖然比絮花，艶陽不得共繁華。',32,'全唐诗/poet.song.29000.json','["白雪雖然比絮花，艶陽不得共繁華。", "爲君故入烏衣巷，飛舞風流謝傅家。"]'),
('bc92ffca-7350-49e3-a952-1afc875c544b','柳枝詞十三首  其一三','司馬光','宋','宋诗','song-poetry','','[]','宣陽門前三月初，家家楊柳綠藏烏。',32,'全唐诗/poet.song.29000.json','["宣陽門前三月初，家家楊柳綠藏烏。", "歡似白花飄蕩去，忍能棄擲博山爐。"]'),
('347a9164-32e3-47bf-bd59-23044673dfce','奉和經略龐龍圖延州南城八詠 迎薫亭','司馬光','宋','宋诗','song-poetry','','[]','華館壓清波，坐待南風至。',24,'全唐诗/poet.song.29000.json','["華館壓清波，坐待南風至。", "須知明牧賢，善達吾君意。"]'),
('4d85e312-03fe-4cb2-b0a4-c7957b2431c9','奉和經略龐龍圖延州南城八詠 供兵磑','司馬光','宋','宋诗','song-poetry','','[]','晨暮響寒泉，飛輪駛風轉。',24,'全唐诗/poet.song.29000.json','["晨暮響寒泉，飛輪駛風轉。", "士飽氣益振，輕與先零戰。"]'),
('a9ec5fd3-b4d2-469d-80e1-659c0e5cf5c0','奉和經略龐龍圖延州南城八詠 柳湖','司馬光','宋','宋诗','song-poetry','','[]','依依煙未歇，漠漠風初靜。',24,'全唐诗/poet.song.29000.json','["依依煙未歇，漠漠風初靜。", "浮花滿波面，不見參差影。"]'),
('93b07f07-22aa-460a-85ef-6cf9afb82986','奉和經略龐龍圖延州南城八詠 飛蓋園','司馬光','宋','宋诗','song-poetry','','[]','軍中富餘暇，飛蓋南城隈。',24,'全唐诗/poet.song.29000.json','["軍中富餘暇，飛蓋南城隈。", "雍容陪後乘，一一應劉才。"]'),
('6dac5e18-100f-432e-b124-a0b47259838e','奉和經略龐龍圖延州南城八詠 翠漪亭','司馬光','宋','宋诗','song-poetry','','[]','雕簷日華動，滉瀁照漪漣。',24,'全唐诗/poet.song.29000.json','["雕簷日華動，滉瀁照漪漣。", "四月芰荷滿，不似在窮邊。"]'),
('f5d2d100-e8f8-40c3-89a3-59d121329a15','奉和經略龐龍圖延州南城八詠 延利渠','司馬光','宋','宋诗','song-poetry','','[]','枝分清淺流，縱横貫城市。',24,'全唐诗/poet.song.29000.json','["枝分清淺流，縱横貫城市。", "還如恩在人，潤澤無終既。"]'),
('f7091ce0-2957-4dd8-9adc-703b53212d4f','奉和經略龐龍圖延州南城八詠 緣雲軒','司馬光','宋','宋诗','song-poetry','','[]','逼漢敞高巖，緣雲結飛閣。',24,'全唐诗/poet.song.29000.json','["逼漢敞高巖，緣雲結飛閣。", "東山草樹曛，致足登臨樂。"]'),
('8b0d7eb3-19c9-4c37-8d74-d396bd085425','奉和經略龐龍圖延州南城八詠 禊堂','司馬光','宋','宋诗','song-poetry','','[]','簫鼓震陽休組練，照芳洲意氣坐中。',32,'全唐诗/poet.song.29000.json','["簫鼓震陽休組練，照芳洲意氣坐中。", "客羞笑山陰遊河，上督役懷噐之寄。"]'),
('25cee630-9267-4cf9-8390-364dbcf5bd63','天馬歌','司馬光','宋','宋诗','song-poetry','','[]','大宛汗血古共知，青海龍種骨更奇。',192,'全唐诗/poet.song.29000.json','["大宛汗血古共知，青海龍種骨更奇。", "網絲舊畫昔嘗見，不意人間今見之。", "銀鞍玉鐙黄金轡，廣路長鳴增意氣。", "富平公子韓王孫，求買傾家不知貴。", "芙蓉高闕北向開，金印紫綬從天來。", "路人回首無所見，流風瞥過驚浮埃。", "如何棄置歸皁棧，踠足垂頭困羈絆。", "精神慘澹筋骨羸，舉目雙睛猶璀璨。", "伏波馬式今已無，子阿肉腐骨久枯。", "舉世無人相騏驥，憔悴不與駑駘殊。", "神兵淬礪精芒在，寶鑑遊塵肯終晦。", "君今鬋剔被鳴鸞，尚能騰踏崑崙外。"]'),
('30508b23-1f60-48c7-9b51-1d2a966fd511','河上督役懷器之寄呈公明叔度時器之鞫獄滄州','司馬光','宋','宋诗','song-poetry','','[]','河災汎東郡，廬井多堙淪。',276,'全唐诗/poet.song.29000.json','["河災汎東郡，廬井多堙淪。", "題輿得賢佐，姁嫗安疲民。", "遂令枯槁餘，稍復蘇陽春。", "伊人屏外飾，倜儻窮天真。", "徒觀浩蕩波，莫測江海津。", "矧兹同府士，一一隨和珍。", "公明抱全德，洞澈無緇磷。", "叔度秉峻節，竦若凌霜筠。", "顧兹不肖材，亦齒幕中賓。", "同依松柏陰，共醉醍醐醇。", "高論探要妙，佳句裁清新。", "有詩縱歡謔，杯案霑衣巾。", "曾無禮節間，但以風期親。", "北州有疑獄，兩造正紛綸。", "當須于公斷，然後無冤人。", "送行出郊岐，揚鞭從此違。", "堤繇春事起，行役未成歸。", "索居如幾日，河草已芳菲。", "徒然掩瑤瑟，坐歎知音稀。", "昨夜西南風，夢中東北飛。", "行行涉滄海，彷彿睹容暉。", "寤思益惆悵，天長羽翼微。", "離懷如柳色，極目正依依。"]'),
('e576803b-fa6e-4711-9fc1-4c176bbadef9','華星篇','司馬光','宋','宋诗','song-poetry','','[]','凉風凈掃雲無迹，海月未生星歷歷。',192,'全唐诗/poet.song.29000.json','["凉風凈掃雲無迹，海月未生星歷歷。", "貝聯珠貫拱北辰，三五縱横此何夕。", "重樓疊榭出秋空，鳷鵲露寒連桂宮。", "瑤井迥臨丹闕外，玉繩斜掛瑣窗中。", "征人遠别空閨悄，鐘漏蕭疏天不曉。", "碧紗展轉無復眠，卧視寒光度華沼。", "漢家賢將戍臨洮，結髪從軍今二毛。", "誰憐身老心猶壯，深入長占太白高。", "豐城古劍沉淪久，匣中夜半雙龍吼。", "乃知神物不自藏，紫氣依稀見牛斗。", "有客離居望所親，遙知清夜會荀陳。", "堤繇未息無由去，不及浮槎河畔人。"]'),
('56a26ab4-79e1-436d-8683-a550e1d98541','宿石堰聞牧馬者歌','司馬光','宋','宋诗','song-poetry','','[]','大河之曲多寛閑，牧田枕倚長堤灣。',160,'全唐诗/poet.song.29000.json','["大河之曲多寛閑，牧田枕倚長堤灣。", "烏栖鵲散堤樹寂，柝木聲稀宵欲闌。", "牧兒跨馬乘涼月，歷歷繞羣高唱發。", "幽情逸氣生自然，往往鳴鞘應疏節。", "歌辭難辨野風高，似述離憂嗟役勞。", "徘徊不斷何妨近，彷彿微聞已復遙。", "長川冷浸秋雲白，露草飜光凝碧色。", "星疏河淡夜初長，展轉空亭奈孤客。", "洞簫音律京君明，可憐骨朽不更生。", "安得使傳哀怨意，爲我寫之羌笛聲。"]'),
('4e44080b-16cf-4015-b576-522ae10f899b','楊白華','司馬光','宋','宋诗','song-poetry','','[]','勸君勿嫌楊花太輕薄，籬下溝中紛漠漠。',66,'全唐诗/poet.song.29000.json','["勸君勿嫌楊花太輕薄，籬下溝中紛漠漠。", "翠鬟婢子不勝愁，掃盡還飛滿朱閣。", "晚來風雨送行春，天無遊絲地無塵。", "雪狂絮亂安可得，孤樹青青愁殺人。"]'),
('96763440-c359-4245-bc9e-ce60ee9a6ef1','都下秋懷呈聶之美','司馬光','宋','宋诗','song-poetry','','[]','愚疏強從仕，趣尚與時乖。',96,'全唐诗/poet.song.29000.json','["愚疏強從仕，趣尚與時乖。", "朅來遊京邑，榮願知誰諧。", "王國富英奇，氣象標巖崖。", "雲鴻送雙目，攀援路可階。", "秋風轉枯葉，颯颯繞寒齋。", "岀門無所之，飛塵滿天街。", "夫君宦未達，猶得稱吾儕。", "解衣換斗酒，且盡平生懷。"]'),
('5d2fac2f-dc97-4e91-964c-56eca221e1f1','陪張龍圖南湖暑飲  其一','司馬光','宋','宋诗','song-poetry','','[]','紅斾縈林却轉，瓊筵就水重開。',28,'全唐诗/poet.song.29000.json','["紅斾縈林却轉，瓊筵就水重開。", "荷香著衣不去，竹色映酒遙來。"]'),
('d1dd61e0-5365-408c-b28a-7970fbe0c9e0','陪張龍圖南湖暑飲  其二','司馬光','宋','宋诗','song-poetry','','[]','樓船瀲灔輕浪，鷗鷺繽紛滿天。',28,'全唐诗/poet.song.29000.json','["樓船瀲灔輕浪，鷗鷺繽紛滿天。", "清歌久之未度，畫梁塵落芳筵。"]'),
('03da59ba-74b2-4383-92e6-bbc840a1a1e8','道傍田家','司馬光','宋','宋诗','song-poetry','','[]','道傍田家翁嫗俱垂白，敗屋蕭條無壯息。',66,'全唐诗/poet.song.29000.json','["道傍田家翁嫗俱垂白，敗屋蕭條無壯息。", "翁攜鎌索嫗攜箕，自向薄田收黍稷。", "静夜偷舂避債家，比明門外已如麻。", "筋疲力敝不入腹，未議縣官租稅足。"]'),
('19c85b57-960d-4106-a943-0c7897f70005','送李汝臣同年謫官導江主簿','司馬光','宋','宋诗','song-poetry','','[]','得喪互循環，古今昧終始。',288,'全唐诗/poet.song.29000.json','["得喪互循環，古今昧終始。", "百歳落其間，僅與毫芒似。", "所以達人心，身外不復紀。", "愁來若亂絲，疏解當以理。", "昔君關外來，籍籍聲華起。", "憑案一濡毫，萬言俱落紙。", "老生闚其文，色若寒灰死。", "閣筆不能下，敢有玼瑕指。", "或時抵卿相，入門俱倒屣。", "閽夫迎受謁，不敢揚眸視。", "解褐吏邊州，長塗初進跬。", "蛟龍得尺水，雙骼方嶷嶷。", "西羌負德澤，飛鏑聳邊鄙。", "添兵十萬餘，斗粟無支擬。", "州郡走符檄，縱横恣鞭箠。", "閭閻浪愁苦，卒食半糠粃。", "上官知君才，悉以儲糧委。", "開倉募平糴，至者車連軌。", "嚴明束吏手，誘諭提民耳。", "留穀受金去，若與同儕市。", "弦朔未云周，露積丘山比。", "曾無轉餉勞，坐飽防秋士。", "幕府上其功，明詔深嘉美。", "爲僚登九寺，長人專百里。"]'),
('ec27de80-b686-4e7f-83e2-02feb4279d32','春日書寄東郡諸同舍','司馬光','宋','宋诗','song-poetry','','[]','滑臺古鎮掲高牙，主人賢厚賓友嘉。',224,'全唐诗/poet.song.29000.json','["滑臺古鎮掲高牙，主人賢厚賓友嘉。", "公庭退休射堂飲，水沈綠李浮甘瓜。", "清言妙諭間詼謔，笑語往反何喧譁。", "别來汎濫若浮梗，塵愁俗累稠於麻。", "提鞭俄蓋觸風日，慘澀滿眼飛埃沙。", "朱門湛湛果深淺，門外日擁千餘車。", "閽人未肯即通刺，指彈手版景欲斜。", "就令入見亦何事，氣象渺邈凌青霞。", "圍棋角智賭勝負，拙者理與功名賖。", "捨之歸入戶庭隘，仰視青天如井蛙。", "後檐數尺地荒穢，不翦欲令生薺花。", "當春寂寂但如此，意恐至外逢紛華。", "奈何勝友百餘里，不可一見如天涯。", "何時更共把巵酒，側身北望空咨嗟。"]'),
('47d90cb0-deaa-4e11-b200-5aae18a999c2','和邵不疑校理蒲州十詩 飲亭','司馬光','宋','宋诗','song-poetry','','[]','飛蓋名僚集，臨流芳宴開。',36,'全唐诗/poet.song.29000.json','["飛蓋名僚集，臨流芳宴開。", "縈紆漱文石，次第傳清杯。", "迴波亦多意，并泛落花來。"]'),
('a5163abd-b3f0-43c9-bda2-17cf7f124abd','和邵不疑校理蒲州十詩 涌泉石','司馬光','宋','宋诗','song-poetry','','[]','蒼然片石寒，百道飛泉吐。',36,'全唐诗/poet.song.29000.json','["蒼然片石寒，百道飛泉吐。", "高堂忽蕭颯，坐失炎蒸苦。", "蛟龍卧欲飛，仰噀秋空雨。"]'),
('e3ad9af6-9b0a-4226-a205-49ab52479ea9','和邵不疑校理蒲州十詩 翠樓','司馬光','宋','宋诗','song-poetry','','[]','條山翠氣横，隱嶙秋空窄。',36,'全唐诗/poet.song.29000.json','["條山翠氣横，隱嶙秋空窄。", "危樓雨初度，卷幌延佳色。", "撲撲滿前軒，嵐光真可摘。"]'),
('a70cbc8b-46c0-4fe0-ac1c-b393a9533cd5','和邵不疑校理蒲州十詩 碧樓','司馬光','宋','宋诗','song-poetry','','[]','烟瓦疊琉璃，危樓半空倚。',36,'全唐诗/poet.song.29000.json','["烟瓦疊琉璃，危樓半空倚。", "歌鐘奉高宴，聲來碧雲裏。", "日暮天四垂，黯澹如秋水。"]'),
('97c59b23-e24e-4518-925b-72bfe968e31b','和邵不疑校理蒲州十詩 靜齋','司馬光','宋','宋诗','song-poetry','','[]','□□□□□，□□□□□。',36,'全唐诗/poet.song.29000.json','["□□□□□，□□□□□。", "聊窺碧甃缺，寒草生歷歷。", "時聞山鳥呼，未得全幽寂。"]'),
('fc59c478-d6f8-4b90-9b06-9a82b29f0da8','和邵不疑校理蒲州十詩 槐軒','司馬光','宋','宋诗','song-poetry','','[]','□□軒已幽，況復植宮槐。',36,'全唐诗/poet.song.29000.json','["□□軒已幽，況復植宮槐。", "簷外陰沉綠，南山雨氣來。", "逍遙不知久，驚此黄花開。"]'),
('721a5000-11f4-4649-9a26-997741042bf7','和邵不疑校理蒲州十詩 涼□','司馬光','宋','宋诗','song-poetry','','[]','□□□□□，□□□□□。',36,'全唐诗/poet.song.29000.json','["□□□□□，□□□□□。", "清風滿四境，豈獨華榱下。", "不若楚臺人，披襟獨蕭灑。"]'),
('1d4e9403-8bb5-428b-ac15-592714b56988','和邵不疑校理蒲州十詩 芙蕖軒','司馬光','宋','宋诗','song-poetry','','[]','荷花爛漫紅，不見方塘水。',36,'全唐诗/poet.song.29000.json','["荷花爛漫紅，不見方塘水。", "嶣嶤結飛閣，苒惹清香裏。", "露重忽欹側，翩然翠禽起。"]'),
('4f252030-13fc-4bd5-a620-efd8a53c3892','和邵不疑校理蒲州十詩 惜花亭','司馬光','宋','宋诗','song-poetry','','[]','春意復蹉蛇，園林日愁寂。',36,'全唐诗/poet.song.29000.json','["春意復蹉蛇，園林日愁寂。", "枝邊綠陰重，砌下紅英積。", "兹亭花最繁，飄零尤可惜。"]'),
('5e2349bf-1acc-49d4-bf9b-30ca26ab0495','和邵不疑校理蒲州十詩 竹軒','司馬光','宋','宋诗','song-poetry','','[]','茂密正當軒，欹垂欲侵案。',36,'全唐诗/poet.song.29000.json','["茂密正當軒，欹垂欲侵案。", "風枝忽交戛，月影爭凌亂。", "誠嘉君子心，匪直林亭玩。"]'),
('6b74ed13-1523-4492-b058-1a904c7ba747','秋日寄山中友人','司馬光','宋','宋诗','song-poetry','','[]','昨夜聽秋風，霜崖幾樹紅。',48,'全唐诗/poet.song.29000.json','["昨夜聽秋風，霜崖幾樹紅。", "心隨新鴈去，宛至碧谿東。", "聖主搜漁釣，林巖今已空。", "胡爲執高節，憔悴久山中。"]'),
('7d332eab-0bdb-4ab9-92e8-79e46a63f24b','和之美舟行雜詩八首 舟中夜坐 其一','司馬光','宋','宋诗','song-poetry','','[]','風柳動蕭疏，寒星浸寥落。',24,'全唐诗/poet.song.29000.json','["風柳動蕭疏，寒星浸寥落。", "中宵四寂然，時有遊魚躍。"]'),
('b2d36a7c-b96e-4bc3-9f73-caf8d14a00b8','和之美舟行雜詩八首 舟中夜坐 其二','司馬光','宋','宋诗','song-poetry','','[]','汀沙落席帆，岸柳縈單舸。',24,'全唐诗/poet.song.29000.json','["汀沙落席帆，岸柳縈單舸。", "小市遠微茫，簇水初燈火。"]'),
('6f07f8d1-66d6-44a0-b165-396398f89f92','和之美舟行雜詩八首 船行遇風','司馬光','宋','宋诗','song-poetry','','[]','蔡水僅成波，不若江湖濬。',24,'全唐诗/poet.song.29000.json','["蔡水僅成波，不若江湖濬。", "誠無傾側憂，纜弱終難進。"]'),
('65e154f8-4302-4d7a-ac1f-aa06b0abd62a','和之美舟行雜詩八首 野花','司馬光','宋','宋诗','song-poetry','','[]','喧喧桃李蹊，何妨笑幽草。',24,'全唐诗/poet.song.29000.json','["喧喧桃李蹊，何妨笑幽草。", "但願保天真，徐共春風老。"]'),
('0ae669ac-c2a5-4276-a223-2d558038d9c5','和之美舟行雜詩八首 水鴨','司馬光','宋','宋诗','song-poetry','','[]','褵縰出短蒲，毰毸浴清水。',24,'全唐诗/poet.song.29000.json','["褵縰出短蒲，毰毸浴清水。", "物忌太鮮明，何妨染泥滓。"]'),
('38375cbc-c81c-467c-916f-279a58d8c447','和之美舟行雜詩八首 魚鷹','司馬光','宋','宋诗','song-poetry','','[]','翩然下林表，不憚風湍惡。',24,'全唐诗/poet.song.29000.json','["翩然下林表，不憚風湍惡。", "得雋輒高飛，爲君羞擊搏。"]'),
('57c9b02a-0278-44ec-9c2c-8cb107efb1bd','和之美舟行雜詩八首 罾魚者','司馬光','宋','宋诗','song-poetry','','[]','弱篠絓輕絲，盡日寒溪側。',24,'全唐诗/poet.song.29000.json','["弱篠絓輕絲，盡日寒溪側。", "獲少近知無，溪魚皆爾識。"]'),
('2a993213-28fe-4eaf-b050-89c96657d23a','和之美舟行雜詩八首 都門路','司馬光','宋','宋诗','song-poetry','','[]','紅塵晝夜飛，車馬古今迹。',24,'全唐诗/poet.song.29000.json','["紅塵晝夜飛，車馬古今迹。", "獨憐道傍柳，慘淡少顔色。"]'),
('528fe1d5-0deb-4b17-a2ca-471434f2923f','吳沖卿直舍閻士安畫墨竹歌','司馬光','宋','宋诗','song-poetry','','[]','閻生畫竹舊所聞，望中一見遙可分。',128,'全唐诗/poet.song.29000.json','["閻生畫竹舊所聞，望中一見遙可分。", "伊予不甚少佳畫，猶愛氣骨高出羣。", "狂枝怒葉凌絹素，勢若飛動爭紛紜。", "蟠根數節出地底，上有積年蒼蘚紋。", "森然直榦忽孤聳，意恐出屋排浮雲。", "秋風颯颯生左右，耳目灑落遺塵氛。", "乃知良工自神解，昧者倣習徒艱勤。", "子猷昔者得收玩，不患終朝無此君。"]'),
('b343e9b6-b369-4081-a132-38dbd3cb9814','和之美河洲四詩  其一','司馬光','宋','宋诗','song-poetry','','[]','冉冉河洲曉，晴霞登木杪。',24,'全唐诗/poet.song.29000.json','["冉冉河洲曉，晴霞登木杪。", "稍見水煙開，孤舟天際小。"]'),
('61cba3d2-6689-44c5-a318-dea2744053b3','和之美河洲四詩  其二','司馬光','宋','宋诗','song-poetry','','[]','杳杳河洲晚，客行殊未返。',24,'全唐诗/poet.song.29000.json','["杳杳河洲晚，客行殊未返。", "目隨林鳥還，心共征鴻遠。"]'),
('8b84c3ba-61ae-4b84-800e-b102807b6490','和之美河洲四詩  其三','司馬光','宋','宋诗','song-poetry','','[]','寂寂河洲夜，蘆花繞墟舍。',24,'全唐诗/poet.song.29000.json','["寂寂河洲夜，蘆花繞墟舍。", "孤客久未眠，窗燈落寒灺。"]'),
('574bd0c0-e6e8-4f48-8012-91177ca89eb3','和之美河洲四詩  其四','司馬光','宋','宋诗','song-poetry','','[]','漠漠河洲雨，依稀辨村聚。',24,'全唐诗/poet.song.29000.json','["漠漠河洲雨，依稀辨村聚。", "時哉鷗鳥羣，凌亂爭鳴舞。"]'),
('8f1ee247-dae3-458c-8edf-d75e92dda421','又和夜雨宿村舍','司馬光','宋','宋诗','song-poetry','','[]','積雨久未闋，豈徒行客憂。',252,'全唐诗/poet.song.29000.json','["積雨久未闋，豈徒行客憂。", "夜聞屋中人，歎息悲田疇。", "方春播殖時，種食皆外求。", "鞭訶犯赤日，酷烈慚羸牛。", "草薉競禾長，從人借鉏耰。", "晨薅戴星起，日闇未能休。", "豈無一時勤，所覬歳有秋。", "今兹昏墊災，大埜成洪流。", "直疑滄海溢，繭栗浮陵丘。", "昔時百丈原，汎汎皆挐舟。", "喬木失端杪，饑鳥下無投。", "黍稷沉黄泥，圭合安可收。", "嗟予乏技能，無以易糠麰。", "販鬻固所昧，敢託市井遊。", "欲依盗賊羣，懦不閑戈矛。", "已哉任天地，無益徒爲愁。", "一身無死所，況爲妻兒謀。", "之美愛物者，凄然涕霑裘。", "一夫有不獲，伊尹爲深羞。", "何當富斯民，比屋囷倉稠。", "惜哉祿秩卑，此志終宜酬。"]'),
('a90e8797-ff6e-436d-9c55-6f2a5cba30f4','送伊闕王大夫歌','司馬光','宋','宋诗','song-poetry','','[]','于嗟古之道邈既遠兮，日陵夷而就衰。',195,'全唐诗/poet.song.29000.json','["于嗟古之道邈既遠兮，日陵夷而就衰。", "羣儒角逐異端競進兮，聖塗榛枳幽昧而難知。", "君獨恥從衆人之後兮，軒然高舉遠取而窮追。", "撥去虹蜺汛掃氛濁兮，廓然廼得睹夫朝曦。", "授邑於雒之南兮，始者既學今得而施。", "歸風俗於醇厚兮，又何西門卓魯之足爲。", "消奸化桀折牙杜蘖兮，寂不知其所之。", "何者爲令之德兮，黄童皓首接手而遊嬉。", "菽粟露積牛羊被野兮，百里獨比於太古之時。", "予願解冠棄佩兮，受一廛於伊之野。", "蓑身笠首兮，同邑民以熙熙。"]'),
('e36f442a-2804-4ca3-a5ad-08a04163bfcf','送韓太祝歸許昌','司馬光','宋','宋诗','song-poetry','','[]','王城名利窟，冠蓋鬰相交。',96,'全唐诗/poet.song.29000.json','["王城名利窟，冠蓋鬰相交。", "夫君獨鳯舉，彯然去喧呶。", "潁水清可濯，箕山高可巢。", "反顧公相榮，一芥浮堂坳。", "□□大吕重，豈知輕斗筲。", "蒼蒼氣象嚴，萬木擁寒郊。", "□□點隈曲，初旭染林梢。", "去去善自將，因聲訪衡茅。"]'),
('a01805da-a8b7-429c-8835-a6feaee2660f','和興宗夜直聽雨','司馬光','宋','宋诗','song-poetry','','[]','□茫凍雨來，入夜勢增急。',108,'全唐诗/poet.song.29000.json','["□茫凍雨來，入夜勢增急。", "縱横挾春風，飄灑相噴吸。", "敗窗端見欺，遽有萬點入。", "先生伏經編，眼冷倍昏澀。", "夜分童僕倦，跛倚厭久立。", "燈火爲溟濛，詩書亦霑濕。", "夫君儲善價，未售不悁悒。", "物華迎霽新，佳賞時將及。", "囷中秫幾何，營釀須汲汲。"]'),
('0e019b91-f4aa-4df6-a34a-c9c26da2044c','和之美諷古  其一','司馬光','宋','宋诗','song-poetry','','[]','曲逆從漢祖，出奇誰與讓。',24,'全唐诗/poet.song.29000.json','["曲逆從漢祖，出奇誰與讓。", "一朝寄天下，不及王陵戇。"]'),
('45e90ff7-880b-4448-a679-83717a53c5cd','和之美諷古  其二','司馬光','宋','宋诗','song-poetry','','[]','海客久藏機，鷗知人未知。',24,'全唐诗/poet.song.29000.json','["海客久藏機，鷗知人未知。", "如何毫末利，管鮑亦相欺。"]'),
('39f966cb-0879-4bbb-806c-3c1bdeb6ced9','和之美二貧詩','司馬光','宋','宋诗','song-poetry','','[]','君子尚仁義，寶用爲身資。',288,'全唐诗/poet.song.29000.json','["君子尚仁義，寶用爲身資。", "其人苟不賢，富饒亦胡爲。", "所以回憲徒，不厭糠與藜。", "當時萬金産，令名傳者誰。", "之美初解褐，爲吏長河湄。", "月得數斗祿，僅足供饘糜。", "謂言家無寶，不必修藩籬。", "囊衣不自暖，乃爲偷意窺。", "穿墉入其室，探取無纖遺。", "從事借之带，同列乞其衣。", "日高服未具，不敢踰門畿。", "蕭條四壁寒，獨立空自嗤。", "援毫引幅紙，書作二貧詩。", "上言運命邅，温飫無時期。", "下嗟職事勞，舊學日以隳。", "乃知賢者心，不獨憂寒饑。", "壈坎雖益多，志業終無衰。", "我實甚貧者，視君猶白圭。", "行年三十餘，碌碌無佗奇。", "庇身太學官，旦夕唯鹽虀。", "讀君二貧作，我事借君詞。", "君誠士林秀，不免青衫卑。", "滿腹豈無才，抱蓄未有施。", "不用固爲小，用之活蒸黎。"]'),
('aa101edc-ecdc-4b7b-8cf1-b9396c47bc53','送薯預苗與興宗','司馬光','宋','宋诗','song-poetry','','[]','客從魏都來，貽我山藷實。',192,'全唐诗/poet.song.29000.json','["客從魏都來，貽我山藷實。", "散之膏土間，春苗比如櫛。", "吾家庭戶狹，樹藝苦其密。", "危根遞扶戴，怒牙猶拂欝。", "興言念伊人，好嗜與我一。", "家蓄桐君書，喜觀氾氏述。", "雖爲簪带拘，雅尚林樊逸。", "分獻取其誠，豈容羞薄物。", "況聞知藥者，餌此等苓朮。", "願益君子年，康直體無疾。", "散誕得寛壤，繁大宜無日。", "蕭梢新蔓抽，苯蒓故叢失。", "入冬霜霰嚴，葉落掊可出。", "伸如猿臂長，拳若熊膰腯。", "拾木爨銅鼎，相期聚書室。", "誰得與其徒，谿茶與山栗。"]'),
('a15ca8b0-087e-4008-a298-45c7cf30f729','答昌言求薯蕷苗','司馬光','宋','宋诗','song-poetry','','[]','冬實散肥壤，春苗動新葉。',48,'全唐诗/poet.song.29000.json','["冬實散肥壤，春苗動新葉。", "雅意非遺人，野情聊自愜。", "何言好事者，求訪來相疊。", "會種十畝餘，坐取詩盈篋。"]'),
('b1a0657b-b329-4874-a71f-6459470a54f0','送冷金牋與興宗','司馬光','宋','宋诗','song-poetry','','[]','蜀山瘦碧玉，蜀土膏黄金。',192,'全唐诗/poet.song.29000.json','["蜀山瘦碧玉，蜀土膏黄金。", "寒谿漱其間，演漾清且深。", "工人剪穉麻，擣之白石砧。", "就溪漚爲紙，瑩若裁璆琳。", "風日常清和，小無塵滓侵。", "時逐賈舟來，萬里巴江潯。", "王城壓汴流，英俊萃如林。", "雄文溢箱篋，爭買傾奇琛。", "夫君乃冠冕，辭氣高千尋。", "十載爲舉首，於今猶陸沉。", "嗟我蓄此紙，才藻不足任。", "願以寫君詩，益爲人所欽。", "縞带豈多物，足明同好心。", "黄鐘聲如雷，豈病無知音。", "請以此爲質，佗年神所臨。", "華軒策駟馬，慎勿忘遺簪。"]'),
('a9f8a7f7-fa50-40fc-8b48-b1aa15df1ad9','謝興宗惠草蟲扇','司馬光','宋','宋诗','song-poetry','','[]','吳僧畫團扇，點綴成微蟲。',204,'全唐诗/poet.song.29000.json','["吳僧畫團扇，點綴成微蟲。", "秋毫宛皆具，獨竊天地功。", "細者及蛛蝥，大者纔阜螽。", "枯枝擁寒蜩，黄蘃粘飛蜂。", "翾然得生意，上下相追從。", "徒觀飛動姿，莫睹筆墨蹤。", "兒曹取真物，細校無不同。", "恐其遂躍去，亟取藏箱中。", "乃知藝無小，意精神可通。", "不與誤圖蠅，能惑紫髯翁。", "子猷狀蟬雀，藏寶傳江東。", "不知古何如，此畫今爲雄。", "人墓木已拱，其徒頗能工。", "舊法存百一，要足超凡庸。", "友人幸爲賜，物薄意何隆。", "玩之不替手，愛重心無窮。", "常如對君子，穆穆來清風。"]'),
('1df49963-a1d7-48e0-836e-ab18ad92cf40','和昌言官舍十題 石榴花','司馬光','宋','宋诗','song-poetry','','[]','靈根逐漢臣，遠自河源至。',48,'全唐诗/poet.song.29000.json','["靈根逐漢臣，遠自河源至。", "流離徧中壤，今兹盡苗裔。", "畏日助殷紅，凍雨滌濃翠。", "宜攜避暑客，花下縱横醉。"]'),
('6c551ce5-3e40-4356-a1d2-d29149985e9d','和昌言官舍十題 薏苡','司馬光','宋','宋诗','song-poetry','','[]','佳實産南州，流傳却山瘴。',48,'全唐诗/poet.song.29000.json','["佳實産南州，流傳却山瘴。", "如何馬伏波，坐取丘山謗。", "夫君道義白，復爲神明相。", "厲氣與流言，安能逞無狀。"]'),
('77d14a26-f980-4f7e-a8df-d92de8343689','和昌言官舍十題 石蘭','司馬光','宋','宋诗','song-poetry','','[]','楚人歌紫蘭，華禁無傳久。',48,'全唐诗/poet.song.29000.json','["楚人歌紫蘭，華禁無傳久。", "循名意兹是，誰得明真否。", "天憐菊性孤，秀發秋風後。", "固令芳物生，聊作黄花友。"]'),
('c4ea07c1-41a3-4f80-8c85-990a1c96c62d','和昌言官舍十題 萱草','司馬光','宋','宋诗','song-poetry','','[]','葉濯宿露翠，花迎朝日黄。',48,'全唐诗/poet.song.29000.json','["葉濯宿露翠，花迎朝日黄。", "昔誰封殖此，儼列侍高堂。", "達士隱於吏，孰爲行與藏。", "逍遙玩永日，自無憂可忘。"]'),
('b46a5143-2c34-47f9-8a96-0901a16b9ef8','和昌言官舍十題 蜀葵','司馬光','宋','宋诗','song-poetry','','[]','白若繒初斷，紅如顔欲酡。',48,'全唐诗/poet.song.29000.json','["白若繒初斷，紅如顔欲酡。", "坐疑仙駕嚴，幢節紛駢羅。", "物性有常妍，人情輕所多。", "菖蒲儻日秀，棄擲不吾過。"]'),
('70742499-688e-466e-b3aa-8aef93eeb7d0','和昌言官舍十題 畦蔬','司馬光','宋','宋诗','song-poetry','','[]','隙土惜荒棄，翦治成春畦。',48,'全唐诗/poet.song.29000.json','["隙土惜荒棄，翦治成春畦。", "講雩時澤洽，葵荏高參差。", "釃渠若貫脉，疏塍如畫棋。", "爲吾謝來客，桔橰毋語機。"]'),
('c8b8dba2-84c1-42dc-aa66-c0d2a12f3dd1','和昌言官舍十題 水紅','司馬光','宋','宋诗','song-poetry','','[]','夢想水鄉遊，階庭植籠古。',48,'全唐诗/poet.song.29000.json','["夢想水鄉遊，階庭植籠古。", "宛如江外行，高帆落寒浦。", "煙枝靜疏秀，風穗閑低舉。", "於今看未好，漠漠宜秋雨。"]'),
('6db0dbfe-ec70-4f48-8b7d-24e7c307799b','和昌言官舍十題 甘菊','司馬光','宋','宋诗','song-poetry','','[]','野菊細瑣物，籬間私自全。',48,'全唐诗/poet.song.29000.json','["野菊細瑣物，籬間私自全。", "徒因氣味殊，不爲庖人捐。", "采升白玉堂，薦以黄金盤。", "願若南陽守，永扶君子年。"]'),
('d5e1928a-96df-4607-91ee-c05931b3a589','和昌言官舍十題 蘭','司馬光','宋','宋诗','song-poetry','','[]','賢者非無心，園夫自臨課。',48,'全唐诗/poet.song.29000.json','["賢者非無心，園夫自臨課。", "蓻植日繁滋，芬芳時入座。", "青蔥春茹擢，皎潔秋英墮。", "正苦郢中人，逸唱高難和。"]'),
('a6c30117-47d8-44bc-906e-8944cc372d6c','和昌言官舍十題 病竹','司馬光','宋','宋诗','song-poetry','','[]','園竹久不治，蕪没真可弔。',48,'全唐诗/poet.song.29000.json','["園竹久不治，蕪没真可弔。", "豈無枯槁容，蕭疏自殊調。", "至人愛高節，命斧除藜藋。", "何用報至恩，清陰與長嘯。"]'),
('ea2761e4-a132-421a-9358-df46431ddc47','送文慧師歸眉山','司馬光','宋','宋诗','song-poetry','','[]','至人心如雲，去住唯所適。',96,'全唐诗/poet.song.29000.json','["至人心如雲，去住唯所適。", "飄颻涉四海，豈復校喧寂。", "朅來王城遊，紅塵曖晨夕。", "忽思還故峰，不可留宿昔。", "離合皆自然，於何寄驩戚。", "從兹坐林下，白首傲泉石。", "山鳥集掌中，巴猿侍瓶錫。", "寺前煙蔓深，何處求行跡。"]'),
('1a0b350a-0b9a-4ecf-89ec-d567c7d71dff','風林石歌','司馬光','宋','宋诗','song-poetry','','[]','聞君家有風林石，鐫刻無痕畫無迹。',80,'全唐诗/poet.song.29000.json','["聞君家有風林石，鐫刻無痕畫無迹。", "靡然合勢俱左傾，偃蹇常如負風力。", "置之坐側野意生，静聽若有颼颼聲。", "忽疑身世在丘壑，使我蕭然無俗情。", "黄金白璧豈非好，子直視之不爲寶。"]'),
('e3ccc172-b8b6-4448-9687-e727587399be','興宗南園草盛不翦僕過而愛之爲詩以贈','司馬光','宋','宋诗','song-poetry','','[]','君家在何許，遠與南城鄰。',132,'全唐诗/poet.song.29000.json','["君家在何許，遠與南城鄰。", "車馬不甚繁，門前無俗塵。", "有園廢鉏治，繞舍皆荆榛。", "入夏益滋蔓，鬖鬖高没人。", "豈無舊桃李，蕪雜與之均。", "謂言彼草木，於我奚疏親。", "於間置取舍，豈得完天真。", "不若任其然，同受雨露仁。", "物性且不違，人心何緇磷。", "閉戶不迎客，箕踞無冠巾。", "苟忘軒冕心，何異巢居民。"]'),
('b1cf4a3b-a5dc-4ff5-9f64-8b6281174594','古詩贈興宗','司馬光','宋','宋诗','song-poetry','','[]','窮達有常分，得喪難豫言。',240,'全唐诗/poet.song.29000.json','["窮達有常分，得喪難豫言。", "古今浩茫茫，倚伏安可原。", "軒裳彼自榮，舉俗同崩奔。", "錙銖校重輕，冰火殊涼温。", "君子固無愧，立身明本根。", "度矩苟不愆，寵辱徒喧喧。", "有如清濟流，横貫長河渾。", "景公馬千駟，南面雄東藩。", "陶青劉舍徒，位爲丞相尊。", "當時非不顯，磨滅何足論。", "顔回在陋巷，藜藿甘盤飧。", "原憲結弊衣，蓬蒿塞其門。", "當時豈不窮，至今榮名存。", "況君齒方壯，德業素所敦。", "安知搨翅歸，不作凌雲飜。", "要之白首期，壯烈施元元。", "爲君畫善策，灑掃清前軒。", "長舒四五榻，客來輒開樽。", "群愁喜伺人，稍醒必煩冤。", "拒之亦無佗，體中常昏昏。"]'),
('195d6187-8a95-451d-8c47-b38d9b990194','出都日塗中成','司馬光','宋','宋诗','song-poetry','','[]','賤生習山野，愚陋出於骨。',132,'全唐诗/poet.song.29000.json','["賤生習山野，愚陋出於骨。", "雖爲冠带拘，性非樊籠物。", "揚鞭出都門，曠若解徽紼。", "是時天風惡，靈沼波蕩汩。", "龍鬛互騫騰，鷗羣遠浮没。", "川原寖疏豁，煙火稍蕭瑟。", "草木雖未榮，春態先彷彿。", "桑稀林已斜，柳弱條可屈。", "蛛絲罥晴陽，鼠土壅新窟。", "徐驅款段馬，放轡不呵咄。", "與爾同逍遙，紅塵免蓬勃。"]'),
('0ce9c4de-de85-492d-a171-d8708f6ad691','重經車輞谷','司馬光','宋','宋诗','song-poetry','','[]','昔年道經車輞谷，直上七里鹽南坡。',96,'全唐诗/poet.song.29000.json','["昔年道經車輞谷，直上七里鹽南坡。", "今年行役復到此，方春流汗如飜波。", "中塗太息坐盤石，涕泗不覺雙滂沱。", "我生微尚在丘壑，強若麋鹿嬰虞羅。", "人踰三十只有老，後時過此知如何。", "雲泉佳處須速去，登山筋力行蹉跎。"]'),
('c7a1f4ed-a759-4e03-9d2e-b9f8f3d65dd6','送巢縣崔尉崔尉','司馬光','宋','宋诗','song-poetry','','[]','弱歲家淮南，常愛風土美。',180,'全唐诗/poet.song.29000.json','["弱歲家淮南，常愛風土美。", "悠然送君行，思逐高秋起。", "巢湖映微寒，照眼正清泚。", "低昂蹙荷芡，明滅縈葭葦。", "銀花鱠肥魚，玉粒炊香米。", "居人自豐樂，不與佗鄉比。", "況得良吏來，倍復蒙嘉祉。", "君爲太學生，氣格已英偉。", "登科如拾遺，舉步歘千里。", "毋嫌位尚微，觀政此爲始。", "尊公久場屋，上國困泥滓。", "豈不重相離，念子勉爲理。", "當令佳譽新，燁燁滿人耳。", "高堂雖在遠，聞之足爲喜。", "何必羞三牲，然後稱甘旨。"]'),
('629f994a-c3de-48f8-9d1d-cb38f9bae0b6','酬宋次道初登朝呈同舍','司馬光','宋','宋诗','song-poetry','','[]','林葩積浮脆，煙霧矜春姿。',120,'全唐诗/poet.song.29000.json','["林葩積浮脆，煙霧矜春姿。", "山桂結芳堅，冰霰横秋枝。", "夫君名卿嗣，華實雙葳蕤。", "如何仕不偶，通籍鬢生絲。", "豈非秋桂類，不足煩嗟咨。", "我今三十餘，汩没無佗奇。", "正恐食浮人，敢言位猶卑。", "同登天子廷，自視誠非宜。", "清朝正求治，諌路方坦夷。", "太平可立致，此任非君誰。"]'),
('2e607eb1-b113-4ed5-ba58-227a5e5a6add','奉同范景仁宋次道太常致齋韓廷評見過閽人不時內韓去乃知爲詩謝之','司馬光','宋','宋诗','song-poetry','','[]','端居太常署，寒日淡孤清。',156,'全唐诗/poet.song.29000.json','["端居太常署，寒日淡孤清。", "取酒呼諸友，談笑方縱横。", "韓君士林秀，四海依高名。", "家襲鍾鼎貴，身無簪組縈。", "逍遙風塵外，萬物秋毫輕。", "未嘗妄過人，所過以爲榮。", "如何枉玉趾，及門失相迎。", "主人豈傲客，事有迷悞并。", "追延既不及，相視徒嗟驚。", "威鳳顧脩梧，不下還孤征。", "景星欻呈彩，旋有流雲生。", "靈物固難覩，俗眼真不明。", "投謝有何物，珉石從雙瓊。"]'),
('322813c5-09d6-442d-a869-a9bb15ddf907','送守哲歸廬山','司馬光','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','哲公金陵來，神韻自孤秀。',192,'全唐诗/poet.song.29000.json','["哲公金陵來，神韻自孤秀。", "京華三十春，高節愈幽茂。", "烜赫公卿門，道俗日奔走。", "自非趣尚合，一息不相就。", "慷慨賢豪士，波溢千金富。", "蔬飯苟有餘，秋毫未嘗受。", "嚻呶不可變，堅白如瓊琇。", "居然尚愁寂，終厭塵土臭。", "忽思香爐雲，薈蔚冠孤岫。", "振衣尋昔遊，煙霞宛如舊。", "絡木藤蔓長，攫石松根瘦。", "瀑泉響夜壑，乳管添春竇。", "茅茨蔭方丈，宴坐度清晝。", "几席雨奇花，階除馴猛獸。", "方知物外樂，回視人寰陋。", "慎勿露聲光，愚迷將輻湊。"]'),
('2d42226e-2daa-4b6e-a264-e483673360a8','清明後二日同鄰幾景仁次道中道興宗元明秉國如晦公疎飲趙道士東軒','司馬光','宋','宋诗','song-poetry','','[]','寂寥清明後，餘春已無多。',48,'全唐诗/poet.song.29000.json','["寂寥清明後，餘春已無多。", "閑軒冨佳致，不惜載酒過。", "水木晚尤秀，風煙晴更和。", "臨樽不盡醉，奈此芳菲何。"]'),
('40512770-9685-4ff4-8139-dee1a30a28dd','和端式十題 春塘冰','司馬光','宋','宋诗','song-poetry','','[]','春塘含薄冰，淅瀝隱隈曲。',36,'全唐诗/poet.song.29000.json','["春塘含薄冰，淅瀝隱隈曲。", "晴日射寒芒，柔風折哀玉。", "草樹曾未知，波光已先綠。"]'),
('4385cea2-40c2-406a-bf71-56c2474f33b8','和端式十題 煙際鐘','司馬光','宋','宋诗','song-poetry','','[]','蒼茫返照收，羃歷寒煙起。',36,'全唐诗/poet.song.29000.json','["蒼茫返照收，羃歷寒煙起。", "前山黯同色，不辨峰巒美。", "獨有遠來鐘，悠揚翠微裏。"]'),
('c7b903a5-526a-4f6f-8cd4-2ef11f4cffe2','和端式十題 汀洲蘋','司馬光','宋','宋诗','song-poetry','','[]','秋江□澹蕩，波急枝難定。',36,'全唐诗/poet.song.29000.json','["秋江□澹蕩，波急枝難定。", "參差碧葉繁，皎潔寒花静。", "幽人吟不歸，獨立汀洲瞑。"]'),
('2573d5fb-dc0c-4875-9cba-38f443f160d6','和端式十題 漁洲火','司馬光','宋','宋诗','song-poetry','','[]','漁翁繫葉舟，遠映楓林宿。',36,'全唐诗/poet.song.29000.json','["漁翁繫葉舟，遠映楓林宿。", "手携雙白魚，呼兒爨山竹。", "深夜寂無人，明滅寒江曲。"]'),
('cb0cc70e-411d-4115-b2fd-ab8a22f623e5','和端式十題 寒溪石','司馬光','宋','宋诗','song-poetry','','[]','穹石正嶄巖，寒流更清急。',36,'全唐诗/poet.song.29000.json','["穹石正嶄巖，寒流更清急。", "霜飛敗葉擁，波濺蒼苔濕。", "谿僧勿劇來，沙鶴方孤立。"]'),
('d2c7b57c-760f-4896-9bbc-0dcc09f33827','和端式十題 幽谷泉','司馬光','宋','宋诗','song-poetry','','[]','深谷窅無底，空聞泉水哀。',36,'全唐诗/poet.song.29000.json','["深谷窅無底，空聞泉水哀。", "時因秋日照，微見碧縈回。", "谷裏非人境，胡麻何處來。"]'),
('f643e08d-a3c9-4c27-b9d5-96cd7ee1aaa3','和端式十題 秋原菊','司馬光','宋','宋诗','song-poetry','','[]','高原向搖落，叢菊始滋榮。',36,'全唐诗/poet.song.29000.json','["高原向搖落，叢菊始滋榮。", "草際浮金碧，照人雙目明。", "何須夭生理，玉斝泛餘英。"]'),
('6cab39a1-82d5-4b50-bb5e-c86d27d2ac7b','和端式十題 垂崖鞭','司馬光','宋','宋诗','song-poetry','','[]','山竹引春根，垂透蒼崖底。',36,'全唐诗/poet.song.29000.json','["山竹引春根，垂透蒼崖底。", "綢直老龍鬚，佶屈修蛇尾。", "支郎雖畜馬，不忍裁爲箠。"]'),
('7871e76a-0f52-4a89-8cbc-578d05758573','和端式十題 古木陰','司馬光','宋','宋诗','song-poetry','','[]','古木夏陰薄，蕭蕭蠧葉微。',36,'全唐诗/poet.song.29000.json','["古木夏陰薄，蕭蕭蠧葉微。", "豈無綠樹濃，愛此風煙姿。", "高僧此休息，肩倚瘦筇枝。"]'),
('9368a0ee-136f-4e57-86a3-a24f381ce7b7','和端式十題 天外峰','司馬光','宋','宋诗','song-poetry','','[]','飛鳥去不息，長空黯何極。',36,'全唐诗/poet.song.29000.json','["飛鳥去不息，長空黯何極。", "疏峰带夕暉，點綴秋天碧。", "禪觀坐超然，相望兩沈寂。"]'),
('dbb2b0b9-04fa-4fa5-bddb-55560f1f616b','晉康陳生家世以孝悌聞有異木連理生其庭郡欲旌表其門不果王禹玉爲之求詩於朝之士大夫以紀之','司馬光','宋','宋诗','song-poetry','','[]','靈珠蟠泥沙，積水不能掩。',144,'全唐诗/poet.song.29000.json','["靈珠蟠泥沙，積水不能掩。", "賢人畜美德，久矣自標檢。", "陳生世同財，百口共豐儉。", "遠居嶺海間，天質非陶染。", "邦人慕其行，鬬辨日衰減。", "祥木并殊柯，童童植軒檻。", "或欲揭其門，令人識儀範。", "愚公私不然，外奬由內歉。", "已能孝悌著，默致神靈感。", "何必賜牛酒，然後明襃貶。", "況兹詩詠末，瑣瑣事鉛槧。", "才薄不敢辤，適能爲汙點。"]'),
('825a3e75-519c-4ba5-96d6-18df3fec9a2e','送邵興宗之丹陽','司馬光','宋','宋诗','song-poetry','','[]','赤日裂后土，萬家如烘爐。',72,'全唐诗/poet.song.29000.json','["赤日裂后土，萬家如烘爐。", "君行何事役，似爲貧所驅。", "埃塵稍去眼，雲景日蕭疏。", "扁舟乘長風，倐忽變三吳。", "六年羈旅倦，一旦誰掃除。", "慎勿忘回首，浩蕩江山娛。"]'),
('83db5722-697e-461f-8ae3-7dff8c8ecfc4','癭盆','司馬光','宋','宋诗','song-poetry','','[]','癭盆生以醜自鬻，突兀當軒聳羣目。',128,'全唐诗/poet.song.29000.json','["癭盆生以醜自鬻，突兀當軒聳羣目。", "海鼃鬭怒腹幹張，老鮫蟠蟄鱗鬐秃。", "昔時仙客浮孤槎，波痕漬朽成凹窪。", "蜀都買卜置之去，爾來流落嚴遵家。", "誰逄好事得寶蓄，裁供盥濯真可辱。", "況爲飲具承歡娛，未必蟠根勝珠玉。", "不若刳爲太古尊，滿斟明水羞百神。", "凷桴葦籥薦忠信，坐使風俗還深淳。"]'),
('22327b94-05b9-4a98-af07-37bc2b69388f','送張兵部知遂州','司馬光','宋','宋诗','song-poetry','','[]','劍嶺横天古棧微，相如重駕傳車歸。',64,'全唐诗/poet.song.29000.json','["劍嶺横天古棧微，相如重駕傳車歸。", "雙親倚門望已久，千騎踏雪行如飛。", "人間富貴非不有，似君榮耀真亦稀。", "聞道西州遺畫像，使我涕淚空沾衣。"]'),
('1bc11e27-6ef8-49de-a5e0-493b59ee4ca9','同舍會飲金明沼上書事','司馬光','宋','宋诗','song-poetry','','[]','日華駘蕩金明春，波光凈綠生魚鱗。',128,'全唐诗/poet.song.29000.json','["日華駘蕩金明春，波光凈綠生魚鱗。", "煙深草青遊人少，道路苦無車馬塵。", "石渠諸君職事簡，載酒擷花畏花晚。", "浮舟逐勝任所之，箕踞狂歌叩舷板。", "眼花耳熱氣愈豪，擲杯擊案聲嗷嗷。", "驚沙颯颯繞洲渚，魚龍遷去避我曹。", "人生大料無百歲，貴賤賢愚同一致。", "在家殽蓛餘幾何，一日風光不宜棄。"]'),
('ed85e339-e62f-4dcb-9237-f8de6b2533fd','和梅聖俞詠昌言五物 括蒼石屏','司馬光','宋','宋诗','song-poetry','','[]','主人小石屏，得之括蒼山。',108,'全唐诗/poet.song.29000.json','["主人小石屏，得之括蒼山。", "括蒼道里遠，致此良亦難。", "層崕萬仞餘，騰出浮雲端。", "吳兒采石時，蘿蔓愁攀緣。", "石文狀松雪，毫髪皆天然。", "置之坐席旁，清風常在顔。", "願君善藏蓄，永日供餘閑。", "慎勿示要人，坐致求者繁。", "將使括蒼民，吁嗟山谷間。"]'),
('ee0f4921-387e-4181-bf3c-af110b78dbe5','和梅聖俞詠昌言五物 淡樹石屏','司馬光','宋','宋诗','song-poetry','','[]','昔行鞏洛間，馬瘦天復陰。',120,'全唐诗/poet.song.29000.json','["昔行鞏洛間，馬瘦天復陰。", "寒煙淡不收，一拂横長林。", "當時無畫工，負此清賞心。", "今朝石上迹，歷歷皆可尋。", "輕素已紛泊，老榦仍蕭森。", "坐令高興還，野氣生衣襟。", "丹青不耐久，風日易消侵。", "何如造化真，更彼歲月深。", "昌言家素貧，購此糜百金。", "請鐫好事名，千古無消沈。"]'),
('d3daa2cc-00db-469f-a987-53037e3c7c03','和梅聖俞詠昌言五物 白鶻圖','司馬光','宋','宋诗','song-poetry','','[]','白鶻日邊來，一息萬里遙。',120,'全唐诗/poet.song.29000.json','["白鶻日邊來，一息萬里遙。", "横飛碧海晴，六翮寒蕭蕭。", "輕如朔雪花，迥與長風飄。", "傾身疊紺爪，吟嘯何嘵哮。", "瞥來疾驚電，欻起先扶搖。", "遂令狐與狸，不敢矜凶妖。", "罻羅不可取，滅影還雲霄。", "世人莫得見，粉繪圖輕綃。", "凛然堂牖間，霜氣生春朝。", "風雨夜如墨，古木無鳴梟。"]'),
('75963246-bfc7-4a7f-9a33-4329ba070e99','和梅聖俞詠昌言五物 懷素書','司馬光','宋','宋诗','song-poetry','','[]','上人工書世所稀，於今散落無復遺。',128,'全唐诗/poet.song.29000.json','["上人工書世所稀，於今散落無復遺。", "君從何處獲數幅，敗絹蒼蒼不成軸。", "雲流電走何縱横，昏醉視之雙目明。", "烈火燒林虎豹慄，疾雷裂地龍蛇驚。", "須臾掛壁未收卷，陰風颯颯來吹面。", "秪疑神物在闇中，寶秘不令關俗眼。", "嗟余平生不識書，但愛意氣豪有餘。", "欲求數字置座側，安得滿斗千金珠。"]'),
('73d866ad-088c-464f-963e-b181db4abe5d','和梅聖俞詠昌言五物 縛虎圖','司馬光','宋','宋诗','song-poetry','','[]','孫生非畫師，趣尚頗奇偉。',180,'全唐诗/poet.song.29000.json','["孫生非畫師，趣尚頗奇偉。", "爲人少諧合，不肯畜妻子。", "時時入深山，信足動百里。", "蕭然坐盤石，盡日曾不起。", "精心忽有得，縱筆何恢詭。", "萬象皆自然，神工相表裏。", "流傳落人間，萬金易寸紙。", "君家縛虎圖，用意尤精緻。", "雖云鎖紐牢，觀者猶披靡。", "昔聞劉綱妻，制虎如犬豕。", "繫之牀脚間，垂頭受鞭箠。", "孫生儻未見，畫此亦何理。", "明知非世人，羽化實不死。", "願君佗日歸，置之成都市。", "必有乘槎人，庶幾能辨此。"]'),
('85493012-f63d-4c0f-9d0a-0120adcdeae0','新遷書齋頗爲清曠偶書呈全董二秀才并示姪良富','司馬光','宋','宋诗','song-poetry','','[]','長夏暑候濁，雲火高巑岏。',168,'全唐诗/poet.song.29000.json','["長夏暑候濁，雲火高巑岏。", "豈徒肌骨煩，木卷川流乾。", "新居得南齋，楹檻稍虛寛。", "森羅對草樹，曉暮清陰寒。", "汛掃布几簟，氣體粗可安。", "圖書雖非多，亦足備覽觀。", "聖賢述事業，細大無不完。", "高出萬古表，遠窮四海端。", "於中苟得趣，自可忘寢餐。", "況今有道世，糓祿正可干。", "朂哉二三子，及時張羽翰。", "力學致顯位，拖玉簪華冠。", "毋爲玩博弈，趣取一笑歡。", "壯年不再來，急景如流丸。"]'),
('241b1444-915a-4edf-b92f-71c2949c0c67','奉同何濟川迎吏未至秋暑方劇呈同舍','司馬光','宋','宋诗','song-poetry','','[]','稚金避老火，暑勢尤驕盈。',144,'全唐诗/poet.song.29000.json','["稚金避老火，暑勢尤驕盈。", "朱光爍厚地，萬葉焦無聲。", "夫子久倦遊，得郡爲親榮。", "束裝待騶吏，歸期殊未成。", "埃沙塞廣陌，蓬藋擁前楹。", "出處兩不愜，孤坐心煩縈。", "何時驚飈來，掃蕩天地清。", "郊墟草樹疏，千騎從雙旌。", "飄颻若神仙，皁蓋西南征。", "離羣詎幾時，豈不懷友生。", "有意肯相過，不妨巾屨并。", "官舍稍虛涼，愧無殽酒迎。"]'),
('92ab3cc5-a796-4192-98b2-4b8428847200','和聶之美雞澤官舍詩七首 西齋','司馬光','宋','宋诗','song-poetry','','[]','明府學既優，所聞今得施。',36,'全唐诗/poet.song.29000.json','["明府學既優，所聞今得施。", "四境已澄清，還以書自怡。", "西齋幾黄卷，治原俱在兹。"]'),
('5847dcef-bc7b-4691-8b64-eb4b2d4287b0','和聶之美雞澤官舍詩七首 題廳壁','司馬光','宋','宋诗','song-poetry','','[]','百里有民社，古爲子男國。',36,'全唐诗/poet.song.29000.json','["百里有民社，古爲子男國。", "苟有愛物心，穉老皆蒙德。", "爲身不爲人，鄙哉陶彭澤。"]'),
('59bd1645-9763-4ffd-ba10-ccc7245550f8','和聶之美雞澤官舍詩七首 縣樓','司馬光','宋','宋诗','song-poetry','','[]','孤樓雖不高，足以瞰四遠。',36,'全唐诗/poet.song.29000.json','["孤樓雖不高，足以瞰四遠。", "餉婦陌頭歸，田夫桑廕飯。", "敇吏省追胥，勿令農事晚。"]'),
('b602d6bb-c441-414f-beb3-29b45be2c96b','和聶之美雞澤官舍詩七首 葦','司馬光','宋','宋诗','song-poetry','','[]','索索夕風遒，瀼瀼朝露裛。',36,'全唐诗/poet.song.29000.json','["索索夕風遒，瀼瀼朝露裛。", "啅雀裊寒枝，宿螢依敗葉。", "眇然秋興長，坐與江潮接。"]'),
('2537f22a-aeb0-4d91-9c42-5accc0f55e19','和聶之美雞澤官舍詩七首 柳','司馬光','宋','宋诗','song-poetry','','[]','驛道苦車馬，田廬悲斧斤。',36,'全唐诗/poet.song.29000.json','["驛道苦車馬，田廬悲斧斤。", "誰栽官舍前，老朽完天真。", "所願明府心，庇樹如庇人。"]'),
('e4409245-8b07-47a0-9cd4-0b50df21c262','和聶之美雞澤官舍詩七首 向城路','司馬光','宋','宋诗','song-poetry','','[]','村路煙欲暝，行人殊未稀。',36,'全唐诗/poet.song.29000.json','["村路煙欲暝，行人殊未稀。", "借問往來者，營營皆有爲。", "乃知市朝客，趣務良可悲。"]'),
('8a59a509-65f5-49f7-ab87-158d9c4fb7c9','和聶之美雞澤官舍詩七首 懷翠亭','司馬光','宋','宋诗','song-poetry','','[]','高齋對秋山，平望殊不遠。',36,'全唐诗/poet.song.29000.json','["高齋對秋山，平望殊不遠。", "雖違獨往心，蒼蒼長在眼。", "可嗟都邑遊，終日紅塵滿。"]'),
('3a3f9d85-ce6c-4b28-8380-f614134a9316','晚食菊羮','司馬光','宋','宋诗','song-poetry','','[]','朝來趨府庭，飲啄厭腥羶。',216,'全唐诗/poet.song.29000.json','["朝來趨府庭，飲啄厭腥羶。", "況臨敲扑喧，憒憒成中煩。", "歸來禠冠带，杖屨行東園。", "菊畦濯新雨，綠秀何其繁。", "平時苦目痾，滋味性所便。", "采擷授廚人，烹瀹調甘酸。", "母令薑桂多，失彼真味完。", "貯之鄱陽甌，薦以白木盤。", "餔啜有餘味，芬馥逾秋蘭。", "神明頓颯爽，毛髮皆蕭然。", "迺知愜口腹，不必矜肥鮮。", "嘗聞南陽山，有菊環清泉。", "居人飲其流，孫息皆華顛。", "嗟予素荒浪，強爲簪緌牽。", "何當葺弊廬，脫略區中緣。", "南陽匄嘉種，蒔彼數畝田。", "抱甕親灌溉，爛漫供晨餐。", "浩然養恬漠，庶足延頽年。"]'),
('65cc38df-1443-4b89-8d81-c638368f240e','和吳冲卿崇文宿直睹壁上題名見寄并寄邵不疑','司馬光','宋','宋诗','song-poetry','','[]','白袍昔紛紛，相與會東堂。',288,'全唐诗/poet.song.29000.json','["白袍昔紛紛，相與會東堂。", "帝梧碧蕭瑟，翔集皆鸞凰。", "伊予素空疏，濫吹翰墨場。", "不爲羣儁遺，出處聯簪裳。", "爾來凡六閏，轉轂飛炎凉。", "同歌太學下，共醉金馬旁。", "脩竹壓窗寒，夭桃倚戶芳。", "金盤剖盧橘，玉壺分蔗漿。", "驚呼局上急，嘲笑杯間狂。", "神情一契會，形迹兩俱忘。", "歡餘嘆薄宦，離合何能常。", "濡毫紀歲時，揮霍素壁光。", "去秋隨相車，沿牒來東方。", "城中未徧辭，不疑逐南荒。", "奔波走郊外，取别何蒼黄。", "舉觴未及盡，亟歸還束裝。", "行行到官下，日積簿領忙。", "文書擁筆端，胥史森如牆。", "況當三伏深，霑汗尤淋浪。", "細蠅繞眉睫，驅赫不可攘。", "涔涔頭目昏，始覺冠带妨。", "誠知才智微，吏治非所長。", "懼貽知已羞，敢不益自強。", "因思甌閩遠，南走侵溟漲。"]'),
('aef46e94-57fd-49c7-ac52-d241755b5f60','昔别贈宋復古張景淳','司馬光','宋','宋诗','song-poetry','','[]','昔别如飛蓬，飄蕩随所適。',144,'全唐诗/poet.song.29000.json','["昔别如飛蓬，飄蕩随所適。", "那知十六載，巵酒對今夕。", "渺然思舊遊，間不容一息。", "百年詎幾何，會合難屢得。", "復古素愷悌，志行重金錫。", "皎如百鍊精，不爲燥濕易。", "景淳氣高逸，浩蕩誰與敵。", "下筆驚雷霆，龍蛇走屋壁。", "居然器業美，但有富貴逼。", "佗時綰金印，羈束愈愁寂。", "須窮今日懽，快意浮大白。", "勿辤簪弁傾，頽然倒樽席。"]'),
('500c6de8-4479-4a58-8bda-c3f272dd7188','苦寒行','司馬光','宋','宋诗','song-poetry','','[]','窮冬北上太行嶺，霰雪糺結風崢嶸。',256,'全唐诗/poet.song.29000.json','["窮冬北上太行嶺，霰雪糺結風崢嶸。", "熊潛豹伏飛鳥絕，一逕僅可通人行。", "僮饑馬羸石磴滑，戰慄流汗皆成冰。", "妻愁兒號強相逐，萬險歷盡方到并。", "并州從來號惨烈，今日乃信非虛名。", "陰煙苦霧朝不散，旭日不復能精明。", "跨鞍纜轡趨上府，髪拳鬚磔指欲零。", "炭爐炙硯湯涉筆，重複畫字終難成。", "誰言醇醪能獨立，壺腹迸裂無由傾。", "石脂装火近不熱，蓬勃氣入頭顱腥。", "仰慚鴻鴈得自適，隨陽南去何溟溟。", "又慚鳦鳥識時節，巖穴足以潛微形。", "我來蓋欲報恩分，契闊非狥利與榮。", "古人有爲知已死，只恐凍骨埋邊庭。", "中朝故人豈念我，重裘厚履飄華纓。", "傳聞此北更寒極，不知彼民何以生。"]'),
('0a12433c-de7b-44aa-bcb9-266034c946d1','初見白髪慨然感懷','司馬光','宋','宋诗','song-poetry','','[]','萬物壯必老，性理之自然。',72,'全唐诗/poet.song.29000.json','["萬物壯必老，性理之自然。", "我年垂四十，安得無華顛。", "所悲道業寡，汩没無佗賢。", "深懼歲月頽，宿心空棄捐。", "視此足自儆，拔之廼違天。", "留爲鑑中銘，晨夕思乾乾。"]'),
('c7cf4386-40bf-42ae-86be-6a66af3cc8da','謝胡文學惠水牛圖二卷','司馬光','宋','宋诗','song-poetry','','[]','牛生天地間，益物用最大。',180,'全唐诗/poet.song.29000.json','["牛生天地間，益物用最大。", "其功配坤元，彖爻參衆卦。", "血毛類上帝，肸蠁景福介。", "宗廟及賓客，百禮無不在。", "引耒刺中田，粒食烝民賴。", "服箱走四方，竭力任重載。", "昔聞戴叟筆，圖寫窮纖芥。", "胡君繼其妙，差肩立異代。", "公卿仰名聲，一觀不可匄。", "如何散賤者，遽有雙圖賚。", "所嗟性顓愚，雅不曉佳畫。", "有如歌九韶，鐘鼓樂聾瞶。", "得之乃虛器，無異居大蔡。", "神物恐化去，立召風雨怪。", "雙圖雖卷還，重貺敢不拜。"]'),
('cbb45a10-8e4a-447c-a6bb-4c2203ac0856','王書記以近詩三篇相示各摭其意以詩賡之 感遇','司馬光','宋','宋诗','song-poetry','','[]','白鵠出江渚，刷羽何鮮新。',216,'全唐诗/poet.song.29000.json','["白鵠出江渚，刷羽何鮮新。", "志陵青霞端，欲飲天漢津。", "清飈未我與，陂澤聊逡巡。", "偶爲虞羅獲，遠趣無由伸。", "樊籠厭局促，野性那能馴。", "庭除數驚顧，慘慘常畏人。", "皓素不入俗，衆目誰爲珍。", "稻粱不充腹，日與鷄鶩鄰。", "舉頭畏太高，俛啄空愁辛。", "蕭蕭斂六翮，憔悴傷精神。", "男兒五十不如意，青衫華髮遊埃塵。", "曏爲鹽官北如晉，今爲幕吏西適秦。", "慨然遂欲抛手板，拂衣高蹈錦水濱。", "長竿短艇入煙雨，放歌酣飲欹烏巾。", "方今聖朝清似水，林空谷静無隱淪。", "吾君夢卜偶未到，勿學君平與子真。"]'),
('af073deb-f98d-4696-ae06-612d5fb049b3','王書記以近詩三篇相示各摭其意以詩賡之 投聖俞','司馬光','宋','宋诗','song-poetry','','[]','聖俞精爲詩，堅重比白玉。',228,'全唐诗/poet.song.29000.json','["聖俞精爲詩，堅重比白玉。", "至寶識之希，未必諧衆目。", "應辰仰高風，跂聳自西蜀。", "平生未相識，歉歉不自足。", "薄遊困京師，旅食止脫粟。", "得官當入秦，行李未結束。", "先求聖俞門，執贄請所欲。", "九衢季冬月，風沙正慘黷。", "羸馬憚遠行，毛鬛寒瑟縮。", "旅拒不肯前，一步九刺蹙。", "饑童袖擁口，手足盡皸瘃。", "論詩久未出，竊罵怨滿腹。", "歸來面揚揚，氣若飫粱肉。", "纍纍數十字，疏淡不滿幅。", "自謂獲至珍，呼兒謹藏蓄。", "長安十五驛，重複問川陸。", "置詩懷袖間，勌懣輒披讀。", "高吟桑野闊，目瞑即投宿。", "自可忘羈愁，行瞻灞陵曲。"]'),
('60bf22f0-24e0-48d1-b31c-94078d41a8cb','王書記以近詩三篇相示各摭其意以詩賡之 呈景仁','司馬光','宋','宋诗','song-poetry','','[]','劍山中斷融爲川，清江雙流鬰迴旋。',128,'全唐诗/poet.song.29000.json','["劍山中斷融爲川，清江雙流鬰迴旋。", "溝塍阡陌粲如繡，香秔紫芋皆良田。", "地靈物秀氣淑美，由來衮衮生英賢。", "朝家文明所及遠，於今臺閣尤蟬聯。", "獵纓鳴佩走聲望，出入金馬如雲煙。", "奈何應辰獨壈坎，華髮未得離賓筵。", "璵璠懸黎已爲寶，結綠豈得偏棄捐。", "願君彈冠自重惜，邑人行誦子虛篇。"]'),
('31139439-2cac-4be6-851f-e1ca37e9e09a','酬胡侍講先生見寄','司馬光','宋','宋诗','song-poetry','','[]','后王命天官，考績弊群吏。',120,'全唐诗/poet.song.29000.json','["后王命天官，考績弊群吏。", "屬曹省閥閱，專職米鹽事。", "賤生偶承乏，竊祿聊自庇。", "才力困不逮，慘慘日憂惴。", "賴依僚友賢，剸裂沛餘地。", "自知雖寄名，不足繫軒輊。", "先生喜誘掖，貽詩極襃賁。", "誰云歲杪寒，面熱汗沾漬。", "非不悅子道，駑鈍力難致。", "常恐負吹噓，終爲重言累。"]'),
('48c29189-e3ef-4ff6-a013-3e2ef2b1898d','和錢君倚日本刀歌','司馬光','宋','宋诗','song-poetry','','[]','昆吾道遠不復通，世傳切玉誰能窮。',192,'全唐诗/poet.song.29000.json','["昆吾道遠不復通，世傳切玉誰能窮。", "寶刀近出日本國，越賈得之滄海東。", "魚皮装貼香木鞘，黄白間雜鍮與銅。", "百金傳入好事手，佩服可以攘祅凶。", "傳聞其國居大島，土壤沃饒風俗好。", "其先徐福詐秦民，采藥淹留童丱老。", "百工五種與之俱，至今器用皆精巧。", "前朝貢獻屢往來，士人往往工辭藻。", "徐福行時書未焚，逸書百篇今尚存。", "令嚴不許傳中國，舉世無人識古文。", "嗟予乘桴欲往學，滄波浩蕩無通津。", "令人感嘆坐流涕，鏽澀短刀何足云。"]'),
('98cc1c75-4f92-4797-93fb-3d99cd314856','同聖民過楊之美聽琵琶女奴彈啄木曲觀諸公所贈歌明日投此爲謝','司馬光','宋','宋诗','song-poetry','','[]','坐曹據案心目疲，出門上馬行何之。',284,'全唐诗/poet.song.29000.json','["坐曹據案心目疲，出門上馬行何之。", "闕然久不見之美，率意共往初無期。", "正逢攬轡欲有適，爲我却解連環羈。", "閑軒適足容數客，夏木初繁有佳色。", "呼兒取次具杯盤，青眼相逄喜無極。", "檀槽錦带小青娥，妙質何須誇綺羅。", "按絃運撥驚四座，當今老手誰能過。", "彈爲幽鳥啄寒木，園林颯颯風雨和。", "喙長爪短躍更上，丁丁取蠧何其多。", "曲終拂羽忽飛去，不覺酒盡朱顔酡。", "已聞啄木曲，又觀啄木歌。", "雄文更復值絕藝，有如天際傾長河。", "今朝壯觀誠極樂，去此將奈寂寞何。", "歸來解带豁胸腹，坐踞胡牀仰看屋。", "從今三日不洗耳，耳內泠泠有殘曲。", "人間何物號富貴，紆紫懷金盡虛器。", "如君自處真得策，身外百愁都擲置。", "太學餐錢月幾何，客來取酒同醒醉。"]'),
('1d57ff54-87cb-45a1-bf6e-e377ce535c1b','晚歸書室呈君倚','司馬光','宋','宋诗','song-poetry','','[]','簿領日沈迷，事役等胥靡。',60,'全唐诗/poet.song.29000.json','["簿領日沈迷，事役等胥靡。", "得歸無所爲，未免閱書史。", "一種勞精神，胸中異憂喜。", "人生無苦樂，適意即爲美。", "乃知抱關人，不必羨青紫。"]'),
('3e749bc7-eac7-4f39-888e-bcac524ed311','偶成','司馬光','宋','宋诗','song-poetry','','[]','於陵薄三公，桔橰親灌園。',60,'全唐诗/poet.song.29000.json','["於陵薄三公，桔橰親灌園。", "伯成輕南面，執耒耕丘樊。", "淵明恥爲令，乞食倚人門。", "賢人樂遂志，榮辱安足言。", "鄙哉夸毗子，結駟乘朱軒。"]'),
('ce86ed4b-9445-4e10-8e6d-d121cb6648fa','同君倚過聖俞','司馬光','宋','宋诗','song-poetry','','[]','王畿天下樞，薄領日填積。',108,'全唐诗/poet.song.29000.json','["王畿天下樞，薄領日填積。", "自非奉朝請，九衢未嘗識。", "今兹到東城，胥靡蹔逃役。", "近指聖俞居，安能不往覿。", "一室静蕭然，昏碑帖古壁。", "叩階讀新詩，迷闇得指擿。", "笑言殊未足，黯然日將夕。", "呼馬涉歸塗，燈火已歷歷。", "又知幾何時，更有重來迹。"]'),
('ba2fe2fb-dcb1-4908-9210-6cba39f70952','聖俞惠詩復以二章爲謝  其一','司馬光','宋','宋诗','song-poetry','','[]','我得聖俞詩，於身亦何有。',24,'全唐诗/poet.song.29000.json','["我得聖俞詩，於身亦何有。", "名字託文編，佗年知不朽。"]'),
('51de696b-5c65-487b-9cba-0394715fed79','聖俞惠詩復以二章爲謝  其二','司馬光','宋','宋诗','song-poetry','','[]','我得聖俞詩，於家果何如。',24,'全唐诗/poet.song.29000.json','["我得聖俞詩，於家果何如。", "留爲子孫寶，勝有千年珠。"]'),
('b7cd5944-0826-4f14-a0fd-fa81b84f14d0','和君倚藤牀十二韻','司馬光','宋','宋诗','song-poetry','','[]','嗟予仕京府，謀祿非謀身。',144,'全唐诗/poet.song.29000.json','["嗟予仕京府，謀祿非謀身。", "豈徒勞百骸，消鑠侵天真。", "所畏曠官誅，敢辭從事勤。", "朝訊獄中囚，暮省案前文。", "雖有八尺牀，初無偃息痕。", "比歸蹔解带，日没軒窗昏。", "援枕未及就，撲面愁飛蚊。", "未能習律令，何暇闚皇墳。", "夫君天才秀，明潁排糾紛。", "右曹況清簡，剸裂奚足云。", "未遇且堅卧，逢時將致君。", "行當起經濟，膏沐醒吾人。"]'),
('cf58d539-1e55-457f-a8ae-7f65b2ca085d','旬慮十七韻呈同舍','司馬光','宋','宋诗','song-poetry','','[]','府官無旬休，慮問廼遊息。',204,'全唐诗/poet.song.29000.json','["府官無旬休，慮問廼遊息。", "詔書禁從詣，還舍始朝食。", "緩带對藜羮，下筯免促迫。", "門前吏卒散，却掃謝來客。", "北軒有藤牀，今晨始拂拭。", "蓬髪亂宜梳，霜髭閑可摘。", "開囊曬藥物，發笥出書册。", "菊畦親灌浸，茶器自涓滌。", "於時孟秋末，天晴色紺碧。", "林葉雖未零，風聲已淅瀝。", "神明還九藏，清氣襲百脉。", "征夫解甲胄，疲馬脫羈靮。", "蜚鳥開樊籠，跳魚出鼎鬲。", "形骸盡我有，不復爲物役。", "雖非久安逸，幸得少頃適。", "訟庭止敲扑，咫尺異喧寂。", "明朝不能然，顧盼愁月夕。"]'),
('040b637a-89b5-45cc-a84d-b083fbac9744','夜坐','司馬光','宋','宋诗','song-poetry','','[]','春陽氣未勝，重爲陰所乘。',180,'全唐诗/poet.song.29000.json','["春陽氣未勝，重爲陰所乘。", "涔涔積雨闋，慘慘餘寒增。", "流雲鬰不開，烈風尚憑陵。", "夜闌閉戶牖，青暈生昏燈。", "僮僕悉已眠，書几久欹凭。", "涉獵閱舊聞，蹔使心魂澄。", "有如行役歸，丘園恍重登。", "又如遠别離，邂逅逢友朋。", "嗟嗟宦遊子，何異魚入罾。", "奪其性所樂，強以所不能。", "人生本不勞，苦被外物繩。", "坐愁清旦出，文墨來相仍。", "吏徒紛四集，僕僕如秋蠅。", "煩中劇沸鼎，入骨真可憎。", "安得插六翮，適意高飛騰。"]'),
('cd038537-0571-473b-b868-960a0e3dbc4b','二月中旬慮問過景靈宮門始見花卉呈君倚','司馬光','宋','宋诗','song-poetry','','[]','賤生參府僚，勉強踰半歲。',180,'全唐诗/poet.song.29000.json','["賤生參府僚，勉強踰半歲。", "終非性所好，出入意如醉。", "訟庭敲扑喧，衆草絕生意。", "不知有青春，倐忽已改燧。", "周章連日忙，爛漫數宵睡。", "軒窗岌飛舉，風雨頗恣睢。", "謂言芳菲物，狼藉應掃地。", "今晨呼馬出，歷獄問囚繫。", "窈窕清宮深，倉琅朱門閉。", "廣殿肅層陰，虛庭藹佳氣。", "長楊委嫰綠，老柏凈新翠。", "薜荔垂蜿延，奇石立贔屭。", "豁然愁憤開，精神四面至。", "事役難少留，馬去尚回睇。", "亦足慰無聊，年華不都棄。"]'),
('264f08f4-d536-44b9-900f-fbdd3fee383d','和始平公夢中有懷歸之念作詩始得兩句而寤因足成一章','司馬光','宋','宋诗','song-poetry','','[]','元宰撫洪鈞，四海可熏灼。',48,'全唐诗/poet.song.29000.json','["元宰撫洪鈞，四海可熏灼。", "至人養天真，視此猶嬰縛。", "出入金鼓威，寤寐琴樽樂。", "乃知伊吕心，未始忘丘壑。"]'),
('bb5ddaca-b719-4946-ab6d-4619ee813254','和江鄰幾六月十一日省宿書事','司馬光','宋','宋诗','song-poetry','','[]','長夏金正伏，火意尤驕盈。',180,'全唐诗/poet.song.29000.json','["長夏金正伏，火意尤驕盈。", "夫子寓官舍，無術逃煩蒸。", "軒窗豁四開，滅去壁上燈。", "紵衣不可親，羽扇安能勝。", "濯泉泉已温，撫簟簟可憎。", "萬葉悄無風，但有飛蚊鳴。", "六府燥不濡，喉舌煙塵生。", "攝衣起徐步，四顧天正晴。", "雲漢淺欲涸，箕畢徒縱横。", "忽思終南巔，秀出秦雲青。", "上有長松林，蔽日深杳冥。", "下有萬仞壑，含蓄太古冰。", "安得躡輕屐，杖策緣峥嶸。", "挂冠芙蓉闕，結屋高崖稜。", "回視萬鍾祿，飄撇如飛蠅。"]'),
('4b656938-a38f-448d-8aaf-5ff96481c02b','和張仲通學士苦暑思長安幕中望終南秋雪呈江鄰幾','司馬光','宋','宋诗','song-poetry','','[]','秋雲覆秦川，小雨野未濕。',180,'全唐诗/poet.song.29000.json','["秋雲覆秦川，小雨野未濕。", "誰言終南頂，已有霰雪集。", "返景開新晴，孱顔照都邑。", "初疑江津闊，遠浪横風急。", "又疑龍蛻骨，逶迤委原隰。", "詞客登高樓，四望清興入。", "當時應百篇，遺散不復拾。", "今兹宦帝城，大暑困鬰悒。", "紅塵滿九衢，出入冠带襲。", "家居賓旅來，俯僂煩拜揖。", "回思幕中趣，引領安可及。", "江翁養文采，正如玄豹蟄。", "君往犯其嚴，騰起誰敢縶。", "嗟予素恇怯，旁睨毛髪立。", "強復綴此章，庶幾勇可習。"]'),
('b8b7a2aa-d2d6-4d35-96de-951d398d1ee0','和張仲通追賦陪資政侍郎吳公臨虛亭燕集寄呈陜府祖擇之學士','司馬光','宋','宋诗','song-poetry','','[]','吾家陜之北，陜事吾能說。',288,'全唐诗/poet.song.29000.json','["吾家陜之北，陜事吾能說。", "孤亭占城隅，形勝最殊絕。", "雲消天宇空，極目鳥飛滅。", "大河西北來，洶湧地脉裂。", "萬里卷流沙，長驅走溟碣。", "羣山勢離合，披靡隨曲折。", "林薄带村墟，郊原如繡纈。", "祠宮望神禹，閑田指虞芮。", "高丘想巫咸，空巖懷傅說。", "聖賢迹已遠，縹渺見風烈。", "吳公昔爲守，治行瑩冰雪。", "君從豐鎬來，華館息塵轍。", "主人喜佳客，置酒升嵽嵲。", "清歡浩無涯，燭至樽未撤。", "誰知捧手辭，遽有幽明訣。", "至今猶墮淚，遺愛滿耆耋。", "擇之新下車，條教悉施設。", "依然典刑在，先後如符節。", "嗟予仕京邑，苟祿自羈紲。", "丘壟翳荒松，三年灑掃缺。", "求歸未能得，朝莫腸百結。", "得君臨虛詩，彷彿見里闕。", "何時往登臨，曠若目去䁾。", "憂來復長吟，益使寸心折。"]'),
('238ebe01-3434-4413-b2a6-3d77d4cf7998','秋意呈鄰幾吳冲','司馬光','宋','宋诗','song-poetry','','[]','新凉入閭巷，舊暑何人掃。',60,'全唐诗/poet.song.29000.json','["新凉入閭巷，舊暑何人掃。", "筠籠賣紅蓮，莎堦墜丹棗。", "蕉衫日以疏，紈扇安能好。", "蟬悲西風樹，燕亂斜陽草。", "此意屬淵明，籬邊幾樽倒。"]'),
('604b8208-677a-4e5d-b32c-df4ae7e706b1','次韻和吳冲卿秋意四首 掃棗好草倒','司馬光','宋','宋诗','song-poetry','','[]','槐花滿庭除，籍籍不可掃。',60,'全唐诗/poet.song.29000.json','["槐花滿庭除，籍籍不可掃。", "稍疏召平瓜，漸熟王陽棗。", "失時團扇棄，新進袷衣好。", "日暮益愁思，寒螿起幽草。", "忽聞秋興篇，嘆賞幾絕倒。"]'),
('26cf817d-409d-4182-b188-086fdee408d7','次韻和吳冲卿秋意四首 窺梨卑枝垂','司馬光','宋','宋诗','song-poetry','','[]','端居倦煩暑，園圃久不窺。',60,'全唐诗/poet.song.29000.json','["端居倦煩暑，園圃久不窺。", "雨餘秋氣新，紅葉生紫棃。", "形骸得蕭散，不知環堵卑。", "何能效流俗，把酒須菊枝。", "登高已可醉，四野青雲垂。"]'),
('ec731672-7414-469c-bb4a-c2692f888604','次韻和吳冲卿秋意四首 偏眠船舷邊','司馬光','宋','宋诗','song-poetry','','[]','縱棹下清溪，波靜地仍偏。',60,'全唐诗/poet.song.29000.json','["縱棹下清溪，波靜地仍偏。", "日夕水風涼，蕭灑成安眠。", "兀兀但高枕，悠悠還進船。", "中流忽驚寤，漁父歌扣舷。", "山川非曏時，回首雲霞邊。"]'),
('e3ab2803-d054-495c-bc27-be28d244937b','次韻和吳冲卿秋意四首 後牖有朽柳','司馬光','宋','宋诗','song-poetry','','[]','弱植生川澤，託根北堂後。',60,'全唐诗/poet.song.29000.json','["弱植生川澤，託根北堂後。", "昔時青春姿，扶疏映軒牖。", "風霜日消落，憔悴復何有。", "蠧穿枯節斷，雨漬虛心朽。", "幸不夭天年，猶得勝凡柳。"]'),
('bb22c33c-4bff-43df-af7b-37f271d52882','聶著作三舅謫官長沙作耐辱亭書來索詩','司馬光','宋','宋诗','song-poetry','','[]','少連善降志，無恤能忍詬。',72,'全唐诗/poet.song.29000.json','["少連善降志，無恤能忍詬。", "兹亭名耐辱，締構自吾舅。", "樽前湘水清，席下湘山秀。", "於焉忘榮枯，終日醉醇酎。", "攻愁若攻敵，避喧如避寇。", "困久理須通，非徒保無咎。"]'),
('630e19ed-9c58-4c15-939a-125af57aa497','走索','司馬光','宋','宋诗','song-poetry','','[]','伎兒欲誇衆，喜占衢路交。',96,'全唐诗/poet.song.29000.json','["伎兒欲誇衆，喜占衢路交。", "繫組不厭長，縛竿不厭高。", "空中紛往來，巧捷如飛猱。", "却行欠膚寸，倒絓連秋毫。", "參差有萬一，虀粉安可逃。", "錢刀不盈掬，身世輕鴻毛。", "徒資旁觀好，曹偶相稱襃。", "豈知從事者，處之危且勞。"]'),
('050a9ff2-96dd-466c-8212-f2aa5053f197','邵不疑廳薜荔及竹','司馬光','宋','宋诗','song-poetry','','[]','脩竹非俗物，薜荔亦嘉草。',60,'全唐诗/poet.song.29000.json','["脩竹非俗物，薜荔亦嘉草。", "樹之君子庭，人來見逾好。", "侵堦鶴脛細，緣壁龍鱗老。", "紛披兩疏翠，煙色宜秋早。", "主人日封植，清風庶長保。"]'),
('1e4fe5d4-1313-4ae6-bfdc-5540602c03e5','和公達過潘樓觀七夕市','司馬光','宋','宋诗','song-poetry','','[]','織女雖七襄，不能成報章。',96,'全唐诗/poet.song.29000.json','["織女雖七襄，不能成報章。", "無巧可乞汝，世人空自狂。", "帝城秋色新，滿市翠帟張。", "僞物踰百種，爛漫侵數坊。", "誰家油壁車，金碧照面光。", "土偶長尺餘，買之珠一囊。", "安知杼軸勞，何物爲蠶桑。", "紛華不足悅，浮侈真可傷。"]'),
('f1f815e9-60e6-4845-889c-1df8bfd9fdbc','酬鄰幾問不飲栽菊','司馬光','宋','宋诗','song-poetry','','[]','黄菊本天物，先隨元化生。',60,'全唐诗/poet.song.29000.json','["黄菊本天物，先隨元化生。", "酒醴乃人功，後因儀狄成。", "酒客強親菊，菊酒初無情。", "種之荒階側，何嘗妨獨醒。", "脩竹氣蕭灑，自合生君庭。"]'),
('d761de36-8b46-4782-88a4-9b0e4624711b','次韻和邵不疑假書江鄰幾知方酣寢爲詩通意','司馬光','宋','宋诗','song-poetry','','[]','江翁順天和，心迹兩夷簡。',144,'全唐诗/poet.song.29000.json','["江翁順天和，心迹兩夷簡。", "雖如邊韶寢，且異宰予懶。", "平居無時閑，經史自課限。", "高歌慕翰林，鳴琴寫中散。", "翛然物外人，強爲章綬綰。", "官舍苦秋霖，瞬息聊休眼。", "勤勩已有餘，宴安何愧赧。", "借書誰敢驚，欹枕尚未暖。", "不疑神驥才，垂耳困皁棧。", "碌碌隨吾儕，拜揖把手版。", "毋嫌朱墨倦，騰舉已爲晚。", "慎勿思山林，山林付愚孱。"]'),
('a8865a26-8442-4022-be77-81b35d142d91','八月十七日夜省直紀事呈同舍','司馬光','宋','宋诗','song-poetry','','[]','窮秋直省舍，大雨吁可畏。',204,'全唐诗/poet.song.29000.json','["窮秋直省舍，大雨吁可畏。", "九河飜層空，入夜愈恣睢。", "置牀東壁根，時有塗塈墜。", "颯颯勢將摧，怵惕不成寐。", "中宵抱衾立，呼燭久方至。", "徙之近西偏，禂帳不能備。", "飛蚊胡不仁，忍此加啄噬。", "避煩只深藏，悒悒面蒙被。", "須臾漏轉劇，枕褥亦沾漬。", "雖起欲何之，室中無燥地。", "展轉遂達旦，耿耿負憂悸。", "因思閭井民，餬口仰執技。", "束手已連旬，妻兒日憔悴。", "嚢錢與盎米，薪木同時匱。", "敗衣不足準，搏手坐相視。", "予今幸已多，敢不自知愧。", "無謀忝肉食，念爾但增欷。"]'),
('30e83357-bfa5-42b0-a5bf-a8b33b8c7442','送雷太簡','司馬光','宋','宋诗','song-poetry','','[]','南山有白雲，應物任所適。',48,'全唐诗/poet.song.29000.json','["南山有白雲，應物任所適。", "欻來非有心，倐去還無迹。", "甘澤望霑浹，嘉生待蘇息。", "無爲遽收卷，復入巖間石。"]'),
('7f81da86-0b56-4f05-9054-1d7e1a6d6ae3','和王介甫明妃曲','司馬光','宋','宋诗','song-poetry','','[]','胡雛上馬唱胡歌，錦車已駕白橐駝。',193,'全唐诗/poet.song.29000.json','["胡雛上馬唱胡歌，錦車已駕白橐駝。", "明妃揮淚辭漢主，漢主傷心知奈何。", "宮門銅環雙獸面，回首何時復來見。", "自嗟不若住巫山，布袖蒿簪嫁鄉縣。", "萬里寒沙草木稀，居延塞外使人歸。", "舊來相識更無物，只有雲邊秋鴈飛。", "愁坐泠泠調四絃，曲終掩面向胡天。", "侍兒不解漢家語，指下哀聲猶可傳。", "傳徧胡人到中土，萬一佗年流樂府。", "妾身生死知不歸，妾意終期寤人主。", "目前美醜良易知，咫尺掖庭猶可欺。", "君不見白頭蕭太傅，被讒仰藥更無疑。"]'),
('a71f2d00-11c6-4e14-b04e-ffae19928df6','和不疑送虜使還道中聞江鄰幾梅聖俞長逝作詩哭之','司馬光','宋','宋诗','song-poetry','','[]','昨夕郵吏來，叩門致書函。',288,'全唐诗/poet.song.29000.json','["昨夕郵吏來，叩門致書函。", "呼奴取以入，就火開其緘。", "不疑賦長篇，發自燕之南。", "痛傷江與梅，繼踵良人殲。", "噫嗟知其二，尚未知其三。", "請從北轅後，覼縷爲君談。", "鄰幾雖久病，始不妨朝參。", "飲歠寖衰少，厥逆生虛痰。", "逮於易簀辰，皮骨餘崆嵌。", "遺書屬清儉，終始真無慚。", "聖俞食寒冰，外以風邪兼。", "愚醫暴下之，結轖候愈添。", "惙惙氣上走，不復容鍼砭。", "自言從良友，地下心亦甘。", "欽聖體素彊，藥石性所諳。", "平居察舉措，敢以不壽占。", "一朝蹔歸卧，簿領不廢簽。", "訃來衆皆愕，未信猶闚覘。", "興言念三子，舉袂涕已霑。", "英賢能幾何，逝者迹相銜。", "君疑天上才，難得帝所貪。", "我疑人間美，多取神所嫌。", "茫茫幽明際，蓍蔡難窮探。", "憂來不可忘，終日心厭厭。"]'),
('0d6c8551-229e-4521-9012-3f7fbaca903f','虞帝','司馬光','宋','宋诗','song-poetry','','[]','虞帝老倦勤，薦禹爲天子。',60,'全唐诗/poet.song.29000.json','["虞帝老倦勤，薦禹爲天子。", "豈有復南巡，迢迢渡湘水。", "至德遠無象，異論紛紛起。", "意疑大聖人，姦憸亦如已。", "乃知中下士，何由逃謗毁。"]'),
('a66447ee-d8ac-4edc-bce0-81ff3eec6e04','憫獄謠','司馬光','宋','宋诗','song-poetry','','[]','五刑象天有震耀，上聖本以防姦邪。',81,'全唐诗/poet.song.29000.json','["五刑象天有震耀，上聖本以防姦邪。", "法官由來少和泰，臯陶之面如削瓜。", "況於秦漢任酷吏，死人籍籍如亂麻。", "捶楚之求靡不得，小者勍刖大滅家。", "君不見古時牢獄地，幾多冤骨埋黄沙。"]'),
('d290bade-72fa-4f76-aab3-1c36ac45cf8f','和吳冲卿三哀詩','司馬光','宋','宋诗','song-poetry','','[]','天生千萬人，中有一雋傑。',264,'全唐诗/poet.song.29000.json','["天生千萬人，中有一雋傑。", "奈何喪三賢，前後纔朞月。", "鄰幾任天資，浮飾恥澡刷。", "朝市等山林，衣冠同布褐。", "外無涇渭分，內有淄澠别。", "逢時敢危言，慷慨誰能奪。", "聖俞詩七千，歷歷盡精絕。", "初無追琢勤，氣質禀清潔。", "負兹驚世才，未嘗自標掲。", "鞠躬隨衆後，側足畏蹉跌。", "欽聖渥洼駒，初生已汗血。", "雖有絕塵蹤，不失和鸞節。", "宜爲清廟噐，儼雅應鐘律。", "衆論仍共然，非從友朋出。", "羣才方大來，軮軋扶帝室。", "誰云指顧間，聯翩化異物。", "弔縗哭未已，病枕氣已竭。", "同爲地下遊，攜手不相失。", "紳紱頓蕭條，相逢但嗟咄。", "誦君三哀詩，終篇涕如雪。", "眉目尚昭晣，笑言猶彷彿。", "肅然來悲風，四望氣蕭瑟。"]'),
('cf7ffdb9-9d05-48b2-9322-47f3cf3ed888','窮兔謠二首  其一','司馬光','宋','宋诗','song-poetry','','[]','鶻翅崩騰來九霄，兔命迫窄無所逃。',64,'全唐诗/poet.song.29000.json','["鶻翅崩騰來九霄，兔命迫窄無所逃。", "秋毫就死忽背躍，鶻拳不中還飛高。", "安知韓盧復在後，力屈但作嬰兒號。", "少年只取一快樂，誰念草根腥血毛。"]'),
('c2891a9d-c224-417f-8fbe-9caaab3f2991','窮兔謠二首  其二','司馬光','宋','宋诗','song-poetry','','[]','兔營三窟定何在，棘間塹底高丘巔。',64,'全唐诗/poet.song.29000.json','["兔營三窟定何在，棘間塹底高丘巔。", "却行百步方躍入，未免餘蹤留雪田。", "少年何爲無惻隱，解鷹縱犬薫以煙。", "人言兔狡非兔狡，窘急偷生真可憐。"]'),
('875de05b-d55c-4681-827c-f3c9ed255a3d','和王介甫烘蝨','司馬光','宋','宋诗','song-poetry','','[]','天生萬物名品夥，嗟爾爲生至么麽。',288,'全唐诗/poet.song.29000.json','["天生萬物名品夥，嗟爾爲生至么麽。", "依人自活反食人，性喜覆藏便垢涴。", "晨朝生子暮生孫，不日蕃滋踰萬箇。", "透疏緣隙巧百端，通夕爬搔不能卧。", "我歸彼出疲奔命，備北驚南厭搜邏。", "所擒至少所失多，捨置薫燒無術奈。", "加之炭上猶晏然，相顧未知亡族禍。", "大者洋洋迷所適，奔走未停身已墮。", "細者懦怯但深潛，乾死縫中誰復課。", "黑者抱髪亦憂疑，逃入幧頭默相賀。", "腥煙騰起遠襲人，袖擁鼻端時一唾。", "初雖快意終自咎，致爾殲夷非爾過。", "吾家篋笥本自貧，況復爲人苦慵惰。", "體生鱗甲未能浴，衣不離身成脆破。", "朽繒壞絮爲淵藪，如麥如麻寖肥大。", "虛膓不免須侵人，肯學夷齊甘死餓。", "醯酸蜹聚理固然，爾輩披攘我當坐。", "但思努力自潔清，群蝨皆當遠邇播。"]'),
('ba4ae6cf-a708-4a71-af3c-fe49042df90b','和王勝之雪霽借馬入局偶書','司馬光','宋','宋诗','song-poetry','','[]','勝之家本公侯貴，弱冠英才已驚世。',192,'全唐诗/poet.song.29000.json','["勝之家本公侯貴，弱冠英才已驚世。", "雒陽多士誰敢倫，千古比肩唯賈誼。", "昔遭絳灌深切齒，奔走十年爲下吏。", "近方抆拭出泥塗，稍學和光匿鋒銳。", "會計之官豈足爲，黽勉簿書聊自庇。", "王城九衢臘月尾，風雪數朝窮恣睢。", "櫪間款段疲且病，借馬於人亦疲曳。", "揚鞭掣轡趨省廷，刺蹙不前泥没鼻。", "慨然遂有勞者歌，滿紙雄文欻軒輊。", "人生榮遇有早晚，視此錙銖勿關意。", "況君卓犖高出羣，異日青雲終自致。", "鮮車大蓋擁驊騮，莫忘今朝乘小駟。"]'),
('a54e9927-1bb1-46d6-9789-58cb47e47c2f','齊山詩呈王學士','司馬光','宋','宋诗','song-poetry','','[]','江上有奇山，羣峰矗如翦。',72,'全唐诗/poet.song.29000.json','["江上有奇山，羣峰矗如翦。", "昔聞齊刺史，置酒升絕巘。", "其人有惠政，嘉名自兹遠。", "君來踵其迹，詞牒日清簡。", "驪駒時入谷，勝地窮搜選。", "問俗復懷人，非徒事遊衍。"]'),
('b1047173-62a2-4ada-9db6-4ef47a8b9073','吹簫','司馬光','宋','宋诗','song-poetry','','[]','古人吹簫者，以和虞韶聲。',24,'全唐诗/poet.song.29000.json','["古人吹簫者，以和虞韶聲。", "後世不復貴，給喪仍賣餳。"]'),
('a883f556-1357-4070-83ad-cdec10b2eaa1','和始平公見寄八韻','司馬光','宋','宋诗','song-poetry','','[]','嚮來從後車，雍容鎮藩垣。',96,'全唐诗/poet.song.29000.json','["嚮來從後車，雍容鎮藩垣。", "政成簿書簡，終日侍清樽。", "今兹備言職，不得登朱門。", "違離詎幾時，風色變寒温。", "忽聆吉甫什，穆如承話言。", "安得六翮生，隨意遠飛翻。", "垂耳倦新羈，蹀足思華軒。", "諒無伯樂顧，疲勞安敢論。"]'),
('84960ecb-4c5d-40a8-be1a-d9a42f202c85','又和并寄楊樂道十二韻','司馬光','宋','宋诗','song-poetry','','[]','聖主樂忠諫，曲從如轉圜。',144,'全唐诗/poet.song.29000.json','["聖主樂忠諫，曲從如轉圜。", "玉色粹陽春，至仁生自然。", "所慚羣臣愚，無以稱開延。", "賤生何爲者，側足青規前。", "頑石不可鍊，安能補高天。", "狂簡昧大體，所依官長賢。", "有如驂之靷，左右隨周旋。", "庶幾助山甫，衮職無尤愆。", "緬思老成人，阻親函丈筵。", "豈不寸心勞，動爲纒徽牽。", "何當執壽巵，跪起得差肩。", "相顧藐無期，瞻望徒悁悁。"]'),
('c95c604a-f047-4a0d-b2d3-3c5fbb99fbfc','朝雞贈王樂道','司馬光','宋','宋诗','song-poetry','','[]','小雞距短雙翅垂，廣場勇鬬無所施。',128,'全唐诗/poet.song.29000.json','["小雞距短雙翅垂，廣場勇鬬無所施。", "清曉長鳴獨先衆，朝者恃此能知時。", "星河滿天月光白，東望扶桑悄無色。", "一聲高舉耳目醒，四遠羣陰俱辟易。", "陋巷人疏煙火稀，永夜沈沈鐘鼓微。", "聞之徐起就盥櫛，顛倒不復憂裳衣。", "君家迥居北城曲，阿閣嶕嶢日鳴玉。", "蕭蕭風雨得司晨，不使無功啄君粟。"]'),
('3d82a0e7-5d7b-4f43-8bd6-b64aba4970b2','謝始平公以近詩一卷賜示','司馬光','宋','宋诗','song-poetry','','[]','皇家駿命承蒼穹，烝民之傑生維嵩。',272,'全唐诗/poet.song.29000.json','["皇家駿命承蒼穹，烝民之傑生維嵩。", "聖賢會合若符契，坐致四海登熙隆。", "三階清平九鼎重，指麾拱揖安華戎。", "人情誰不樂將相，往往皓首忘疲癃。", "北平飲乳尚懷印，千秋乘車猶入宮。", "唯公致政年甫至，耳目明利志氣充。", "幡然脫去萬鍾祿，羽儀高遠如翔鴻。", "靈臺不復絓塵務，至德恬淡含黄中。", "英華純粹積不發，事業轉爲文字工。", "大篇短韻間金石，遠追吉甫流清風。", "刻雕衆物非用意，默與元化參神功。", "應劉鮑謝事奇巧，細瑣豈足誇才雄。", "祼圭夷玉清廟器，肯與環玦爭玲瓏。", "絳帳生徒東閣客，微官拘縶如樊籠。", "言詩何敢望商賜，幸得誦詠袪童蒙。", "昏花病目不自惜，服膺盥手書一通。", "千金之産不可易，子孫寶蓄傳無窮。"]'),
('c2b3b76e-71ad-4de5-8960-40f88169112f','早春戲作呈范景仁','司馬光','宋','宋诗','song-poetry','','[]','閏餘春意早，卉木先有思。',192,'全唐诗/poet.song.29000.json','["閏餘春意早，卉木先有思。", "嚶嚶羣鳥翔，東西各求類。", "伊予忝諌垣，動息抱憂悸。", "衮職曠不補，言責真可畏。", "況復禁過從，陋巷若囚繫。", "茅茨庇風雨，偏隘無餘地。", "時於壞垣隙，歷歷生新薺。", "君侯乃比鄰，跬步難自致。", "常思去歲初，西軒學歌吹。", "座客皆故人，歡笑無拘忌。", "平生不喜酒，是日成爛醉。", "豈言長揖歸，良會難再值。", "東風忽復來，時華一何駛。", "叢竹固無恙，夭桃作花異。", "朝廷正清明，詎肯容竊位。", "何當遂廢放，歡飲還自恣。"]'),
('ec8d5a00-26bc-4928-b5c8-023cda2d339e','瞻彼南山詩  其一','司馬光','宋','宋诗','song-poetry','','[]','瞻彼南山，有梌有棠。',60,'全唐诗/poet.song.29000.json','["瞻彼南山，有梌有棠。", "維葉牂牂，君子之燕。", "籩豆洋洋，鼎俎將將。", "百羞阜昌，上下樂康。", "邦家之光，君子萬年。", "撫有四荒，受祿無疆。"]'),
('52ded73b-f956-4c5b-9ecb-8372d3f97926','瞻彼南山詩  其二','司馬光','宋','宋诗','song-poetry','','[]','瞻彼南山，有椐有栩。',60,'全唐诗/poet.song.29000.json','["瞻彼南山，有椐有栩。", "維葉湑湑，君子之燕。", "清酒有藇，壺樽有楚。", "酌言賜之，命之釂之。", "上下以序，君子萬年。", "永綏兆民，受天之祜。"]'),
('13a51688-630d-4a58-8f11-266caf2417d5','瞻彼南山詩  其三','司馬光','宋','宋诗','song-poetry','','[]','瞻彼南山，有杞有樅。',60,'全唐诗/poet.song.29000.json','["瞻彼南山，有杞有樅。", "維葉逢逢，君子之燕。", "管絲噰噰，奏鼓𪔳𪔳。", "自堂徂庭，上下肅雍。", "靡有不恭，君子萬年。", "令德高明，高明有融。"]'),
('3fe127e1-4093-4f40-8fca-7854624eb57a','瞻彼南山詩  其四','司馬光','宋','宋诗','song-poetry','','[]','赫赫明明，天命有嚴。',60,'全唐诗/poet.song.29000.json','["赫赫明明，天命有嚴。", "命我祖考，九土是監。", "倭馯之東，蠻蜑之南。", "享獻有時，靡敢不詹。", "閟兹餘文，複閣巖巖。", "萬世是承，四方是瞻。"]'),
('d2127430-4662-4376-9086-41cbd7313270','瞻彼南山詩  其五','司馬光','宋','宋诗','song-poetry','','[]','帝曰卿士，左右之臣。',60,'全唐诗/poet.song.29000.json','["帝曰卿士，左右之臣。", "四方無虞，矜爾之勤。", "式觀且遊，從予一人。", "于壼于閎，于堂于陳。", "金石之符，翰墨之珍。", "匪予汝夸，祖考之勲。"]'),
('b96df46d-3c70-4d74-9d52-2f3dd8a4e4e0','瞻彼南山詩  其六','司馬光','宋','宋诗','song-poetry','','[]','多士庶尹，羣公百辟。',60,'全唐诗/poet.song.29000.json','["多士庶尹，羣公百辟。", "拜手稽首，答揚休德。", "既醉既飽，慎思爾職。", "罔顧爾私，罔愛爾力。", "惇忠祗敕，永奉丕則。", "立民之極，載祀千億。"]'),
('26e9c20e-a7e1-4941-a260-8440de779dba','夏夜','司馬光','宋','宋诗','song-poetry','','[]','溽暑鬰不開，矗矗雲萬疊。',84,'全唐诗/poet.song.29000.json','["溽暑鬰不開，矗矗雲萬疊。", "長風卷地來，凍雨不濡葉。", "雖無潤物功，涼泠得所惬。", "須臾號怒息，清月照壁頰。", "小冠簪短髪，衣裾輕獵獵。", "欹傾依曲几，暫爾蘇疲苶。", "坐久不思眠，草間微露浥。"]'),
('114157da-e779-4905-827f-d73c0a329fea','和范景仁西圻野老詩','司馬光','宋','宋诗','song-poetry','','[]','西郊廣路浮壤黄，上天雨泣寒雲蒼。',192,'全唐诗/poet.song.29000.json','["西郊廣路浮壤黄，上天雨泣寒雲蒼。", "鸞旗闟戟紛晻靄，扈從威神歸帝鄉。", "田家老父眉睫白，杖藜匍匐泣路傍。", "且云生逢至仁主，蠲租罷役歲爲常。", "蠺收百箔桑蔽野，麻麥極望無邊疆。", "去年翠華出賽雨，錦繡綿絡墟里光。", "拜迎六馬負縑帛，孫扶嫗接歸揚揚。", "自分謳歌畢餘景，一朝縞素安可防。", "哀聲澒洞徹四極，草木慘淡顔色傷。", "螻蟻衰齡不足贖，淚如飛雪空霑裳。", "河縈洛貫嵩峰足，泉底寰瀛日月長。", "羨門已閉屬車返，軛上空瞻金鳯凰。"]'),
('0d8b4302-d1be-4aa3-b573-ef2fd425907a','種竹','司馬光','宋','宋诗','song-poetry','','[]','種竹南牆陰，竹生皆北響。',48,'全唐诗/poet.song.29000.json','["種竹南牆陰，竹生皆北響。", "苟非陽在北，竹性安可強。", "乃知就陽意，草木皆有情。", "園葵最柔弱，獨取傾心名。"]'),
('47e56a7a-45fb-43f4-94d4-11d3b016d21b','介甫巫山高命光屬和勉率成篇真不知量','司馬光','宋','宋诗','song-poetry','','[]','巫山高，巫山之高高不極。',217,'全唐诗/poet.song.29000.json','["巫山高，巫山之高高不極。", "寒江西來曳練長，羣峰森羅十二戟。", "清狖悲號裂翠崖，老蛟怒鬭摧丹壁。", "輕生重利三巴客，一葉直衝高浪白。", "船頭吟嘯坐自如，仰視長天不盈尺。", "叢祠象設儼山椒，巫祝紛紛非一朝。", "云是高唐神女之所處，至今暮雨常蕭蕭。", "我聞神理明且直，興亡唯觀惡與德。", "安肯來從楚國君，憑依夢寐爲淫昏。", "襄王之心自荒惑，引領日望陽臺雲。", "獨不思懷王西行不復返，甲光照地屯秦軍。", "蠺食黔中下荆門，陵園宗廟皆燒焚。", "社稷飄零不復存，嗟嗟若敖蚡冒時，篳路藍縷皆辛勤。"]'),
('1ca48dea-7b6a-4dab-88ac-bf0a7c1e75bf','昔予嘗權宰韋城今重過之二十五年矣慨然有懷','司馬光','宋','宋诗','song-poetry','','[]','二十五年南北走，遺愛寂然民記否。',32,'全唐诗/poet.song.29000.json','["二十五年南北走，遺愛寂然民記否。", "昔日嬰兒今壯夫，昔日壯夫今老叟。"]'),
('1f9da59e-4e8d-41d1-ac00-00d8f1488049','秋懷呈范景仁','司馬光','宋','宋诗','song-poetry','','[]','草木正蕃廡，孰知天地秋。',72,'全唐诗/poet.song.29000.json','["草木正蕃廡，孰知天地秋。", "況兹宿雨餘，景氣益和柔。", "消搖愧簪紱，夢想懷林丘。", "兹志久未果，素髪今已稠。", "仰視白日光，浩蕩浮雲流。", "安得黄鶴羽，陵風千里遊。"]'),
('17875648-7e42-4fba-a99c-a72dc89ca09c','又和秋懷','司馬光','宋','宋诗','song-poetry','','[]','疇昔共登仕，爾来三十秋。',72,'全唐诗/poet.song.29000.json','["疇昔共登仕，爾来三十秋。", "常晞絲繩直，竊恥鴟夷柔。", "蹄涔學鉅海，螘垤依崇丘。", "行之不自疑，親寡憎怨稠。", "於今不亟去，淪胥恐同流。", "努力買良田，遠追沮溺遊。"]'),
('0059f39d-8e9c-42b6-a953-e2d520ce21b5','贈道士陳景元酒','司馬光','宋','宋诗','song-poetry','','[]','籬根委餘菊，堦角擁殘葉。',48,'全唐诗/poet.song.29000.json','["籬根委餘菊，堦角擁殘葉。", "清言久不悒，何以慰疲苶。", "朋樽涵太和，高興雅所愜。", "誰云居室遠，風味自可接。"]'),
('e9e67de0-17b4-4457-b56c-3bd6ed6f992c','景仁召飲東園呈陳彦升宋次道李才元蘇子容','司馬光','宋','宋诗','song-poetry','','[]','去冬辱嘉招，寒風方贔屭。',84,'全唐诗/poet.song.29000.json','["去冬辱嘉招，寒風方贔屭。", "今秋侍高宴，晴日正澄麗。", "雖無花蘤繁，且有丘樊思。", "雖無山泉樂，蹔違塵土氣。", "僕休散城邑，馬縱脫羈轡。", "讙呼笑言適，散誕冠带棄。", "殊勝禁掖嚴，進止有常地。"]'),
('bdcd6525-b17c-4f47-ba8d-c94f9deac106','花庵詩寄邵堯夫  其一','司馬光','宋','宋诗','song-poetry','','[]','洛陽四時常有花，雨晴顔色秋更好。',32,'全唐诗/poet.song.29000.json','["洛陽四時常有花，雨晴顔色秋更好。", "誰能相與共此樂，坐對年華不知老。"]'),
('d10b1c6b-1e28-450b-96f9-e1f0c7ca1996','花庵詩寄邵堯夫  其二','司馬光','宋','宋诗','song-poetry','','[]','自然天物勝人爲，萬葉無風綠四垂。',32,'全唐诗/poet.song.29000.json','["自然天物勝人爲，萬葉無風綠四垂。", "猶恨簪紳未離俗，荷衣蕙带始相宜。"]'),
('ad134dde-36c6-4357-ac9d-c128e958f320','康定中予過洛橋南得詩兩句於今三十二年矣再過其處足成一章','司馬光','宋','宋诗','song-poetry','','[]','銅駝陌上桃花紅，洛陽無處無春風。',32,'全唐诗/poet.song.29000.json','["銅駝陌上桃花紅，洛陽無處無春風。", "重來羞見水中影，鬢毛蕭颯如秋蓬。"]'),
('83a61f98-e0fa-4231-8997-b2d769c6b839','寶鑑貽開叔','司馬光','宋','宋诗','song-poetry','','[]','流塵集寶鑑，塵昏鑑不昏。',60,'全唐诗/poet.song.29000.json','["流塵集寶鑑，塵昏鑑不昏。", "纖泥落清水，泥渾非水渾。", "人能辨二物，相與自忘言。", "二物不能辨，悠悠何足論。", "無爲捨其內，逐外取煩冤。"]'),
('6b19cea5-bda8-4c99-b7af-9ceeaabfad1c','謝王道濟惠古詩古石器','司馬光','宋','宋诗','song-poetry','','[]','緱氏古城裏，好古王道濟。',132,'全唐诗/poet.song.29000.json','["緱氏古城裏，好古王道濟。", "作詩有古風，讀書知古意。", "朝來遣僕夫，遺我古石器。", "結從天地初，生自一拳際。", "工倕創規摹，般輸施剞劂。", "瀹茗北窗下，坐有羲皇思。", "嗟予性迂鄙，齟齬居今世。", "忝官污臺省，曾無益時智。", "退藏又濡滯，尚不離朝市。", "闕地避煩暑，頗與營窟類。", "誠非古人比，拜賜得無愧。"]'),
('205dcdd9-4fde-4579-8c33-ada9c9e25a7f','壽安雜詩十首 噴玉泉','司馬光','宋','宋诗','song-poetry','','[]','蒼崖雙起秋雲齊，亂峰迸出如攢犀。',64,'全唐诗/poet.song.29000.json','["蒼崖雙起秋雲齊，亂峰迸出如攢犀。", "石稜澀不容馬蹄，下馬步入荆榛蹊。", "瀑泉沃雪拖白霓，落潭横引成清溪。", "老木長藤咫尺迷，興闌欲出忘東西。"]'),
('0a629697-0dff-46ad-a9ea-816b58d1f9c9','壽安雜詩十首 神林谷二首 其一','司馬光','宋','宋诗','song-poetry','','[]','石下泉聲蔓草深，石上露濃蒼蘚徧。',32,'全唐诗/poet.song.29000.json','["石下泉聲蔓草深，石上露濃蒼蘚徧。", "山禽驚起飛且鳴，葉墜空林人不見。"]'),
('800ae8fd-1759-49ee-8165-58a57440a84c','壽安雜詩十首 神林谷二首 其二','司馬光','宋','宋诗','song-poetry','','[]','鷄幘奇峰雲外横，青壁千尋不可上。',32,'全唐诗/poet.song.29000.json','["鷄幘奇峰雲外横，青壁千尋不可上。", "却羨樵兒輕險峽，腰繩操斧常來往。"]'),
('1adcf48f-375e-4b33-a2c4-4acd6b57f056','壽安雜詩十首 遊神林谷寄邵堯夫','司馬光','宋','宋诗','song-poetry','','[]','山人有山未嘗遊，俗客遠來仍久留。',32,'全唐诗/poet.song.29000.json','["山人有山未嘗遊，俗客遠來仍久留。", "白雲滿眼望不見，可惜宜陽一片秋。"]'),
('c79bfdfc-871f-4bb0-ae7b-02b0a4c83786','壽安雜詩十首 靈山寺流泉','司馬光','宋','宋诗','song-poetry','','[]','去寺猶一里，隔林聞水聲。',24,'全唐诗/poet.song.29000.json','["去寺猶一里，隔林聞水聲。", "安知客乘興，山下遠相迎。"]'),
('1b23bbcc-709d-425f-b72d-a8596e59636e','壽安雜詩十首 且遊','司馬光','宋','宋诗','song-poetry','','[]','遊人戀山水，日晏澹忘歸。',24,'全唐诗/poet.song.29000.json','["遊人戀山水，日晏澹忘歸。", "但愛雲煙好，那知僕馬饑。"]'),
('982d2f13-dd89-48b7-85f4-d327723b2e4a','壽安雜詩十首 永濟渡二首 其一','司馬光','宋','宋诗','song-poetry','','[]','洛水寒可涉，長汀柳飛葉。',24,'全唐诗/poet.song.29000.json','["洛水寒可涉，長汀柳飛葉。", "節物先無期，自與幽懷愜。"]'),
('780bda95-9b5f-4148-ab3d-4a0cdbe0de65','壽安雜詩十首 永濟渡二首 其二','司馬光','宋','宋诗','song-poetry','','[]','清波見白鷗，靜林聞啄木。',24,'全唐诗/poet.song.29000.json','["清波見白鷗，靜林聞啄木。", "泉細入平沙，雲閑出幽谷。"]'),
('f330213c-6eca-4f83-b749-b6775d64aa94','壽安雜詩十首 靈山寺','司馬光','宋','宋诗','song-poetry','','[]','神林興盡謀早歸，草間露裛行徑微。',272,'全唐诗/poet.song.29000.json','["神林興盡謀早歸，草間露裛行徑微。", "忽思靈山去不遠，馬首欲東還向西。", "垂鞭縱轡尋山足，洛水逶迤過數曲。", "漸聞林下飛泉鳴，未到已覺神骨清。", "入門拂去衣上土，先愛娑羅陰滿庭。", "庭下雙渠走清澈，羅縠成紋日光徹。", "寒聲淅瀝入肝髓，亂影彯蕭動毛髪。", "寺僧引我觀泉源，堂東周迴百步寛。", "碧頗梨色湛無底，想象必有虬龍蟠。", "泉南高山名鳯翅，宛轉抱泉張遠勢。", "岸旁脩竹踰萬竿，颯颯長含風雨氣。", "寺門下望情豁然，桑柘紛披滿一川。", "嵩高女几列左右，王屋太行來掌前。", "昔爲孔氏懸泉莊，巖洞猶存荆棘荒。", "到今其下多怪石，熊蹲豹攫爭軒昂。", "嗟予歸來苦不早，汩没朝市行欲老。", "捫蘿躡屣須數遊，筋力支離難自保。"]'),
('18b7aab6-bbbf-464a-976a-6a2e177fd856','壽安雜詩十首 藏珠石','司馬光','宋','宋诗','song-poetry','','[]','水齧東山根，土色渥如丹。',132,'全唐诗/poet.song.29000.json','["水齧東山根，土色渥如丹。", "危峰忽摧脫，半崖銜石丸。", "陰陽昔融結，神化不可原。", "初疑偓佺養靈藥，魑魅觸之無故落。", "又疑蛟龍伏巨卵，雷電擊之從此毈。", "或者女媧補天餘，却下青冥遺耳珠。", "不然盤古戲爲樂，聊取天弧彈朱雀。", "物理萬狀終難知，巧心推求徒自疲。", "不如引客坐石上，好奇且醉手中巵。"]'),
('de0cf7c3-cdaa-4074-b35d-dcd2090b3d9a','王君貺宣徽垂示嵩山祈雪詩十章合爲一篇以酬之','司馬光','宋','宋诗','song-poetry','','[]','今秋少雨冬不雪，麥寄浮埃根欲絕。',384,'全唐诗/poet.song.29000.json','["今秋少雨冬不雪，麥寄浮埃根欲絕。", "聖主焦心閔萬民，負扆不怡常膳撤。", "詔書朝下徧九州，岳瀆百神俱禱求。", "西都留守虔君命，促駕不敢須臾留。", "嵩高萬仞蟠地中，海內衆山無與雄。", "前驅大斾擁千騎，波騰雲涌來祠宮。", "牲肥酒香籩豆潔，盛服齋明薦毛血。", "有司執事皆肅然，寶帳神來風窣屑。", "公心猶畏九閽遙，丹誠不能通青霄。", "分留導從屯林麓，别張醮具登山椒。", "山椒迢遰峻無極，行挽枯藤蹋危石。", "萬室嗷嗷愁死饑，敢憚劬勞愛餘力。", "天門上出俄坦平，下視一世塵杳冥。", "焚香拜手傾懇惻，左右前後皆列星。", "公今三守三川地，咫尺嵩高未嘗至。", "詰朝既畢祠事嚴，暫轉鳴珂歷諸寺。", "少林昔爲達摩居，達摩英靈今有無。", "瘦辭流散滿天下，競以兩手捫空虚。", "法王魏氏離宮舊，玉刻狻猊曏猶有。", "子孫宗廟皆塵灰，止見伽藍存不朽。", "會善庭隅千歳松，一根二股凌寒空。", "勢如鼎足爭秀出，泠泠永夜吟霜風。", "少室先生樂閑暇，棄官來家玉峰下。", "昔爲浪泊據鞍人，今結東陵賣瓜舍。"]'),
('c751f51c-5c01-4b8e-86a7-8d0789f02e04','酬吳仲庶龍圖終南山詩','司馬光','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u7ec8\u5357\u5c71"]','泰山魯所瞻，終南乃秦望。',120,'全唐诗/poet.song.29000.json','["泰山魯所瞻，終南乃秦望。", "西侵井絡闊，北壓鶉野曠。", "條梅韞名材，金玉富珍藏。", "飄風何烈烈，萬物盡搖蕩。", "屹立不傾倚，勢與厚坤壯。", "有如牧伯賢，斯民蒙保障。", "雪霜舉世寒，千里獨重纊。", "病夫伏閭里，非能事微尚。", "顧無孤高實，藻飾安可強。", "景行雖不忘，詎敢承嘉貺。"]'),
('94b1ba60-bc6b-4bec-8971-4b902fbb923e','酬永樂劉秘校四洞詩','司馬光','宋','宋诗','song-poetry','','[]','貧居苦湫隘，無術逃炎曦。',240,'全唐诗/poet.song.29000.json','["貧居苦湫隘，無術逃炎曦。", "穿地作幽室，頗與朱夏宜。", "寛者容一席，狹者分三支。", "芳草植中唐，嘉卉周四垂。", "詎堪接賓宴，適足供兒嬉。", "自問安取法，前脩果慕誰。", "非如太古民，營窟避寒威。", "又非學射人，空石專致思。", "又非沮漆俗，陶復習西夷。", "又非楚司馬，金奏相賓儀。", "又非鄭伯有，壑谷甘糟醨。", "又非越王子，丹宂免憂危。", "又非張巨和，崇巖立師資。", "所慕於陵子，欲效蚓所爲。", "微竅足藏身，槁壤足充饑。", "養生既無憾，此外安敢知。", "唯祈膏澤布，歌嘯樂餘滋。", "豈羞泥塗賤，甘受高明嗤。", "何言清尚士，善頌形聲詩。", "困剝固未嘗，井復敢終辭。"]'),
('1d968556-71ad-4818-b936-bf3bee7f9d63','杕柏寄傅欽之  其一','司馬光','宋','宋诗','song-poetry','','[]','彼杕者柏，生于崇巒，其葉丸丸。',35,'全唐诗/poet.song.29000.json','["彼杕者柏，生于崇巒，其葉丸丸。", "君子爰處，爰處爰遊。", "匪憂勿憂，其樂休休。"]'),
('931b385e-58c1-4738-b10b-5fdd1e19fa29','杕柏寄傅欽之  其二','司馬光','宋','宋诗','song-poetry','','[]','彼郁者蘭，生於幽涯，其葉菲菲。',35,'全唐诗/poet.song.29000.json','["彼郁者蘭，生於幽涯，其葉菲菲。", "君子爰處，爰處爰嬉。", "靡適弗宜，忘其渇饑。"]'),
('1c7a23d1-63bb-419e-8010-e46de4eb04a4','杕柏寄傅欽之  其三','司馬光','宋','宋诗','song-poetry','','[]','洋洋者舟，汎彼中流，于渚于洲。',35,'全唐诗/poet.song.29000.json','["洋洋者舟，汎彼中流，于渚于洲。", "思其可思，知其可知。", "其逝勿追，其來勿期。"]'),
('ea9e0599-2fa8-4765-af2a-32646ae09d5f','獨樂園七詠 讀書堂','司馬光','宋','宋诗','song-poetry','','[]','吾愛董仲舒，窮經守幽獨。',48,'全唐诗/poet.song.29000.json','["吾愛董仲舒，窮經守幽獨。", "所居雖有園，三年不遊目。", "邪說遠去耳，聖言飽充腹。", "發策登漢庭，百家始消伏。"]'),
('2756c861-4d9c-4060-a67f-ce5890465533','獨樂園七詠 釣魚庵','司馬光','宋','宋诗','song-poetry','','[]','吾愛嚴子陵，羊裘釣石瀨。',48,'全唐诗/poet.song.29000.json','["吾愛嚴子陵，羊裘釣石瀨。", "萬乘雖故人，訪求失所在。", "三公豈易貴，不足易其介。", "奈何夸毗子，斗祿窮百態。"]'),
('3b1d6631-6cbc-4474-8b79-b16884629459','獨樂園七詠 采藥圃','司馬光','宋','宋诗','song-poetry','','[]','吾愛韓伯休，采藥賣都市。',48,'全唐诗/poet.song.29000.json','["吾愛韓伯休，采藥賣都市。", "有心安可欺，所以價不二。", "如何彼女子，已復知姓字。", "驚逃入窮山，深畏名爲累。"]'),
('7cfcb1c3-737a-4fa3-b625-af60d0d8cf97','見山臺','司馬光','宋','宋诗','song-poetry','','[]','吾愛陶淵明，拂衣遂長往。',48,'全唐诗/poet.song.29000.json','["吾愛陶淵明，拂衣遂長往。", "手辭梁主命，犧牛憚金鞅。", "愛君心豈忘，居山神可養。", "輕舉向千齡，高風猶尚想。"]'),
('bd9d7a40-cfc0-4e52-8122-188b0fda9b42','見山臺 弄水軒','司馬光','宋','宋诗','song-poetry','','[]','吾愛杜牧之，氣調本高逸。',48,'全唐诗/poet.song.29000.json','["吾愛杜牧之，氣調本高逸。", "結亭侵水際，揮弄消永日。", "洗硯可抄詩，泛觴宜促膝。", "莫取濯冠纓，紅塵汙清質。"]'),
('ff66481c-1045-4b72-a0b3-4dbd8420f13e','見山臺 種竹齋','司馬光','宋','宋诗','song-poetry','','[]','吾愛王子猷，借宅亦種竹。',48,'全唐诗/poet.song.29000.json','["吾愛王子猷，借宅亦種竹。", "一日不可無，蕭灑常在目。", "雪霜徒自白，柯葉不改綠。", "殊勝石季倫，珊瑚滿金谷。"]'),
('506bb69d-b183-45ae-a035-58b240938d18','見山臺 澆花亭','司馬光','宋','宋诗','song-poetry','','[]','吾愛白樂天，退身家履道。',48,'全唐诗/poet.song.29000.json','["吾愛白樂天，退身家履道。", "釀酒酒初熟，澆花花正好。", "作詩邀賓朋，欄邊長醉倒。", "至今傳畫圖，風流稱九老。"]'),
('62f867ee-7b4a-401c-ab63-156a5556edb9','和利州鮮于轉運公居八詠 桐軒','司馬光','宋','宋诗','song-poetry','','[]','朝陽升東隅，照此庭下桐。',96,'全唐诗/poet.song.29000.json','["朝陽升東隅，照此庭下桐。", "菶菶復萋萋，居然古人風。", "疏柯青玉聳，密葉翠羽蒙。", "午景凝餘清，夕照當殘紅。", "雨響甍棟外，風生戶牖中。", "主人政多暇，步賞常從容。", "終當致威鳯，覧德鳴噰噰。", "又將施五絃，解愠歌帝宮。"]'),
('59d30950-f9f6-45a2-b24c-e71aa6ba37de','和利州鮮于轉運公居八詠 竹軒','司馬光','宋','宋诗','song-poetry','','[]','兹軒最灑落，歷歷種琅玕。',84,'全唐诗/poet.song.29000.json','["兹軒最灑落，歷歷種琅玕。", "正晝簿書稀，蕭蕭風雨寒。", "翠陰涼宴坐，疏韻承清歡。", "錦籜裁夏扇，玉筍供春槃。", "晴蝸潛葉底，暝雀投林端。", "幽興遇物愜，高懷隨處安。", "且免一日無，何須千畝寛。"]'),
('524381ed-dae1-4a16-a1a7-b97e7fd71534','和利州鮮于轉運公居八詠 柏軒','司馬光','宋','宋诗','song-poetry','','[]','凜然凌霜色，本自生丘壑。',72,'全唐诗/poet.song.29000.json','["凜然凌霜色，本自生丘壑。", "徙之君子庭，栽培固不薄。", "靜夜聲飂飂，清晝陰漠漠。", "秀氣逼簷楹，翠影通簾箔。", "知君梁棟材，大匠偶未度。", "但守歲寒心，閑軒亦不惡。"]'),
('29dc908a-bfae-4a2c-bd16-62ed71f1968e','和利州鮮于轉運公居八詠 巽堂','司馬光','宋','宋诗','song-poetry','','[]','華堂選形勝，地直巽之隅。',96,'全唐诗/poet.song.29000.json','["華堂選形勝，地直巽之隅。", "主人心潔齊，公閑此燕居。", "西來故鄉客，東過朝大夫。", "時逢志所愜，下榻同歡娛。", "琴棋間壺觴，賦詠雜歌呼。", "民間既羲皇，席上宜華胥。", "每思就一醉，幸無官守拘。", "奈何三千里，風埃與泥塗。"]'),
('45fd2edf-1383-4abc-a95b-bae9ad06c888','和利州鮮于轉運公居八詠 山齋','司馬光','宋','宋诗','song-poetry','','[]','幽蹊入桃李，危棧蟠林麓。',144,'全唐诗/poet.song.29000.json','["幽蹊入桃李，危棧蟠林麓。", "行行忽虛敞，高齋出山腹。", "園圃近指掌，郊郭紛盈目。", "春老酴醿香，夏淺篔簹綠。", "條横喜罥衣，笋迸乍穿屋。", "秋江澄可卷，冬嶺翠如撲。", "煙間漁艇小，塞外村居獨。", "燒轉望畬田，響答聆伐木。", "驚麏挺走險，鳴禽嚶出谷。", "物華時變更，興趣日相續。", "誰知使者尊，常著野人服。", "肯以駟馬榮，區區詫鄉族。"]'),
('e9070f3e-4a11-4467-a1c1-8da0d79cbe77','閑燕亭','司馬光','宋','宋诗','song-poetry','','[]','吏治正倥傯，夫君何燕閑。',72,'全唐诗/poet.song.29000.json','["吏治正倥傯，夫君何燕閑。", "繭絲既云寡，符移皆可删。", "印封從事散，躡屐升東山。", "放杖坐危亭，清嘯出雲間。", "無私席賓少，忘機林鳥還。", "野人瞻翠微，稽首雙眉斑。"]'),
('6b7e7553-a35a-44d6-9f05-1afae130ab01','會景亭','司馬光','宋','宋诗','song-poetry','','[]','景物浩無窮，兹爲一都會。',72,'全唐诗/poet.song.29000.json','["景物浩無窮，兹爲一都會。", "之人心若鑑，萬狀盡相對。", "喬林擁砌底，脩嶺倚窗背。", "流雲過席上，去鳥出天外。", "徐徐杖屨整，藹藹郊原晦。", "來往亦何爲，逍遙真樂內。"]'),
('2cb6c16d-b3f8-4919-8adb-6f67dddb3efc','會景亭 寶峰亭','司馬光','宋','宋诗','song-poetry','','[]','孤亭冠山椒，下視物不隔。',156,'全唐诗/poet.song.29000.json','["孤亭冠山椒，下視物不隔。", "六合縱心賞，萬家窮目力。", "髻鬟烏奴翠，衣带嘉陵碧。", "霞生白水尾，日没九隴脊。", "煙凝朝夕市，塵飛往來驛。", "雖復對紛紜，何嘗改岑寂。", "實兼觀風遠，非徒選勝適。", "巴峽少平田，每苦天宇窄。", "及兹伏櫺檻，坐瞰南北極。", "先君昔乘軺，名題古寺壁。", "侍行尚垂髫，孤露今戴白。", "讀君登臨詩，舊遊皆歷歷。", "永無膝下歡，終篇涕霑臆。"]'),
('cc30486b-ace2-4ba8-8438-0750771435ec','題太原通判楊郎中新買水北園','司馬光','宋','宋诗','song-poetry','','[]','洛陽名園不勝紀，門巷相連如櫛齒。',128,'全唐诗/poet.song.29000.json','["洛陽名園不勝紀，門巷相連如櫛齒。", "修竹長楊深徑迂，令人邑邑氣不舒。", "愛君買園中橋北，堂壓崖端跨空碧。", "滿川桃李皆目前，近水遠山一朝得。", "曾陪尊兄此高會，豁然如出樊籠外。", "蹔遊尚爾況久居，勝氣清風日相對。", "易生畫筆世所珍，麞猿滿壁皆逼真。", "并州近胡沙塵惡，終更早來爲主人。"]'),
('f34fece0-bb9a-4655-96e5-f8766a9a1261','首夏二章呈諸鄰  其一','司馬光','宋','宋诗','song-poetry','','[]','首夏木陰薄，清和自一時。',48,'全唐诗/poet.song.29000.json','["首夏木陰薄，清和自一時。", "筍抽八九尺，荷生三四枝。", "新服裁蟬翼，舊扇拂蛛絲。", "莎徑熱未劇，晨昏往來宜。"]'),
('74f78326-3b40-4ebe-a976-23ac6b7ccfca','首夏二章呈諸鄰  其二','司馬光','宋','宋诗','song-poetry','','[]','爞爞久旱天，颯颯昨宵雨。',48,'全唐诗/poet.song.29000.json','["爞爞久旱天，颯颯昨宵雨。", "塵頭清過轍，水脉生新渚。", "豈徒滋杞菊，亦可望禾黍。", "勿笑盤蔬陋，時來一觴舉。"]'),
('a9c1cee1-4f6e-46af-973e-5f94398a37fa','酬王安之謝藥栽二章  其一','司馬光','宋','宋诗','song-poetry','','[]','洛人栽花不栽藥，吾屬好尚何其偏。',32,'全唐诗/poet.song.29000.json','["洛人栽花不栽藥，吾屬好尚何其偏。", "服之雖能已百疾，愛閑成僻無由痊。"]'),
('5becdf86-8cf8-4460-9ec9-80791f24eca8','酬王安之謝藥栽二章  其二','司馬光','宋','宋诗','song-poetry','','[]','護根带土我親移，荷鍤汲泉君自種。',32,'全唐诗/poet.song.29000.json','["護根带土我親移，荷鍤汲泉君自種。", "悅目寧將惡草殊，扶危或比兼金重。"]'),
('2753c565-ee33-4a06-91db-986f4d72a790','雨中過王安之所居不謁以詩寄之','司馬光','宋','宋诗','song-poetry','','[]','萬木含涼雨，驅馬有餘清。',84,'全唐诗/poet.song.29000.json','["萬木含涼雨，驅馬有餘清。", "長街带短蕪，舊潦駢新蓱。", "高齋彼誰居，雅尚推名卿。", "汙亭雖地卑，躡屐未妨行。", "野服踞藜牀，蕭散臨前楹。", "纂纂棗林繁，欣欣藥畹榮。", "過門不敢叩，自視慚冠纓。"]'),
('361155ad-dfe5-4e2e-8c3d-d386d8dcaa88','送藥栽與安之','司馬光','宋','宋诗','song-poetry','','[]','盛夏移藥栽，及雨方可種。',48,'全唐诗/poet.song.29000.json','["盛夏移藥栽，及雨方可種。", "爲君著屐取，呼童執傘送。", "到時雲已開，枝軟葉猶重。", "夕陽宜屢澆，又須煩抱甕。"]'),
('f23d6bb9-0964-4dc4-ae10-724393265c7e','張明叔兄弟雨中見過弄水軒投壺賭酒薄暮而散詰朝以詩謝之','司馬光','宋','宋诗','song-poetry','','[]','喜君午際來，涼雨正紛泊。',96,'全唐诗/poet.song.29000.json','["喜君午際來，涼雨正紛泊。", "呼奴掃南軒，壺席謹量度。", "軒前紅薇開，壺下鳴泉落。", "必爭如五射，有禮異六博。", "求全怯垂成，倒置畏反躍。", "雖無百驍巧，且有一笑樂。", "交飛觥酒滿，強進盤餐薄。", "苟非興趣同，珍殽徒綺錯。"]'),
('36951783-c4bc-43f3-b5c2-7f56985856b4','小雨','司馬光','宋','宋诗','song-poetry','','[]','雲日互出没，數朝飛雨清。',72,'全唐诗/poet.song.29000.json','["雲日互出没，數朝飛雨清。", "曈曨似欲止，廉纖還未晴。", "映空輕絲亂，著物細珠明。", "葉端危未落，荷心重忽傾。", "喜涼高鷰舞，便濕羣蛙鳴。", "於予亦有得，藥畹胡麻生。"]'),
('d32dd82e-9a48-4603-837c-45fe4c68acbf','園中書事二絕  其一','司馬光','宋','宋诗','song-poetry','','[]','芳洲晚日鮮，曲岸新雨好。',24,'全唐诗/poet.song.29000.json','["芳洲晚日鮮，曲岸新雨好。", "紅薇點圓荷，金䔲出幽草。"]'),
('8c411eae-43b1-411f-b7b5-288c83d84215','園中書事二絕  其二','司馬光','宋','宋诗','song-poetry','','[]','坐嗅白蓮蘃，卧看青竹枝。',24,'全唐诗/poet.song.29000.json','["坐嗅白蓮蘃，卧看青竹枝。", "閑齋不成寐，起讀聖俞詩。"]'),
('8596320c-eb12-432f-bbe7-984a9a13f279','送劉仲通知涇州','司馬光','宋','宋诗','song-poetry','','[]','四載一相逢，相逢遽爲别。',48,'全唐诗/poet.song.29000.json','["四載一相逢，相逢遽爲别。", "儕輩日蕭條，與君俱白髮。", "巵酒不暇執，舊遊那復說。", "忽忽無他言，暑行戒饑渇。"]'),
('0081b289-9e21-4f7d-8fa9-5bc47ab4b133','和宋復古大雨  其一','司馬光','宋','宋诗','song-poetry','','[]','積陰連日作鬰蒸，長雲飛天勢如鵬。',32,'全唐诗/poet.song.29000.json','["積陰連日作鬰蒸，長雲飛天勢如鵬。", "白雨四注垂萬絙，坐間斗寒衣可增。"]'),
('bb02e37b-2516-498a-be11-a2c273016948','和宋復古大雨  其二','司馬光','宋','宋诗','song-poetry','','[]','雷公推車電施鞭，飛騰九澤舞百川。',32,'全唐诗/poet.song.29000.json','["雷公推車電施鞭，飛騰九澤舞百川。", "須臾開晴萬物鮮，仰視白日當青天。"]'),
('8a19d862-12ba-4582-a885-5d777a77e095','南園雜詩六首 見山臺晝卧偶成','司馬光','宋','宋诗','song-poetry','','[]','移牀獨上高臺卧，颯颯涼風吹面過。',32,'全唐诗/poet.song.29000.json','["移牀獨上高臺卧，颯颯涼風吹面過。", "林蟬忽噪驚薄夢，手執殘書幅巾墮。"]'),
('71022907-36c1-4343-8d3c-05211d80a5b0','南園雜詩六首 修酴醾架','司馬光','宋','宋诗','song-poetry','','[]','貧家不辦構堅木，縛竹立架擎酴醿。',80,'全唐诗/poet.song.29000.json','["貧家不辦構堅木，縛竹立架擎酴醿。", "風搖雨漬不耐久，未及三載俱離披。", "往來遂復廢此徑，舉頭礙冠行絓衣。", "呼奴改作豈得已，抽新換故拆四籬。", "來春席地還可飲，日色不到香風吹。"]'),
('0c219013-5bdc-4dcc-8697-9913b3a9f2e3','南園雜詩六首 螢','司馬光','宋','宋诗','song-poetry','','[]','林塘荒濕地，向夕已飛螢。',48,'全唐诗/poet.song.29000.json','["林塘荒濕地，向夕已飛螢。", "月没蛩吟砌，露涼人在庭。", "隨風疑落燼，過水亂疏星。", "學子燈前寢，誰將爾照經。"]'),
('748135d3-23ab-4969-ae0a-e98121d32097','南園雜詩六首 明叔家瑞蓮','司馬光','宋','宋诗','song-poetry','','[]','君家得蓮種，遠自浙江湄。',72,'全唐诗/poet.song.29000.json','["君家得蓮種，遠自浙江湄。", "明燭然深盌，濃朱畫細絲。", "盛開尤菡萏，到落不離披。", "豈獨夏花好，仍兼秋實奇。", "味長包石蜜，殻嫩剝燕脂。", "況復芬芳久，霜前殊未衰。"]'),
('196285c2-1b15-4d71-b8c4-373db67a0e7f','南園雜詩六首 蓮房','司馬光','宋','宋诗','song-poetry','','[]','蓮房前後熟，供噉不須齊。',48,'全唐诗/poet.song.29000.json','["蓮房前後熟，供噉不須齊。", "肉嫩山蜂子，稜深天馬蹄。", "尚連餘蘂在，深映亂荷低。", "脆美知新采，近根猶带泥。"]'),
('cf33a40c-2299-4bb6-aeec-0c80d61cf60d','南園雜詩六首 不寐','司馬光','宋','宋诗','song-poetry','','[]','長年睡益少，氣耗非神清。',72,'全唐诗/poet.song.29000.json','["長年睡益少，氣耗非神清。", "昨朝多啜茶，況以思慮并。", "中煩枕屢移，展轉何時明。", "蘇秦六國印，力取鴻毛輕。", "白圭萬金産，運智立可營。", "如何五更夢，百方終不成。"]'),
('65a94d46-7b65-46f8-baea-5b0a17eaf931','南園雜詩六首 苦雨','司馬光','宋','宋诗','song-poetry','','[]','今春憂亢陽，引領望雲族。',180,'全唐诗/poet.song.29000.json','["今春憂亢陽，引領望雲族。", "首夏忽滂沲，意爲蒼生福。", "自爾無虛日，高原亦霑足。", "連年困饑饉，此際庶和熟。", "如何涉秋序，沈陰仍慘黷。", "長簷瀉潺湲，晝夜浩相續。", "喧豗流潦怒，突兀壞垣秃。", "駕牛泥没鼻，跨馬水平腹。", "瓦欹松漫白，道廢草濃綠。", "汙萊閔下田，漏濕憐破屋。", "縱横委地麻，狼藉卧隴穀。", "怯聞饑嬰啼，愁聽寡婦哭。", "閑官雖無責，飽食愧有祿。", "世紛久去心，物役奈經目。", "欝陶聊秉筆，狂簡已盈幅。"]'),
('1cd54922-32b4-4cce-b043-c8a279a37756','八月十五日夜宿南園懷王君貺','司馬光','宋','宋诗','song-poetry','','[]','昔公在洛師，未嘗棄嘉節。',60,'全唐诗/poet.song.29000.json','["昔公在洛師，未嘗棄嘉節。", "今宵秋半分，空羨西園月。", "天色湛澄清，風聲冷騷屑。", "笑言不可親，引領望金闕。", "賴有篋中詩，端居數披閱。"]'),
('98d75821-eee1-41b0-8ed8-55be619931ed','八月十六日過天街懷景仁','司馬光','宋','宋诗','song-poetry','','[]','秋潦收四野，晴雲無一斑。',60,'全唐诗/poet.song.29000.json','["秋潦收四野，晴雲無一斑。", "忽驚龍門缺，遠見鳴臯山。", "涼飈入毛髮，顥氣清心顔。", "悠然念吾友，逍遙城闕間。", "思陪籃輿尾，共此登臨閑。"]'),
('507478d9-1588-4d7a-b96d-a7a065e599f3','宿南園','司馬光','宋','宋诗','song-poetry','','[]','頃來興味少，旬日不爲詩。',48,'全唐诗/poet.song.29000.json','["頃來興味少，旬日不爲詩。", "昏昏但思眠，疲病知吾衰。", "豈無籬邊菊，不欲拈酒巵。", "絡緯爾何苦，終夕鳴聲悲。"]'),
('1d299e54-62da-4133-8303-78679e1db856','宿南園 九月十一日夜雨宿南園韓秉國寄酒兼見招以詩謝之','司馬光','宋','宋诗','song-poetry','','[]','雨多秋草盛，濃綠擁寒階。',264,'全唐诗/poet.song.29000.json','["雨多秋草盛，濃綠擁寒階。", "吾廬奥且曲，退縮如晴蝸。", "小園已自隘，欲往泥霑鞋。", "體羸畏風冷，室處門常䦱。", "九日古所重，負此時節佳。", "緬想使君宴，綺席臨高齋。", "肥羜堆玉盤，飛觴酒如淮。", "楚舞陵湖波，茱茰落金釵。", "神醒鼓吹喧，百疊疑傾崖。", "歡餘忽我思，牙兵星火差。", "潩泉恥獨醉，醇味相與偕。", "我飲雖不多，和氣浩無涯。", "梧子拾爲果，拒霜伐爲柴。", "沼中數寸魚，烹煎足爲鮭。", "誰言無以侑，繞渚多鳴蛙。", "交道久衰薄，巋然見吾儕。", "奈何數舍遙，晤語積年乖。", "況乃辱嘉招，私心豈不懷。", "轘轅石道澀，重以陰雲埋。", "雖有果下馬，款段非渥洼。", "臨風徒竦踊，志願焉能諧。", "狂詩寄一笑，聊用當詼俳。"]'),
('0ab4121b-255d-4b92-8150-8390e85f3eae','子厚先生哀辭','司馬光','宋','宋诗','song-poetry','','[]','先生負材氣，弱冠遊窮邊。',288,'全唐诗/poet.song.29000.json','["先生負材氣，弱冠遊窮邊。", "麻衣揖鉅公，決策期萬全。", "謂言叛羌背，坐可執而鞭。", "意趣小參差，萬金莫留連。", "中年更折節，六籍事精研。", "羲農訖周孔，上下皆貫穿。", "造次循繩墨，儒行無少愆。", "師道久廢闋，模範幾無傳。", "先生力振起，不絕尚聯綿。", "教人學雖博，要以禮爲先。", "庶幾百世後，復覩三王前。", "釋老比尤熾，羣倫將蕩然。", "先生論性命，指示令知天。", "聲光動京師，名卿爭薦延。", "寘之石渠閣，豈徒修簡編。", "丞相正自用，立有榮枯權。", "先生不可屈，去之歸卧堅。", "孤嫠聚滿室，餬口耕無田。", "欣欣茹藜藿，皆不思肥鮮。", "近因詔書起，尋取病吿旋。", "舊廬不能到，丹旐風翩翩。", "人生會歸盡，但問愚與賢。", "借令陽虎壽，詎足驕顔淵。", "況於朱紫貴，飄忽如雲煙。"]'),
('c68d7c23-85ee-4cd4-b4b6-dfd30eb31280','古墳','司馬光','宋','宋诗','song-poetry','','[]','茫茫野田平極目，歷歷古墳如夏屋。',80,'全唐诗/poet.song.29000.json','["茫茫野田平極目，歷歷古墳如夏屋。", "碑板無文荆棘深，石獸沈淪松栢秃。", "問人雖不知姓名，昔皆高官仍厚祿。", "子孫流落何所之，凶吉當年非不卜。", "我來正值寒食天，祭膰不設無人哭。"]'),
('fd7746de-f55c-4327-865d-4077310f3386','酬趙少卿藥園見贈','司馬光','宋','宋诗','song-poetry','','[]','鄙性苦迂僻，有園名獨樂。',60,'全唐诗/poet.song.29000.json','["鄙性苦迂僻，有園名獨樂。", "滿城爭種花，治地惟種藥。", "栽培親荷鍤，購買屢傾槖。", "縱横百餘區，所識恨不博。", "身病尚未攻，何論療民瘼。"]'),
('ee7a2670-cfd9-44af-a2aa-2a3d8b8cad55','登封龐國博年三十八自云欲棄官隱嵩山作吏隱庵於縣寺俾光賦詩勉率塞命','司馬光','宋','宋诗','song-poetry','','[]','懋德負長才，全牛不足剸。',84,'全唐诗/poet.song.29000.json','["懋德負長才，全牛不足剸。", "纔爲百里宰，驥足殊未展。", "齒髮方盛彊，趣尚已高遠。", "結庵睋二室，志欲巢絕巘。", "賢人心如雲，無迹有舒卷。", "不須驚俗目，卓犖乃求顯。", "既知吏可隱，何必遺軒冕。"]'),
('48860966-d4be-499c-8e1b-1886b6bb4ec4','暮春同劉伯壽史誠之飲宋叔達園','司馬光','宋','宋诗','song-poetry','','[]','絮狂飛作團，梅小不多酸。',72,'全唐诗/poet.song.29000.json','["絮狂飛作團，梅小不多酸。", "共惜春餘好，更窮今日歡。", "清流入花底，翠嶺出林端。", "嫩筍玉縈筯，新櫻珠照盤。", "邀迎嘉客易，會合故人難。", "寄語門前僕，驊騮任解鞍。"]'),
('5e48886f-05b1-4b10-a047-ee34b4a5ec6f','用前韻再呈','司馬光','宋','宋诗','song-poetry','','[]','舊友今餘幾，追思鼻可酸。',72,'全唐诗/poet.song.29000.json','["舊友今餘幾，追思鼻可酸。", "休論身外事，且盡目前歡。", "薜荔垂堤面，酴醿擁席端。", "舞精抽繭緒，絃妙落珠盤。", "醇酒回春易，靈丹却老難。", "扶歸不復記，酩酊上金鞍。"]'),
('b81117b0-aa8f-4a64-a7ae-99340ed72af1','示道人','司馬光','宋','宋诗','song-poetry','','[]','天覆地載如洪鑪，萬物死生同一塗。',67,'全唐诗/poet.song.29000.json','["天覆地載如洪鑪，萬物死生同一塗。", "其中松柏與龜鶴，得年稍久終摧枯。", "借令真有蓬萊山，未免亦居天地間。", "君不見太上老君頭似雪，世人浪說駐童顔。"]'),
('8cd5e59d-e564-4c9e-842e-bab1d03880e1','謝君貺中秋見招不及赴','司馬光','宋','宋诗','song-poetry','','[]','不侍庾公宴，月華虛四秋。',48,'全唐诗/poet.song.29000.json','["不侍庾公宴，月華虛四秋。", "幸逢東閣開，又阻西園遊。", "清輝散廣坐，孤影隨行輈。", "衮衣如未歸，志願終可酬。"]'),
('8301ecd8-22ed-4dc6-9a36-de56df32c0d3','久雨效樂天體','司馬光','宋','宋诗','song-poetry','','[]','雨多雖可厭，氣涼還可喜。',60,'全唐诗/poet.song.29000.json','["雨多雖可厭，氣涼還可喜。", "欲語口慵開，無眠身懶起。", "一榻有餘寛，一飯有餘美。", "想彼廟堂人，正應憂燮理。", "聞范景仁遷，居許昌爲詩。"]'),
('3fd0879f-eb33-4cd7-a12f-0759d9e2f526','聞景仁遷居許昌爲詩寄之','司馬光','宋','宋诗','song-poetry','','[]','天衢名利場，塵泥繼朝昏。',240,'全唐诗/poet.song.29000.json','["天衢名利場，塵泥繼朝昏。", "況兹辭榮久，厭苦車馬喧。", "慨然忽高舉，翩若黄鵠翻。", "朝賣西城宅，暮理南行轅。", "回首豈無懷，眷眷望國門。", "想象解装初，完美未可論。", "縱横置老屋，缺剝周短垣。", "臧獲念去故，炊爨假甖盆。", "幼稚喜就新，階庭走諸孫。", "幸有克家子，生事不日温。", "許昌昔名都，於今亦雄藩。", "先賢雖已遠，風迹凜猶存。", "况復多巨公，分義素所敦。", "丞相辭黄閣，學士乘朱轓。", "青雲司禁省，白首會山樊。", "潩水湛寒光，盡眼清心魂。", "華堂臨曲渚，畫舫承芳樽。", "高談金石諧，逸筆風雨奔。", "得朋誠多歡，孤陋未可諼。", "時當惠好音，獨樂慰荒園。"]'),
('f7246ce0-edc9-4813-b95e-cdbb0cb610e1','送張伯常同年移居郢州','司馬光','宋','宋诗','song-poetry','','[]','楚江白逶迤，楚山碧參差。',96,'全唐诗/poet.song.29000.json','["楚江白逶迤，楚山碧參差。", "玉炊稻粒長，縷切魚腴肥。", "羨君盡室行，飄然無所羈。", "伐竹營茅茨，種橘爲藩籬。", "荒坡無四垣，但以荷塘圍。", "官雖朝大夫，身世已相遺。", "野老坐爭席，林叟談忘歸。", "猶嫌沮溺徒，名字爲人知。"]'),
('5cca5406-7c1d-485b-9a14-ced1acbcd5be','南園飲罷留宿詰朝呈鮮于子駿范堯夫彝叟兄弟','司馬光','宋','宋诗','song-poetry','','[]','園僻青春深，衣寒積雨闋。',48,'全唐诗/poet.song.29000.json','["園僻青春深，衣寒積雨闋。", "中宵酒力散，卧對滿窗月。", "旁觀萬象寂，遠聽羣動絕。", "只疑玉壺冰，未足比明潔。"]'),
('bdaed820-74f5-464e-a00f-aaf2abe4f16d','自用前韻','司馬光','宋','宋诗','song-poetry','','[]','耿耿寐不成，迢迢夜未闋。',48,'全唐诗/poet.song.29000.json','["耿耿寐不成，迢迢夜未闋。", "良朋悔不留，負此當軒月。", "懷想空鬰陶，眺聽轉清絕。", "佗時重見過，餘樽猶可潔。"]'),
('297ff6c1-635b-4795-9077-d91b672914c3','不寐','司馬光','宋','宋诗','song-poetry','','[]','思夢久不效，良夜行已闌。',48,'全唐诗/poet.song.29000.json','["思夢久不效，良夜行已闌。", "此心如杯水，擾易澄苦難。", "百年能幾何，萬慮誰能殫。", "棄置勿復尋，専取形神安。"]'),
('c76c473a-441b-4dfa-93db-25b780da4683','招子駿堯夫','司馬光','宋','宋诗','song-poetry','','[]','虚牖延朝光，高林散晴靄。',60,'全唐诗/poet.song.29000.json','["虚牖延朝光，高林散晴靄。", "深夏猶清和，閑齋亦爽塏。", "離羣纔宿昔，跂佇心已痗。", "楸枰頗光潔，置設儼相待。", "軒車能朅来，雞黍足充餒。"]'),
('04305858-86c0-4c66-8302-dde685ef4689','和家兄喜晴用安之韻','司馬光','宋','宋诗','song-poetry','','[]','象龍雖得請，躍蜧亦須占。',72,'全唐诗/poet.song.29000.json','["象龍雖得請，躍蜧亦須占。", "既有膏苗益，寧無漂麥嫌。", "餘霏方映戶，反照忽通簾。", "羈旅愁懷闋，農家喜色添。", "田間拾穗滿，陌上荷鋤兼。", "預想三川迥，秋場萬庾尖。"]'),
('a7d200e5-530f-4701-b6f0-37f94571522a','病中子駿見招不往兼呈正叔堯夫','司馬光','宋','宋诗','song-poetry','','[]','衰朽拙自將，藴積成中病。',84,'全唐诗/poet.song.29000.json','["衰朽拙自將，藴積成中病。", "掩扉卧小榻，安養惟便静。", "遙知良友集，欝若荀陳盛。", "獻酬屏浮飾，簡率任真性。", "雖無束带苦，實憚把酒併。", "開囊檢藥物，不與樽罍稱。", "筋骸幸復常，佗時掃三徑。"]'),
('82b4d344-adb5-41e2-af4e-cd63c8404850','和子駿秋意','司馬光','宋','宋诗','song-poetry','','[]','好風自遠來，小雨初濡地。',72,'全唐诗/poet.song.29000.json','["好風自遠來，小雨初濡地。", "雖當未夏半，已有清秋意。", "新蟬乍孤吟，病葉或先墜。", "頓覺愈沉疴，暫喜濯炎熾。", "彩筆動高興，瑤徽發幽思。", "賤子獨何爲，宵涼甘熟寐。"]'),
('5f139297-aad7-4a1a-9053-5e3311bfba49','龍門','司馬光','宋','宋诗','song-poetry','','[]','石樓臨晴空，南眺出千里。',48,'全唐诗/poet.song.29000.json','["石樓臨晴空，南眺出千里。", "人憐山氣佳，予歎禹功美。", "想彼未鑿時，極目皆洪水。", "誰知耕桑民，幸免魴與鯉。"]'),
('edb8ff23-4e23-427e-bc74-29ee4a5c6579','座中呈子駿堯夫','司馬光','宋','宋诗','song-poetry','','[]','微雨雖妨行樂，薄寒却解留花。',28,'全唐诗/poet.song.29000.json','["微雨雖妨行樂，薄寒却解留花。", "今日且遊小圃，明朝更向誰家。"]'),
('6b7a8838-a546-4ce6-95ed-9afd2ae2bfd1','園櫻傷老也  其一','司馬光','宋','宋诗','song-poetry','','[]','園有繁櫻，圃有肥菁。',80,'全唐诗/poet.song.29000.json','["園有繁櫻，圃有肥菁。", "我酒既清，我殽既馨。", "我友戾止，聊以娛情。", "今我不樂，日月其徑。", "園有穠李，圃有肥杞。", "我酒既旨，我殽既美。", "我友戾止，改憂爲喜。", "今我不樂，年其有幾。"]'),
('bff98ea0-1280-463b-998c-084ce233d6ff','園櫻傷老也  其二','司馬光','宋','宋诗','song-poetry','','[]','園有弱柳，圃有肥韭。',40,'全唐诗/poet.song.29000.json','["園有弱柳，圃有肥韭。", "我酒既有，我殽既阜。", "載笑載歌，以宴我友。", "今我不樂，年其無久。"]'),
('33583745-581c-4602-925c-0865920ddd4e','園櫻傷老也  其三','司馬光','宋','宋诗','song-poetry','','[]','悠悠汎舟，載縱載横。',40,'全唐诗/poet.song.29000.json','["悠悠汎舟，載縱載横。", "白日將傾，飄風載驚。", "嗟我老矣，髪脫齒零。", "胡爲百憂，勞此餘生。"]'),
('7c92326b-ebba-4c20-b719-91a3877bc7b3','和景仁緱氏别後見寄求決樂議雖用其韻而不依次蓋以景仁才力高逸步驟絕羣非駑拙所能追故也','司馬光','宋','宋诗','song-poetry','','[]','至樂存要眇，失易求之難。',288,'全唐诗/poet.song.29000.json','["至樂存要眇，失易求之難。", "昔從周道衰，疇人曠其官。", "聲律久無師，文字多缺漫。", "仁皇閔崩壞，廣庭集危冠。", "紛紜鬭筆舌，異論誰能殫。", "或欲狥陳迹，竅厚潛鎪剜。", "或欲立私意，妄取舊史刊。", "古今互齟齬，大抵皆欺讕。", "景仁信其說，墨守不可干。", "賤子欲面從，誰與換膽肝。", "必求此議決，深谷爲崇巒。", "何如兩置之，試就中和看。", "天地育萬物，生成適暄寒。", "聖人保四海，皇極致阜安。", "樂理亦如此，炳煥猶朱丹。", "嘽緩與噍殺，折衷遺兩端。", "兹道苟不由，芒刃難嬰髖。", "魯樂最爲備，雍徹施三桓。", "齊韶猶肄習，太公避陳完。", "唐民聽伴侣，不復含悲酸。", "乃知樂有源，鐘鼓皆波瀾。", "昨者清明初，榆火始改鑚。", "景仁從許來，傾都咸聚觀。", "諸公競邀迓，非獨惜春殘。"]'),
('74c92e6e-e785-4356-a7d7-dca2d6dd4018','和秉國招范景仁飲景仁不至云方作書與光論樂','司馬光','宋','宋诗','song-poetry','','["\u897f\u6e56"]','小桃佳李實如拳，西湖盡眼鋪芳蓮。',144,'全唐诗/poet.song.29000.json','["小桃佳李實如拳，西湖盡眼鋪芳蓮。", "景仁不從鄉賢飲，爲此樂論方窮研。", "周衰官失疇人散，鐘律要眇誰能傳。", "近人欺衆出私意，最可閔笑房生顛。", "如光初不辨宮羽，是非得失安敢專。", "每煩教諭累百紙，頑如鐡石不可鐫。", "王李阮胡相詆毁，各執所學何妨偏。", "景仁家居鑄鬴斛，欲除民瘼恐未然。", "要須中和育萬物，始見大樂之功全。"]'),
('86b2a49c-b47a-4f4d-80c0-9f2e92a9335b','同子駿題和樂亭','司馬光','宋','宋诗','song-poetry','','[]','春禽弄晴朝，秋蟲吟雨夕。',120,'全唐诗/poet.song.29000.json','["春禽弄晴朝，秋蟲吟雨夕。", "風和振蘭芳，露寒滋菊色。", "萬物苟得所，隨時各有適。", "矧伊人最靈，胡爲長慼慼。", "聖人垂大訓，燦爛著方册。", "至樂和無聲，大禮簡無跡。", "心專守中庸，身不蹈邪僻。", "造次常在前，須臾不離側。", "窮通雖百變，何往不自得。", "兹亭聊寓名，和樂在胸臆。"]'),
('f12c7895-fc4a-45a0-8e15-7e3fc6b1f6f9','夏日西齋書事','司馬光','宋','宋诗','song-poetry','','[]','榴花映葉未全開，槐影沉沉雨勢來。',32,'全唐诗/poet.song.29000.json','["榴花映葉未全開，槐影沉沉雨勢來。", "小院地偏人不到，滿庭鳥迹印蒼苔。"]'),
('89c04f5f-cf6d-4f04-b965-5d9b48640457','過故洛陽城  其一','司馬光','宋','宋诗','song-poetry','','[]','四合連山繚繞青，三川滉漾素波明。',32,'全唐诗/poet.song.29000.json','["四合連山繚繞青，三川滉漾素波明。", "春風不識興亡意，草色年年滿故城。"]'),
('68dc961a-f1a3-4eee-a3cc-ca2f17e36d0e','過故洛陽城  其二','司馬光','宋','宋诗','song-poetry','','[]','煙愁雨嘯奈華生，宮闕簪蕖舊帝京。',32,'全唐诗/poet.song.29000.json','["煙愁雨嘯奈華生，宮闕簪蕖舊帝京。", "若問古今興廢事，請君只看洛陽城。"]'),
('e814ad8b-4c42-4819-ba85-51e79e1b5a06','華清宮','司馬光','宋','宋诗','song-poetry','','[]','新豐雞犬稀，薊北馬秋肥。',48,'全唐诗/poet.song.29000.json','["新豐雞犬稀，薊北馬秋肥。", "金殿翠華去，玉階紅葉飛。", "荒林上路廢，温谷舊流微。", "嗟此非人事，何須問是非。"]'),
('8db4405d-eb1d-4e7b-8ed4-1872670c66cc','初春登興國寺塔','司馬光','宋','宋诗','song-poetry','','[]','雨過風清露氣勻，林花變色柳條新。',32,'全唐诗/poet.song.29000.json','["雨過風清露氣勻，林花變色柳條新。", "爲君作意登高處，試望皇州表裏春。"]'),
('45296c86-e1fe-4c58-a93e-72b0b25b9ae8','虎牢關','司馬光','宋','宋诗','song-poetry','','[]','天險限西東，難知造化功。',48,'全唐诗/poet.song.29000.json','["天險限西東，難知造化功。", "路邀三晉會，勢壓兩河雄。", "餘雪霑枯草，驚飈卷斷蓬。", "徒觀爭戰處，今古索然空。"]'),
('dcf0e481-2919-4143-ae3d-75946f5e493d','和李殿丞倉中對菊  其一','司馬光','宋','宋诗','song-poetry','','[]','高士寄朝市，迥然心迹殊。',48,'全唐诗/poet.song.29000.json','["高士寄朝市，迥然心迹殊。", "秋風太倉裏，黄菊滿庭隅。", "陶令成詩後，王公送酒無。", "遙知厭俗事，未免強躊蹰。"]'),
('de88e95e-1e1e-463c-836b-ed920aafd2eb','和李殿丞倉中對菊  其二','司馬光','宋','宋诗','song-poetry','','[]','文案漸消散，倉閑吏已稀。',48,'全唐诗/poet.song.29000.json','["文案漸消散，倉閑吏已稀。", "庭空數蝶下，夜静一螢飛。", "愛賞忽成句，淹留時忘歸。", "高情雖不繫，遇此獨依依。"]'),
('205a9ea4-165e-4e86-8255-381bd949f548','和李殿丞倉中對菊  其三','司馬光','宋','宋诗','song-poetry','','[]','凉風正蕭瑟，好月復徘徊。',48,'全唐诗/poet.song.29000.json','["凉風正蕭瑟，好月復徘徊。", "幽興眇不盡，芳罇時一開。", "餘英蓋紅葉，墜露濕蒼苔。", "從此東籬下，應忘歸去來。"]'),
('1ac454ca-5def-455d-8156-890ecc03aa67','送何萬下第歸蜀  其一','司馬光','宋','宋诗','song-poetry','','[]','十上終無就，才高定復論。',48,'全唐诗/poet.song.29000.json','["十上終無就，才高定復論。", "清時守儒術，白首在丘園。", "遠樹隱殘日，孤煙生暮村。", "揚鞭萬里去，幾許不銷魂。"]'),
('28005d45-94d7-4bb0-9dfb-aaaeb30676ec','送何萬下第歸蜀  其二','司馬光','宋','宋诗','song-poetry','','[]','失意流年老，殘春對夕陽。',48,'全唐诗/poet.song.29000.json','["失意流年老，殘春對夕陽。", "可堪臨遠道，更復舉離觴。", "花柳已蕭索，雲山復渺茫。", "西風如有意，音信勿相忘。"]'),
('f65c222f-f46d-4ffd-b9a7-5f5f90d26eb4','執酒','司馬光','宋','宋诗','song-poetry','','[]','執酒勸君君盡之，今朝取醉不當疑。',32,'全唐诗/poet.song.29000.json','["執酒勸君君盡之，今朝取醉不當疑。", "好風好景心無事，閑利閑名何足知。"]'),
('a78f6c5d-aa51-4382-a82c-317c39df971b','河橋春别','司馬光','宋','宋诗','song-poetry','','[]','河橋春盡送君歸，又惜無歡度此時。',32,'全唐诗/poet.song.29000.json','["河橋春盡送君歸，又惜無歡度此時。", "亂花滿眼遮人望，不見行塵空酒旗。"]'),
('c1ccc3aa-02d8-498b-8730-3b46571a3cd1','答陳進士謂之憶江東舊遊見贈','司馬光','宋','宋诗','song-poetry','','[]','客路今東去，亭臯木葉飛。',48,'全唐诗/poet.song.29000.json','["客路今東去，亭臯木葉飛。", "居然不堪恨，況與賞心違。", "顧渚煙波闊，長洲草樹微。", "江邊好春色，行望錦標歸。"]'),
('5b58ad90-c531-483c-bbb0-9d61839f6349','又贈謂之  其一','司馬光','宋','宋诗','song-poetry','','[]','文藻兼名理，三吳第一賢。',24,'全唐诗/poet.song.29000.json','["文藻兼名理，三吳第一賢。", "鄉心幾千里，飛鴈滿秋天。"]'),
('7637bcb5-9eed-421e-a418-1e884eb788fa','又贈謂之  其二','司馬光','宋','宋诗','song-poetry','','[]','籬下多新菊，淵明歸思長。',24,'全唐诗/poet.song.29000.json','["籬下多新菊，淵明歸思長。", "主人方愛客，未得傲羲皇。"]'),
('308d164c-7461-4b6c-85a7-0afaacf972bc','又贈謂之  其三','司馬光','宋','宋诗','song-poetry','','[]','君念東歸日，應須晝繡榮。',24,'全唐诗/poet.song.29000.json','["君念東歸日，應須晝繡榮。", "當令故關吏，還識棄繻生。"]'),
('5fe253eb-1761-4045-8525-d2ef7183304f','重九日憶菊','司馬光','宋','宋诗','song-poetry','','[]','節物都何晚，佳辰容易過。',24,'全唐诗/poet.song.29000.json','["節物都何晚，佳辰容易過。", "黄花不足念，當奈酒杯何。"]'),
('832e1fd9-d6b9-4095-8159-40f7704ae608','客思','司馬光','宋','宋诗','song-poetry','','[]','客思倦漂泊，居然感物華。',48,'全唐诗/poet.song.29000.json','["客思倦漂泊，居然感物華。", "關頭望紅葉，馬上見黄花。", "薄宦終無定，閑愁詎有涯。", "今朝書至否，幾夕夢還家。"]'),
('ba987bbf-6f55-4d62-bba4-6dab266762f3','前年春與楚正叔同遊陟屺寺今兹已復周歳窅然思之','司馬光','宋','宋诗','song-poetry','','[]','陟屺寺南山，曾陪半日閑。',24,'全唐诗/poet.song.29000.json','["陟屺寺南山，曾陪半日閑。", "春來夢攜手，宛在白雲間。"]'),
('32313472-7367-4c77-b1e1-f18423cced08','曉霽','司馬光','宋','宋诗','song-poetry','','[]','夢覺繁聲絕，林光透隙來。',24,'全唐诗/poet.song.29000.json','["夢覺繁聲絕，林光透隙來。", "開門驚烏鳥，餘滴墮蒼苔。"]'),
('6cdee8cf-158d-4d37-bff6-6ac0e3fddc8f','觀江上人壁許道寧畫寒林','司馬光','宋','宋诗','song-poetry','','[]','昔曾驅瘦馬，衝雪過滎陽。',24,'全唐诗/poet.song.29000.json','["昔曾驅瘦馬，衝雪過滎陽。", "不悟當時景，蕭然在此堂。"]'),
('c327313d-d980-4ad4-bcf7-6af1e85ff080','自都往餘杭懷聶之美','司馬光','宋','宋诗','song-poetry','','[]','閣上新文卷，欲逢知已開。',24,'全唐诗/poet.song.29000.json','["閣上新文卷，欲逢知已開。", "相思不能已，欹枕夢君來。"]'),
('2b337644-664f-499c-8b7c-fd77cfc6794c','夢與之美爲寒食遊','司馬光','宋','宋诗','song-poetry','','[]','寒食無佳賞，芳菲半已空。',24,'全唐诗/poet.song.29000.json','["寒食無佳賞，芳菲半已空。", "夜來逢勝友，末至負東風。"]'),
('58e89372-2957-43d3-bc3d-8b85f69cd9c2','秋日登觀信亭','司馬光','宋','宋诗','song-poetry','','[]','西風連夜雨，草樹已蕭條。',48,'全唐诗/poet.song.29000.json','["西風連夜雨，草樹已蕭條。", "宿靄稍零落，寒山更寂寥。", "林紅猶带日，岸白欲生潮。", "新鴈來何處，離離天際遙。"]'),
('da424da6-0ad3-4d5a-9d2e-33097bfb0852','湖上村家','司馬光','宋','宋诗','song-poetry','','[]','萬頃寒煙外，茅茨枕碧流。',48,'全唐诗/poet.song.29000.json','["萬頃寒煙外，茅茨枕碧流。", "楓林巢乳鶴，沙溆亂鳴鷗。", "漠漠菰蒲晚，蒼蒼蘆荻秋。", "欲過南浦去，籬下出漁舟。"]'),
('c6212cc3-136f-4bed-a712-8454abcbadd9','别聶之美','司馬光','宋','宋诗','song-poetry','','[]','客宦常漂泊，離懷徒自勞。',48,'全唐诗/poet.song.29000.json','["客宦常漂泊，離懷徒自勞。", "貧無衣換酒，空有涕霑袍。", "木葉寒猶在，江湖暮更豪。", "行舟遠不見，賴有片帆高。"]'),
('00032b89-d1f5-493b-a78a-9a7a5d20aacb','松江  其一','司馬光','宋','宋诗','song-poetry','','[]','吳山黯黯江水清，欲雨未雨傷交情。',32,'全唐诗/poet.song.29000.json','["吳山黯黯江水清，欲雨未雨傷交情。", "扁舟蕩漾泊何處，紅蓼白蘋相映生。"]'),
('e4cf8d76-7ed1-4209-9097-2c4b83d8044a','松江  其二','司馬光','宋','宋诗','song-poetry','','[]','秋風索索連江起，暮過煙波十餘里。',32,'全唐诗/poet.song.29000.json','["秋風索索連江起，暮過煙波十餘里。", "長蘆瘦竹映漁家，燈火渺茫寒照水。"]'),
('6f9fc5fd-ddb9-404a-83ff-f037ff707801','潮水  其一','司馬光','宋','宋诗','song-poetry','','[]','平江欲上潮，古木自蕭蕭。',24,'全唐诗/poet.song.29000.json','["平江欲上潮，古木自蕭蕭。", "兩岸饒葭葦，寒波浸寂寥。"]'),
('65499535-b40d-4cbe-b9e0-fca79442262e','潮水  其二','司馬光','宋','宋诗','song-poetry','','[]','淋淋出海門，百里雪花噴。',24,'全唐诗/poet.song.29000.json','["淋淋出海門，百里雪花噴。", "坐看東歸去，平沙空有痕。"]'),
('b299e51c-3fc7-47fd-8476-e2da030d777c','雙竹','司馬光','宋','宋诗','song-poetry','','[]','雙幹標枯腹，青青凡幾霜。',48,'全唐诗/poet.song.29000.json','["雙幹標枯腹，青青凡幾霜。", "龍騰雙角直，鯨噴兩鬚長。", "但欲尋支遁，安能問辟疆。", "屢來非别意，未與此君忘。"]'),
('b72ae5b9-b31c-4e07-9865-776949e28bda','旅宿睢陽南湖','司馬光','宋','宋诗','song-poetry','','[]','梁王棄宮館，時世古今違。',48,'全唐诗/poet.song.29000.json','["梁王棄宮館，時世古今違。", "猶有南湖水，春來鴈鶩飛。", "樓臺沈倒影，林薄挂餘暉。", "豪侈終何在，行人得暫依。"]'),
('c220083a-ee3b-49eb-b732-b3c278e69413','南湖  其一','司馬光','宋','宋诗','song-poetry','','[]','宋都南野水，花柳媚名園。',48,'全唐诗/poet.song.29000.json','["宋都南野水，花柳媚名園。", "鳥起沙留迹，魚驚浪結痕。", "朱橋通别島，白路出荒村。", "城邑雖云邇，常無車馬喧。"]'),
('b7760337-cace-4ef5-970a-cea4d2f70fe2','南湖  其二','司馬光','宋','宋诗','song-poetry','','[]','海鴈長橋北，乘閑日日來。',48,'全唐诗/poet.song.29000.json','["海鴈長橋北，乘閑日日來。", "遊魚自應樂，宿鳥不相猜。", "弱柳週遭合，芳花次第開。", "梁王昔遊集，後乘列鄒枚。"]'),
('49f2bb66-0679-4ce3-a476-6670d4373baf','西谿公讌  其一','司馬光','宋','宋诗','song-poetry','','[]','五馬非從樂，西城念勸功。',48,'全唐诗/poet.song.29000.json','["五馬非從樂，西城念勸功。", "翠帷低映水，紅斾不勝風。", "葉脫青山静，雲歸碧落空。", "淹留盡佳興，新月漸朦朧。"]'),
('a2a28a38-6f42-4b47-b454-376468ea7e0e','西谿公讌  其二','司馬光','宋','宋诗','song-poetry','','[]','謝守愛山水，軍城況不賖。',48,'全唐诗/poet.song.29000.json','["謝守愛山水，軍城況不賖。", "魚驚避落葉，鳥倦立浮查。", "古柏依岡遠，垂楊带岸斜。", "秋風吹急管，一曲度荷花。"]'),
('52ca6e31-eab7-4de2-8aca-6ded3e31e222','西湖','司馬光','宋','宋诗','song-poetry','','["\u897f\u6e56"]','佳麗三吳國，湖光蕩日華。',48,'全唐诗/poet.song.29000.json','["佳麗三吳國，湖光蕩日華。", "魚驚動蘋葉，鷰喜掠楊花。", "雲過山腰黑，風驅雨脚斜。", "煙波遙盡處，彷彿見漁家。"]'),
('b2ed37bf-f214-4fc6-b254-aa591beb6788','金山寺','司馬光','宋','宋诗','song-poetry','','[]','香剎冠嵳峨，松門絡薜蘿。',48,'全唐诗/poet.song.29000.json','["香剎冠嵳峨，松門絡薜蘿。", "風清塵不到，岸闊鳥難過。", "欲雨江聲怒，新晴海氣多。", "行舟未搖棹，回望隔烟波。"]'),
('d3726a91-f230-4b57-a8fe-6b784925a149','出塞','司馬光','宋','宋诗','song-poetry','','[]','邊草荒無路，星河秋夜明。',48,'全唐诗/poet.song.29000.json','["邊草荒無路，星河秋夜明。", "卷旗遮遠塞，歇馬受降城。", "霜重征衣薄，風高戰鼓鳴。", "將軍功未厭，士卒不須生。"]'),
('8f1f98ac-9030-4393-a59d-3c5305e751ed','古松','司馬光','宋','宋诗','song-poetry','','[]','摧頽巖壑間，磊落得天頑。',48,'全唐诗/poet.song.29000.json','["摧頽巖壑間，磊落得天頑。", "香葉低漸水，餘根倒挂山。", "白猿窺子落，黄鶴認巢還。", "不久應爲石，莓苔舊已班。"]'),
('02c64b95-870f-4046-b8bd-cec067a68b62','聞龔伯建下第','司馬光','宋','宋诗','song-poetry','','[]','文章真長物，堪歎又遺賢。',48,'全唐诗/poet.song.29000.json','["文章真長物，堪歎又遺賢。", "利器空埋土，靈光久照天。", "趙錐猶未出，荆璧會須傳。", "道在雖窮困，知君不慨然。"]'),
('3103ac4c-fbd8-4c64-a05e-949fd7349f91','故絳城','司馬光','宋','宋诗','song-poetry','','[]','文公恢霸略，征討輔周衰。',48,'全唐诗/poet.song.29000.json','["文公恢霸略，征討輔周衰。", "奕世爲盟主，諸侯聽會期。", "山河表裏在，朝市古今移。", "欲訪虒祁處，鄉人亦不知。"]'),
('8bcc2f54-4e10-40b0-a80c-aa60ae903039','題陳秀才園林','司馬光','宋','宋诗','song-poetry','','[]','劇談驚滿座，音貌獨琅然。',48,'全唐诗/poet.song.29000.json','["劇談驚滿座，音貌獨琅然。", "可惜酈生老，誰知蘇季賢。", "青囊世外藥，碧幕醉中天。", "不佩黄金印，都緣負郭田。"]'),
('5af7a2f3-b61f-491b-8802-c38f0001f8e5','九日登麻藺坂','司馬光','宋','宋诗','song-poetry','','[]','客路逢佳節，無歡更益愁。',24,'全唐诗/poet.song.29000.json','["客路逢佳節，無歡更益愁。", "前山造雲日，登陟不因遊。"]'),
('2bcee33f-a883-4241-838e-82fd2f93c45d','遊延安宿馬太博東館','司馬光','宋','宋诗','song-poetry','','[]','高館寂無譁，安閑勝在家。',48,'全唐诗/poet.song.29000.json','["高館寂無譁，安閑勝在家。", "暮煙凝塞上，堠火落天涯。", "坐久筆生凍，夜闌燈作花。", "主人意未盡，歸路不爲賖。"]'),
('00d82531-f431-4c2f-8ebb-ad91213eea73','塞上  其一','司馬光','宋','宋诗','song-poetry','','[]','節物正防秋，關山落葉稠。',48,'全唐诗/poet.song.29000.json','["節物正防秋，關山落葉稠。", "霜風壯金鼓，霧氣濕旌裘。", "未得西羌滅，終爲大漢羞。", "慚非班定遠，棄筆取封侯。"]'),
('16d22c3f-8b39-4ce7-abb7-a5cdfd6f4df1','塞上  其二','司馬光','宋','宋诗','song-poetry','','[]','鴻鴈秋先到，牛羊夕未還。',48,'全唐诗/poet.song.29000.json','["鴻鴈秋先到，牛羊夕未還。", "旌旗遙背水，亭堠遠依山。", "落日銜西塞，陰烟澹北關。", "何時獻戎捷，鞍甲一朝閑。"]'),
('a4e634b4-1c48-4a56-8560-ad2ae95342c7','塞上  其三','司馬光','宋','宋诗','song-poetry','','[]','瀚海秋風至，蕭蕭木葉飛。',48,'全唐诗/poet.song.29000.json','["瀚海秋風至，蕭蕭木葉飛。", "如何逢漢使，猶未寄征衣。", "不歎千里遠，難甘一信稀。", "年年沙漠鴈，隨意得南歸。"]'),
('3c409d62-2e3e-4e5c-9847-7183b8a38134','塞上  其四','司馬光','宋','宋诗','song-poetry','','[]','劍客蒼鷹隊，將軍白虎牙。',48,'全唐诗/poet.song.29000.json','["劍客蒼鷹隊，將軍白虎牙。", "分兵邏圁水，縱騎獵鳴沙。", "浪有書藏袖，難憑信達家。", "不堪聞曉角，吹盡落梅花。"]'),
('9abd3482-77df-457a-af0c-513b5d679b84','送何濟川爲龐公使慶陽席上探得冬字','司馬光','宋','宋诗','song-poetry','','[]','幕府遙三舍，傳車乘一封。',48,'全唐诗/poet.song.29000.json','["幕府遙三舍，傳車乘一封。", "忠深輕遠道，醉暖失嚴冬。", "圁水猶飛檄，蘆闋未滅烽。", "賢侯雖喜士，難得久從容。"]'),
('a4b01dac-3fc7-4c01-9f41-ad01e2423c2d','延安道中作','司馬光','宋','宋诗','song-poetry','','[]','羈旅兼邊思，川原蹀血新。',48,'全唐诗/poet.song.29000.json','["羈旅兼邊思，川原蹀血新。", "煙雲長带雨，草樹不知春。", "細水淘沙骨，驚飈轉路塵。", "今朝見烽火，白首太平人。"]'),
('719a1ea7-c94d-433a-9ae2-ef797defa216','鄜州懷聶之美','司馬光','宋','宋诗','song-poetry','','[]','何言內外家，憂患兩如麻。',48,'全唐诗/poet.song.29000.json','["何言內外家，憂患兩如麻。", "别淚行三歳，思心各一涯。", "海邊昏霧雨，塞外慘風沙。", "安得雲飛術，乘空去不遐。"]'),
('2b44fcad-7fe0-440c-9e2a-0a945a85a44c','和張推官同年春陰無緒偶成  其一','司馬光','宋','宋诗','song-poetry','','[]','澹泊輕雲寒不收，未成春雨只添愁。',32,'全唐诗/poet.song.29000.json','["澹泊輕雲寒不收，未成春雨只添愁。", "風煙寂寞幾何限，盡入憑高一寸眸。"]'),
('76f36130-71a8-4a64-9c00-26a970b402a5','和張推官同年春陰無緒偶成  其二','司馬光','宋','宋诗','song-poetry','','[]','薄寒未去臘纔過，春色先知在綠波。',32,'全唐诗/poet.song.29000.json','["薄寒未去臘纔過，春色先知在綠波。", "不是宿雲能作思，大都王粲自情多。"]'),
('29c70cf8-4c6c-49d2-aba8-c8cbb98d9101','歸田詩  其一','司馬光','宋','宋诗','song-poetry','','[]','秋水風波大，嗟嗟未可遊。',48,'全唐诗/poet.song.29000.json','["秋水風波大，嗟嗟未可遊。", "漁樵自應樂，珪組爲誰憂。", "直木知先伐，明珠忌暗投。", "果然鈎可曲，不惜取封侯。"]'),
('ef277d35-a898-4251-a0cc-18bd757435dc','歸田詩  其二','司馬光','宋','宋诗','song-poetry','','[]','紱冕誠虚器，簪裳悉畏途。',48,'全唐诗/poet.song.29000.json','["紱冕誠虚器，簪裳悉畏途。", "觸機身未保，好直道先孤。", "甔石曾何有，田園浪更無。", "可能推兩耜，沮溺共爲徒。"]'),
('ee22bd86-3095-4887-bc9b-c0022cc7e29e','歸田詩  其三','司馬光','宋','宋诗','song-poetry','','[]','聖哲雖云遠，遺文幸未亡。',48,'全唐诗/poet.song.29000.json','["聖哲雖云遠，遺文幸未亡。", "沈冥觀禮樂，彷彿見虞黄。", "雞黍延三逕，琴書樂一堂。", "逍遙名教內，富貴亦微茫。"]'),
('a5c618b1-9c04-47d9-8eb4-3d0eeb91dc8f','歸田詩  其四','司馬光','宋','宋诗','song-poetry','','[]','松菊陶潛宅，蓬蒿仲蔚家。',48,'全唐诗/poet.song.29000.json','["松菊陶潛宅，蓬蒿仲蔚家。", "行遊筇杖瘦，嘯傲幅巾斜。", "屋小疏茅覆，門深亂柳遮。", "村童迎客至，竹箒掃桃花。"]'),
('47c70d2b-de8e-472c-a421-78e6ca479f07','歸田詩  其五','司馬光','宋','宋诗','song-poetry','','[]','桑柘綠無際，田間戴勝飛。',48,'全唐诗/poet.song.29000.json','["桑柘綠無際，田間戴勝飛。", "清醪迎社熟，鳴雉向春肥。", "執耒時將急，銜杯日漸稀。", "四鄰能共樂，招飲莫相違。"]'),
('65c6914b-02e0-4ffa-8df1-4b072e280d04','春曉','司馬光','宋','宋诗','song-poetry','','[]','鐘漏初傳曉，滿窗風雨寒。',24,'全唐诗/poet.song.29000.json','["鐘漏初傳曉，滿窗風雨寒。", "東岡行可種，欹枕不成安。"]'),
('7fd90879-5f68-40df-b3e0-8c0a7943e8d7','詠史  其一','司馬光','宋','宋诗','song-poetry','','[]','不事王侯者，翛然鄭子真。',48,'全唐诗/poet.song.29000.json','["不事王侯者，翛然鄭子真。", "開田谷口美，荷鍤白渠春。", "德化移鄉曲，聲光動搢紳。", "一時鍾鼎貴，磨滅彼何人。"]'),
('aa616fbc-7499-409e-bd09-d6f5de705d1a','詠史  其二','司馬光','宋','宋诗','song-poetry','','[]','延陵腰利劍，上國使初通。',48,'全唐诗/poet.song.29000.json','["延陵腰利劍，上國使初通。", "待我周遊徧，逢君遣奠終。", "晶熒繫高樹，蕭瑟動寒風。", "誰敢欺生死，蒼蒼照爾衷。"]'),
('205be4b9-0cbf-4da4-a026-5b35634dd514','詠史  其三','司馬光','宋','宋诗','song-poetry','','[]','春風三閣上，珠翠日紛紛。',48,'全唐诗/poet.song.29000.json','["春風三閣上，珠翠日紛紛。", "樂飲陶江月，清歌遏海雲。", "醉中失陳國，夢裡入隋軍。", "玉樹庭花曲，凄凉不可聞。"]'),
('3be4d5c8-579a-444d-bdfe-5170735227ad','秋夜望月','司馬光','宋','宋诗','song-poetry','','[]','萬里氛昏歇，金波秋更明。',48,'全唐诗/poet.song.29000.json','["萬里氛昏歇，金波秋更明。", "星連河渚闇，風繞桂枝生。", "鳷鵲臨華館，新豐落故城。", "古今佳賞盡，殊自有餘清。"]'),
('645dc38d-005f-4f46-8386-fd65af19b71f','漢宮詞','司馬光','宋','宋诗','song-poetry','','[]','苜蓿花猶短，昌蒲葉未齊。',48,'全唐诗/poet.song.29000.json','["苜蓿花猶短，昌蒲葉未齊。", "更衣過柏谷，走馬宿棠棃。", "逆旅聊懷璽，田間共鬭雞。", "猶思飲雲露，高舉出虹蜺。"]'),
('e15ad7ff-de00-4a9f-a500-5595a28696d7','讀漢武帝紀','司馬光','宋','宋诗','song-poetry','','[]','方士陳仙術，飄飄意不疑。',48,'全唐诗/poet.song.29000.json','["方士陳仙術，飄飄意不疑。", "雲浮仲山鼎，風降壽宮祠。", "上藥行當就，殊庭庶可期。", "蓬萊何日返，五利不吾欺。"]'),
('06138cd0-7235-44ae-94d7-9b0710b89dcb','鷺鷥','司馬光','宋','宋诗','song-poetry','','[]','清閑自合無憂累，白髪何因更颯然。',32,'全唐诗/poet.song.29000.json','["清閑自合無憂累，白髪何因更颯然。", "遙望孤飛下秋水，雪花一片落晴天。"]'),
('df32b1ec-be44-4f75-acde-8e86de684ac3','待詔  其一','司馬光','宋','宋诗','song-poetry','','[]','京洛風塵裏，相逢眼盡青。',24,'全唐诗/poet.song.29000.json','["京洛風塵裏，相逢眼盡青。", "故人多密近，誰誦四隅銘。"]'),
('44fa56ef-fa00-414b-a3ba-58321cb15bd6','待詔  其二','司馬光','宋','宋诗','song-poetry','','[]','待詔久公車，囊装半已虚。',24,'全唐诗/poet.song.29000.json','["待詔久公車，囊装半已虚。", "雄文雖雅麗，未得似相如。"]'),
('6b2253e4-d0c5-404b-b3a3-cc244a752538','觀僧室畫山水','司馬光','宋','宋诗','song-poetry','','[]','畫精禪室冷，方暑久徘徊。',48,'全唐诗/poet.song.29000.json','["畫精禪室冷，方暑久徘徊。", "不盡林端雪，長青石上苔。", "心閑對巖岫，目浄失塵埃。", "坐久清風至，疑從翠澗來。"]'),
('5a1aee33-99c2-4301-a624-f37cff74ab5d','詠寒士','司馬光','宋','宋诗','song-poetry','','[]','洋洋泌水側，蓬室苦蕭條。',48,'全唐诗/poet.song.29000.json','["洋洋泌水側，蓬室苦蕭條。", "衣薄難勝夜，廚閑空過朝。", "笑談東郭履，歌誦買臣樵。", "但問才何似，無疑卿相遙。"]'),
('fab2d525-321b-4737-bd27-8e2312fb2f2a','贈外兄吳之才','司馬光','宋','宋诗','song-poetry','','[]','何須親始重，友分固非疏。',72,'全唐诗/poet.song.29000.json','["何須親始重，友分固非疏。", "況復羈孤極，同經憂患餘。", "晚成應大器，先得類凡魚。", "遊衍陪嚴忌，聲華誦子虚。", "蒲輪詔枚叔，駟馬寵相如。", "莫忘西都日，寒窗夜讀書。"]'),
('6d20a0c5-9542-4e41-9e6b-1f02687fbe3c','九日懷聶之美  其一','司馬光','宋','宋诗','song-poetry','','[]','錢唐江裏扁舟上，别後籬花幾度黄。',64,'全唐诗/poet.song.29000.json','["錢唐江裏扁舟上，别後籬花幾度黄。", "憂患縈心何繚繞，風光滿目盡凄凉。", "誰同鑿落杯中酒，獨繫茱茰肘後囊。", "可復無書道情素，雲間空有鴈南翔。"]'),
('6f55bffa-b409-44c1-a8a0-aa359b00a084','九日懷聶之美  其二','司馬光','宋','宋诗','song-poetry','','[]','太室横山蔽十里，相思空復上高臺。',64,'全唐诗/poet.song.29000.json','["太室横山蔽十里，相思空復上高臺。", "瓮頭白酒行當熟，籬下黄花稍復開。", "陶令不無同醉興，孟君況有解嘲才。", "欲憑西北高風勢，飛度轘轅勸一杯。"]'),
('5c3c63d5-668d-40ec-b304-96e8045d1255','飲吳之才家','司馬光','宋','宋诗','song-poetry','','[]','京洛相逢設主人，富家鼎食不如貧。',32,'全唐诗/poet.song.29000.json','["京洛相逢設主人，富家鼎食不如貧。", "解衣換酒同爲樂，知是交情百倍親。"]'),
('13def0a1-6c3d-413b-b9a6-0cede51fc917','晚秋洛中思歸東園','司馬光','宋','宋诗','song-poetry','','[]','不利不名空去國，鴈飛葉落未歸來。',32,'全唐诗/poet.song.29000.json','["不利不名空去國，鴈飛葉落未歸來。", "秋風肯待主人至，籬下黄花隨意開。"]'),
('8a2f9975-8f38-4c45-b92e-febc1fd8789d','普明寺荷塘上置酒','司馬光','宋','宋诗','song-poetry','','[]','菡萏飄零水寂寥，敗荷疏柳共蕭條。',32,'全唐诗/poet.song.29000.json','["菡萏飄零水寂寥，敗荷疏柳共蕭條。", "煙斜雨細愁無限，醇酒千分不易消。"]'),
('e179403c-e070-4bb4-a4c7-a64a610eb1d6','送孟仲習宜君令','司馬光','宋','宋诗','song-poetry','','[]','合抱生毫末，無爲厭小官。',48,'全唐诗/poet.song.29000.json','["合抱生毫末，無爲厭小官。", "政成心更逸，道勝意常寛。", "野迥山形秀，雲疏雪意闌。", "離杯如不盡，何用禦祁寒。"]'),
('ff3c9e6a-ed25-4753-ba88-4401ad2b14f0','野廟','司馬光','宋','宋诗','song-poetry','','[]','古廟崩榱在，牆間雜樹荒。',48,'全唐诗/poet.song.29000.json','["古廟崩榱在，牆間雜樹荒。", "依稀設餘像，寂寞閟祠堂。", "舊日牲豭地，今晨狐兔鄉。", "英靈如未滅，何以度凄凉。"]'),
('11eb3b1b-afdf-43fc-8b32-51f5d8db5ae3','吕祿廟','司馬光','宋','宋诗','song-poetry','','[]','赤帝祚四百，徒然諸吕謀。',48,'全唐诗/poet.song.29000.json','["赤帝祚四百，徒然諸吕謀。", "出遊逢友賣，未返見家收。", "弊冢昔無記，遺祠今幸留。", "士心俱左袒，何怨曲周侯。"]'),
('b9545867-f9ee-4e31-abe4-077c79fae816','雪霽登普賢閣','司馬光','宋','宋诗','song-poetry','','[]','積雪明朝日，山河坐可分。',48,'全唐诗/poet.song.29000.json','["積雪明朝日，山河坐可分。", "嶄巖初解凍，片段未歸雲。", "闊望窮人境，高尋俯鴈羣。", "開門枝鳥散，玉絮墮紛紛。"]'),
('3e7d7178-b399-45dc-8ba0-6ad23db1cfc4','上郡南三十里有相思亭在太山之麓二水所交平臯之上往來者徒習其名莫詳其義慶曆甲申歳余適延安過於其下于時夏虜梗邊征戍未息竊感東山采薇之義敘其情而愍其勞因作五詩庶幾不違周公之指且以釋亭之名爾  其一','司馬光','宋','宋诗','song-poetry','','[]','嶺上雙流水，猶知會合時。',24,'全唐诗/poet.song.29000.json','["嶺上雙流水，猶知會合時。", "行人過於此，那得不相思。"]'),
('9f14f00c-73c0-46f3-9ee6-f595efb3d2c3','上郡南三十里有相思亭在太山之麓二水所交平臯之上往來者徒習其名莫詳其義慶曆甲申歳余適延安過於其下于時夏虜梗邊征戍未息竊感東山采薇之義敘其情而愍其勞因作五詩庶幾不違周公之指且以釋亭之名爾  其二','司馬光','宋','宋诗','song-poetry','','[]','偃蹇登脩阪，高侵雲日間。',24,'全唐诗/poet.song.29000.json','["偃蹇登脩阪，高侵雲日間。", "幾人征戍客，跋馬望家山。"]'),
('a754d8a0-1c81-409b-9784-0f56c520d237','上郡南三十里有相思亭在太山之麓二水所交平臯之上往來者徒習其名莫詳其義慶曆甲申歳余適延安過於其下于時夏虜梗邊征戍未息竊感東山采薇之義敘其情而愍其勞因作五詩庶幾不違周公之指且以釋亭之名爾  其三','司馬光','宋','宋诗','song-poetry','','[]','塞下春寒在，東風雪滿鬚。',24,'全唐诗/poet.song.29000.json','["塞下春寒在，東風雪滿鬚。", "河陽機上婦，知我苦辛無。"]'),
('d3ffbfe1-cfc2-4925-b912-d34c562076ce','上郡南三十里有相思亭在太山之麓二水所交平臯之上往來者徒習其名莫詳其義慶曆甲申歳余適延安過於其下于時夏虜梗邊征戍未息竊感東山采薇之義敘其情而愍其勞因作五詩庶幾不違周公之指且以釋亭之名爾  其四','司馬光','宋','宋诗','song-poetry','','[]','柳似妖饒舞，花如爛漫粧。',24,'全唐诗/poet.song.29000.json','["柳似妖饒舞，花如爛漫粧。", "那堪隴頭水，嗚咽斷人腸。"]'),
('8b43cf37-cf46-41ba-b8bd-464bb040470d','上郡南三十里有相思亭在太山之麓二水所交平臯之上往來者徒習其名莫詳其義慶曆甲申歳余適延安過於其下于時夏虜梗邊征戍未息竊感東山采薇之義敘其情而愍其勞因作五詩庶幾不違周公之指且以釋亭之名爾  其五','司馬光','宋','宋诗','song-poetry','','[]','空外遊絲轉，飄揚似妾心。',24,'全唐诗/poet.song.29000.json','["空外遊絲轉，飄揚似妾心。", "别來今幾日，彷彿近雕陰。"]'),
('695520d6-f0db-4233-aed4-5564e7ac4c65','梅花  其一','司馬光','宋','宋诗','song-poetry','','[]','從與夫君别，寒花幾度春。',24,'全唐诗/poet.song.29000.json','["從與夫君别，寒花幾度春。", "坐愁芳樹老，況乃鑒中人。"]'),
('14cadc0f-bf96-4708-ba53-58d52c3b143f','梅花  其二','司馬光','宋','宋诗','song-poetry','','[]','塞北爲君戍，江南是妾家。',24,'全唐诗/poet.song.29000.json','["塞北爲君戍，江南是妾家。", "遙知關外雪，只似嶺頭花。"]'),
('e4d9d00c-ff46-4472-ad00-1f22ca05e0d4','梅花  其三','司馬光','宋','宋诗','song-poetry','','[]','驛使何時發，憑君寄一枝。',24,'全唐诗/poet.song.29000.json','["驛使何時發，憑君寄一枝。", "隴頭人不識，空向笛中吹。"]'),
('a9dd6fa8-db75-4587-98bc-027a539f1458','友人楚孟德過余縱言及神仙余謂之無孟德謂之有伊人也非誕妄者蓋有以知之矣然余俗士終疑之故作遊仙曲五章以佐戲笑云  其一','司馬光','宋','宋诗','song-poetry','','[]','神仙謂無還似有，秦漢可憐空白首。',32,'全唐诗/poet.song.29000.json','["神仙謂無還似有，秦漢可憐空白首。", "會須一躡青雲梯，與子同袪千古疑。"]'),
('b54255fb-f76d-48aa-9abf-e59f55785988','友人楚孟德過余縱言及神仙余謂之無孟德謂之有伊人也非誕妄者蓋有以知之矣然余俗士終疑之故作遊仙曲五章以佐戲笑云  其二','司馬光','宋','宋诗','song-poetry','','[]','仙術有無終未知，眼看白髪亂如絲。',32,'全唐诗/poet.song.29000.json','["仙術有無終未知，眼看白髪亂如絲。", "何時得接浮丘袂，滄海横飛萬餘里。"]'),
('007f49c9-6b36-436c-ae71-d9c40d625ba8','友人楚孟德過余縱言及神仙余謂之無孟德謂之有伊人也非誕妄者蓋有以知之矣然余俗士終疑之故作遊仙曲五章以佐戲笑云  其三','司馬光','宋','宋诗','song-poetry','','[]','若士北遊窮地角，還食蛤蜊養龜殻。',32,'全唐诗/poet.song.29000.json','["若士北遊窮地角，還食蛤蜊養龜殻。", "盧敖尸骨不能飛，今朝九垓何處期。"]'),
('eb6de2a0-afd6-4dfb-a51d-8efd531ad653','友人楚孟德過余縱言及神仙余謂之無孟德謂之有伊人也非誕妄者蓋有以知之矣然余俗士終疑之故作遊仙曲五章以佐戲笑云  其四','司馬光','宋','宋诗','song-poetry','','[]','仙家不似人間歡，瑤漿琅菜青玉盤。',32,'全唐诗/poet.song.29000.json','["仙家不似人間歡，瑤漿琅菜青玉盤。", "乘醉東遊憩陽谷，酒瓢閑掛扶桑木。"]'),
('cc22a471-03e3-4144-8704-6615d536de9a','友人楚孟德過余縱言及神仙余謂之無孟德謂之有伊人也非誕妄者蓋有以知之矣然余俗士終疑之故作遊仙曲五章以佐戲笑云  其五','司馬光','宋','宋诗','song-poetry','','[]','柂師知子能操舟，稳過茫茫滄海流。',32,'全唐诗/poet.song.29000.json','["柂師知子能操舟，稳過茫茫滄海流。", "白浪駕天千萬里，真令挂骨長鯨齒。"]'),
('d5d47084-64d0-4c71-bdd4-d0281be8c3be','雲際亭','司馬光','宋','宋诗','song-poetry','','[]','高齊杳冥際，迥與世塵違。',48,'全唐诗/poet.song.29000.json','["高齊杳冥際，迥與世塵違。", "席上山河近，天邊桑柘微。", "人間已飄灑，棟裏始紛霏。", "草樹收殘照，逍遙久未歸。"]'),
('a610174a-9fda-41a6-80bf-84126fbc06a6','和孫器之清風樓','司馬光','宋','宋诗','song-poetry','','[]','賢侯宴枚馬，歌鼓事繁華。',48,'全唐诗/poet.song.29000.json','["賢侯宴枚馬，歌鼓事繁華。", "晚吹來千里，清商落萬家。", "平原轉疏雨，遠樹隔殘霞。", "宋玉雖能賦，還須念景差。"]'),
('4f959e69-e985-418a-a660-64e9c735d785','龍女祠後塘自生荷花數枝與史誠之更相酬和  其一','司馬光','宋','宋诗','song-poetry','','[]','平湖漠漠芰荷稠，水國芳春不勝秋。',32,'全唐诗/poet.song.29000.json','["平湖漠漠芰荷稠，水國芳春不勝秋。", "空有棹歌人不見，晚風一曲去悠悠。"]'),
('8173ff39-a256-420c-a836-1a12c034e93f','龍女祠後塘自生荷花數枝與史誠之更相酬和  其二','司馬光','宋','宋诗','song-poetry','','[]','越女行歌縱棹輕，蒼茫别浦晚煙凝。',32,'全唐诗/poet.song.29000.json','["越女行歌縱棹輕，蒼茫别浦晚煙凝。", "荷花折盡不歸去，瀲灔扁舟不易勝。"]'),
('75c32baf-f1e7-4bec-9fb3-8acdf07aebb9','龍女祠後塘自生荷花數枝與史誠之更相酬和  其三','司馬光','宋','宋诗','song-poetry','','[]','荷底清漣照綺羅，長安公子舊情多。',32,'全唐诗/poet.song.29000.json','["荷底清漣照綺羅，長安公子舊情多。", "躊躇不去知君意，重唱吳音白紵歌。"]'),
('00ea1650-6a28-4841-9ccf-96761896729c','龍女祠後塘自生荷花數枝與史誠之更相酬和  其四','司馬光','宋','宋诗','song-poetry','','[]','賀監家居逸興饒，枝分鑑水闊容舠。',32,'全唐诗/poet.song.29000.json','["賀監家居逸興饒，枝分鑑水闊容舠。", "穿荷宜去邀漁叟，共醉船頭半榼醪。"]'),
('7d79e674-3b7f-40f0-8674-f8d97ec9b370','龍女祠後塘自生荷花數枝與史誠之更相酬和  其五','司馬光','宋','宋诗','song-poetry','','[]','清江向晚採蓮稀，獨倚蘭舟久未歸。',32,'全唐诗/poet.song.29000.json','["清江向晚採蓮稀，獨倚蘭舟久未歸。", "目斷可堪人不至，斜風細雨濕羅衣。"]'),
('a0c93500-c7cc-4cde-8beb-8306fa457841','龍女祠後塘自生荷花數枝與史誠之更相酬和  其六','司馬光','宋','宋诗','song-poetry','','[]','素舸朱篷青竹篙，棹歌風散近還遙。',32,'全唐诗/poet.song.29000.json','["素舸朱篷青竹篙，棹歌風散近還遙。", "斜陽借問歸何處，家住水村郎姓蕭。"]'),
('d73d15aa-729a-47a1-bd0a-5f7cfe24d179','龍女祠後塘自生荷花數枝與史誠之更相酬和  其七','司馬光','宋','宋诗','song-poetry','','[]','别殿無人梨自芳，玉階朱檻繞金塘。',32,'全唐诗/poet.song.29000.json','["别殿無人梨自芳，玉階朱檻繞金塘。", "館娃寂寞無西子，羞與吳宮競曉粧。"]'),
('927b19ef-857f-4edc-9a85-7ca47702721c','贈楚法曹叔度','司馬光','宋','宋诗','song-poetry','','[]','夫君能直節，不恥楊曹輕。',48,'全唐诗/poet.song.29000.json','["夫君能直節，不恥楊曹輕。", "道果因時屈，官無當已榮。", "松杉雖偃蹇，霜霰苦崢嶸。", "會有良工識，終觀大器成。"]'),
('98cfca82-6111-4249-9d60-886b56c1982f','先春亭','司馬光','宋','宋诗','song-poetry','','[]','園林近鈴閣，旦夕被仁風。',48,'全唐诗/poet.song.29000.json','["園林近鈴閣，旦夕被仁風。", "自得芳菲早，豈將疏遠同。", "冰開半塘綠，雨借數枝紅。", "會待韶光徧，還應到野叢。"]'),
('0fc2e31b-6c4d-4b2d-b66a-bc434b4f03ba','寄揚州侯都監','司馬光','宋','宋诗','song-poetry','','[]','木落淮南樹，秋風日夜高。',48,'全唐诗/poet.song.29000.json','["木落淮南樹，秋風日夜高。", "月臨揚子渡，雪捲廣陵濤。", "不得同蕭散，何因破鬰陶。", "空憑尺書速，未解夣魂勞。"]'),
('238da0cb-d5ef-438b-a125-d4d374f066a5','沉陰欲雪與同列會飲南齋','司馬光','宋','宋诗','song-poetry','','[]','簿領日沈迷，從容樂事稀。',48,'全唐诗/poet.song.29000.json','["簿領日沈迷，從容樂事稀。", "賓朋幸相值，樽酒不須違。", "慘澹愁雲積，參差遠樹微。", "淹留勿輕散，待取雪花飛。"]'),
('113a6006-cd07-4e5b-891a-ec6625a2067d','感懷','司馬光','宋','宋诗','song-poetry','','[]','昨日春冰破水邊，今朝臘雪墜風前。',32,'全唐诗/poet.song.29000.json','["昨日春冰破水邊，今朝臘雪墜風前。", "歳華過目疾飛鳥，壯志如何不着鞭。"]'),
('26dff837-8747-42d4-af19-1beb9391396a','之美舉進士寓京師此詩寄之','司馬光','宋','宋诗','song-poetry','','[]','結髪聲華盛，無疑屈未伸。',48,'全唐诗/poet.song.29000.json','["結髪聲華盛，無疑屈未伸。", "何妨久垂翅，從此欲驚人。", "鷹擊天風壯，鵬飛海浪春。", "行當解故褐，不惜化京塵。"]'),
('3421ca32-7e01-48fa-97c0-a1950ec71ca6','風雪數日不見叔度晚約公明共詣之  其一','司馬光','宋','宋诗','song-poetry','','[]','雲雪連朝闇，朋從歎坐違。',48,'全唐诗/poet.song.29000.json','["雲雪連朝闇，朋從歎坐違。", "臨文與誰共，開卷爲君稀。", "趣掃六花散，聊通一徑微。", "當攜兔園賦，同映讀書幃。"]'),
('babb1930-7a11-47ce-918b-66fe5135f5ea','風雪數日不見叔度晚約公明共詣之  其二','司馬光','宋','宋诗','song-poetry','','[]','南榮卮酒罷，君返道東居。',48,'全唐诗/poet.song.29000.json','["南榮卮酒罷，君返道東居。", "坐作三朝别，杳疑千里餘。", "閑門嗟雀網，深濘怯柴車。", "向晚開簾喜，彤雲稍覺疏。"]'),
('74d3ab1b-c6f1-43a6-be71-1f62ddfee716','贈吳之才','司馬光','宋','宋诗','song-poetry','','[]','勝冠自立艱難裏，大器由來貴晚成。',64,'全唐诗/poet.song.29000.json','["勝冠自立艱難裏，大器由來貴晚成。", "松柏儻非生磊落，巖崖何易出崢嶸。", "蘇秦遊困羞妻嫂，主父居貧厭弟兄。", "六印佗年擁車騎，會須重過洛陽城。"]'),
('05915072-c34d-4422-adc9-764a96391b01','寒食許昌道中寄幕府諸君','司馬光','宋','宋诗','song-poetry','','[]','原上煙蕪淡復濃，寂寥佳節思無窮。',64,'全唐诗/poet.song.29000.json','["原上煙蕪淡復濃，寂寥佳節思無窮。", "竹林近水半邊綠，桃樹連村一片紅。", "盡日解鞍山店雨，晚天回首酒旗風。", "遙知幕府清明飲，應笑驅馳羈旅中。"]'),
('a2a6b3cc-f2ea-4436-b472-51b1a0318361','和叔度獨登天臺水亭','司馬光','宋','宋诗','song-poetry','','[]','郊外靈潭闊，新亭占曲堤。',72,'全唐诗/poet.song.29000.json','["郊外靈潭闊，新亭占曲堤。", "戲魚迎墜絮，驚雉出荒蹊。", "綠倒楊梢亂，光飜芰葉齊。", "雨餘纖月偃，野迥斷雲低。", "水氣常噴薄，天風助慘悽。", "何知塵外境，近在郡樓西。"]'),
('bffbb4a1-7623-466b-b9ef-c1151c5597c2','五哀詩 屈平','司馬光','宋','宋诗','song-poetry','','[]','白玉徒爲潔，幽蘭未謂芳。',48,'全唐诗/poet.song.29000.json','["白玉徒爲潔，幽蘭未謂芳。", "窮羞事令尹，疏不忘懷王。", "冤骨消寒渚，忠魂失舊鄉。", "空餘楚辭在，猶與日爭光。"]'),
('408f6ed2-eb2c-4cf6-8f81-3a1801348d46','五哀詩 李牧','司馬光','宋','宋诗','song-poetry','','[]','椎牛饗壯士，拔距養奇材。',48,'全唐诗/poet.song.29000.json','["椎牛饗壯士，拔距養奇材。", "虜帳方驚避，秦金已闇來。", "旌旗移幕府，荆棘蔓叢臺。", "部曲依稀在，猶能話郭開。"]'),
('3f3cea74-6b6b-45c4-8452-3bfd12386418','五哀詩 晁大夫','司馬光','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','人主恩猶盛，讒夫弄舌端。',48,'全唐诗/poet.song.29000.json','["人主恩猶盛，讒夫弄舌端。", "旋聞就斧質，不得解衣冠。", "反賊齒纔冷，謀臣心盡寒。", "晁宗噍類盡，漢室泰山安。"]'),
('2ef1e3e5-4793-4720-8ca6-7fd3aa07ddb5','五哀詩 馬伏波','司馬光','宋','宋诗','song-poetry','','[]','漢令班南海，蠻兵避鬰林。',48,'全唐诗/poet.song.29000.json','["漢令班南海，蠻兵避鬰林。", "天涯柱分界，徼外貢輸金。", "坐失奸臣意，誰明報國心。", "一棺忠勇骨，漂泊瘴煙深。"]'),
('9320a56d-facd-41fc-83bf-c3d17e5ded2b','五哀詩 斛律丞相','司馬光','宋','宋诗','song-poetry','','[]','君臣日荒宴，歌舞諱言愁。',48,'全唐诗/poet.song.29000.json','["君臣日荒宴，歌舞諱言愁。", "老相猶當國，強鄰不敢謀。", "謠言雖未出，奸謗已先流。", "誰察忠臣意，通宵抱膝憂。"]'),
('d2bfe3e5-7dc0-4145-a6f1-c668edad81e8','留别東郡諸僚友  其一','司馬光','宋','宋诗','song-poetry','','[]','際日浮空漲海流，蟲沙龍蜃各優游。',32,'全唐诗/poet.song.29000.json','["際日浮空漲海流，蟲沙龍蜃各優游。", "津涯浩蕩雖難測，不見驚瀾曾覆舟。"]'),
('664c4784-4d74-45ab-b494-a88ae5d55c42','留别東郡諸僚友  其二','司馬光','宋','宋诗','song-poetry','','[]','白璧紫金爲世寶，賢愚知貴莫能名。',32,'全唐诗/poet.song.29000.json','["白璧紫金爲世寶，賢愚知貴莫能名。", "廟堂祭器杯盤物，隨處得之光彩生。"]'),
('f6356d2a-9a60-4117-ace5-0dee0137eff6','留别東郡諸僚友  其三','司馬光','宋','宋诗','song-poetry','','[]','楚國良金百鍊精，深藏求售價連城。',32,'全唐诗/poet.song.29000.json','["楚國良金百鍊精，深藏求售價連城。", "豈徒豐獄吹毛利，兼有秦臺照膽明。"]'),
('1465d8ae-7426-4cb5-97ef-58c516f586b3','留别東郡諸僚友  其四','司馬光','宋','宋诗','song-poetry','','[]','祖帳飄揚堤柳邊，北來飛蓋復連翩。',32,'全唐诗/poet.song.29000.json','["祖帳飄揚堤柳邊，北來飛蓋復連翩。", "追隨不忍輕言别，逥首城樓沒晚烟。"]'),
('6b14e0ae-5263-4053-a4e6-7c24cf398029','留别東郡諸僚友  其五','司馬光','宋','宋诗','song-poetry','','[]','空府同來賢大夫，短亭門外即長塗。',32,'全唐诗/poet.song.29000.json','["空府同來賢大夫，短亭門外即長塗。", "不辭爛醉樽前倒，明日此歡重得無。"]'),
('a17cf4ae-b138-4c73-a979-1c705b93d568','遣興','司馬光','宋','宋诗','song-poetry','','[]','京洛紅塵裏，閉門常獨居。',72,'全唐诗/poet.song.29000.json','["京洛紅塵裏，閉門常獨居。", "雖無守道愧，終與趣時疏。", "文舉徒飛表，曹丘懶挾書。", "誰憐從宦久，不及策名初。", "待兔謀真拙，屠龍藝亦虚。", "何當治歸計，松菊繞吾廬。"]'),
('f37311ca-0fe6-4060-80a2-bdab9033d53d','閽吏','司馬光','宋','宋诗','song-poetry','','[]','弊車羸馬犯塵泥，愁到朱門徧徧辭。',64,'全唐诗/poet.song.29000.json','["弊車羸馬犯塵泥，愁到朱門徧徧辭。", "相國舍人難驟見，將軍馬監豈相知。", "因循歲月勞何補，顛倒風埃辱固宜。", "惆悵東岡舊陂在，素心空負白雲期。"]'),
('34f731f2-7f67-49e0-b20d-c2c386cce628','追和張學士從沂公遊廣固城','司馬光','宋','宋诗','song-poetry','','[]','蒼鵝集宋幕，遊鹿上燕臺。',72,'全唐诗/poet.song.29000.json','["蒼鵝集宋幕，遊鹿上燕臺。", "霸氣山河盡，王師江漢來。", "重圍經歲合，嚴鎻夜深開。", "廢殿餘沙礫，頽牆蘙草萊。", "清時間千歲，良牧借三台。", "獄市乘餘暇，蕪城賦上才。"]'),
('55b83953-0a48-41f3-862f-4312a34e83f0','去歲與東郡幕府諸君同遊河亭望太行雪飲酒賦詩今冬罷歸京邑悵然有懷','司馬光','宋','宋诗','song-poetry','','[]','疇昔追清景，狂吟忘苦寒。',72,'全唐诗/poet.song.29000.json','["疇昔追清景，狂吟忘苦寒。", "河冰塞津口，山雪照林端。", "健筆千篇冨，醇醪一醉歡。", "困猶揮落麈，瞑不顧歸鞍。", "多是光陰駛，離羣會合難。", "誰知塵滿袖，今日客長安。"]'),
('5674a07a-2da5-4f2c-9fe4-a0f4e70eafd8','哭馬承之','司馬光','宋','宋诗','song-poetry','','[]','平生千里别，書問亦常来。',48,'全唐诗/poet.song.29000.json','["平生千里别，書問亦常来。", "隼拂秋雲擊，鸞兼霏霧迴。", "曏無高世藝，安見出倫才。", "有紙盈箱箧，扃封不忍開。"]'),
('6a660d4e-9383-4970-ba15-c9d6c456ce53','山家','司馬光','宋','宋诗','song-poetry','','[]','林下脫雙履，窗邊掛幅巾。',24,'全唐诗/poet.song.29000.json','["林下脫雙履，窗邊掛幅巾。", "閑堂風掩戶，斷嶺月窺人。"]'),
('d61cf261-5bc1-4ea3-8f5c-26f266ea29a7','風','司馬光','宋','宋诗','song-poetry','','[]','隴首紅旌急，罇前翠幕重。',48,'全唐诗/poet.song.29000.json','["隴首紅旌急，罇前翠幕重。", "林端翻遠剎，花外轉疏鐘。", "夜寂清機發，春闌别意濃。", "如何玉琴韻，併欲在青松。"]'),
('4eace656-f4dc-43c3-af1b-ccce03631e1b','送王殿丞知眉山縣  其一','司馬光','宋','宋诗','song-poetry','','[]','疇昔侍嚴親，俱爲綵服人。',48,'全唐诗/poet.song.29000.json','["疇昔侍嚴親，俱爲綵服人。", "遊蘭已多益，得桂復同春。", "風樹悲歡異，萍波聚散頻。", "峽中盡遺事，何處不霑巾。"]'),
('a3809040-2098-44a3-ae9c-aed46ac29a2b','送王殿丞知眉山縣  其二','司馬光','宋','宋诗','song-poetry','','[]','君行杳何許，萬里蜀雲西。',48,'全唐诗/poet.song.29000.json','["君行杳何許，萬里蜀雲西。", "野色春期近，林煙曉意迷。", "天藏巴峽小，星逼劍關低。", "莫使鄉愁亂，咬咬信子規。"]'),
('3a462c87-2644-457d-be59-504cc167f754','送朱校理知濰州','司馬光','宋','宋诗','song-poetry','','[]','東國連年水傷稼，使君到部即行春。',64,'全唐诗/poet.song.29000.json','["東國連年水傷稼，使君到部即行春。", "茫茫四野潢汙竭，欝欝萬行桑柘新。", "俗不好奢田器貴，獄無留繫吏家貧。", "齊人忽怨歸朝速，自是承明侍從臣。"]'),
('de06e036-d051-4c2d-8ed5-170e6edb14d8','貢院中戲從元禮求酒','司馬光','宋','宋诗','song-poetry','','[]','顧我虛罍恥，知君餘瀝多。',24,'全唐诗/poet.song.29000.json','["顧我虛罍恥，知君餘瀝多。", "庭前有春雪，如此薄寒何。"]'),
('c3f3793b-ed1f-4018-8148-f0e35aa2d917','黄甘','司馬光','宋','宋诗','song-poetry','','[]','黄金綴縹蒂，搖落楚江涯。',48,'全唐诗/poet.song.29000.json','["黄金綴縹蒂，搖落楚江涯。", "采助杯盤勝，羞將橘柚偕。", "時移香不變，物遠味尤佳。", "欲種滄洲樹，何年此意諧。"]'),
('2bcf563b-a34e-4b4b-9911-93fc5a2ce5e0','寒食南宮夜飲','司馬光','宋','宋诗','song-poetry','','[]','積旬留省署，容易度春華。',48,'全唐诗/poet.song.29000.json','["積旬留省署，容易度春華。", "芳草踏青晚，長楸行樂賖。", "雲疏時送雨，風細暗飛花。", "直有黄金百，無因過酒家。"]'),
('04d1d174-e3c2-42d4-8084-3a76c5e7250b','送孟著作知濟陰','司馬光','宋','宋诗','song-poetry','','[]','聖主焦勞意，誰云百里輕。',72,'全唐诗/poet.song.29000.json','["聖主焦勞意，誰云百里輕。", "東州比災害，劇令選精明。", "水去良田闊，人歸旅糓生。", "閭閻還舊觀，鷄犬變新聲。", "盗散疲民活，姦窮老吏驚。", "政成知不日，雙耳爲君傾。"]'),
('ac7a5f9f-c12b-4b90-a0ad-e2badb5e3ab6','同宋次道陪讌瓊林','司馬光','宋','宋诗','song-poetry','','[]','冠蓋連翩數里塵，帝家全借上林春。',64,'全唐诗/poet.song.29000.json','["冠蓋連翩數里塵，帝家全借上林春。", "鵷行不動煙霞秀，龍角正高雷雨新。", "喜氣晴曛宮樹綠，飛花醉墮玉巵頻。", "蒲萄盧橘應相識，半是當年舉酒人。"]'),
('bf1fd379-950b-4e6b-b2d4-c0d1027580fd','送馮狀元歸鄂州','司馬光','宋','宋诗','song-poetry','','[]','夙昔負奇節，琅然爲衆殊。',48,'全唐诗/poet.song.29000.json','["夙昔負奇節，琅然爲衆殊。", "下韝連得儁，出手盡成盧。", "喜氣兼鄰曲，榮名溢道塗。", "風雲俱動色，非復舊江湖。"]'),
('e5d6e569-fc06-47f3-9505-f4441ec56696','送吳耿先生','司馬光','宋','宋诗','song-poetry','','[]','儒服若煙海，幾人潛聖心。',144,'全唐诗/poet.song.29000.json','["儒服若煙海，幾人潛聖心。", "難才成自昔，賤學况于今。", "夫子獨神解，明時何陸沉。", "大羮無和味，至樂寡知音。", "磳磴貂裘弊，飄蕭鶴髮侵。", "遊秦不得意，思越動長吟。", "甑米難求玉，經囊益少金。", "拂衣謝賓友，縱棹指雲岑。", "積葉迷幽逕，荒藤絡舊林。", "澗猿驚重至，野老喜相尋。", "山色猶當戶，絃聲不變琴。", "人生貴適意，何必慕華簪。"]'),
('412cacec-b9f3-4c13-b121-dd153b39de45','送高陟歸金陵','司馬光','宋','宋诗','song-poetry','','[]','之子秣陵去，悠悠天塹東。',72,'全唐诗/poet.song.29000.json','["之子秣陵去，悠悠天塹東。", "帆開曉風疾，潮落夜江空。", "在昔才華盛，至今人物豐。", "山川氣雖盡，龍虎勢猶雄。", "卞玉已三獻，齊禽會一冲。", "當令關下吏，洗目認終童。"]'),
('5cf50eab-be8d-470a-b2cd-135aa62c4eda','子高有徐浩詩碑昌言借摹其文甫及數本石有微釁懼而歸之子高答簡有碎珊瑚之戲昌言以詩贈子高同舍皆和','司馬光','宋','宋诗','song-poetry','','[]','徐公精筆老生神，石刻猶能妙奪真。',64,'全唐诗/poet.song.29000.json','["徐公精筆老生神，石刻猶能妙奪真。", "幾爲通書翻喪寶，愈令好事惜傳人。", "鋒鋩半折猶能健，圭璧微瑕自足珍。", "直使盡隨如意碎，石家玉樹未全貧。"]'),
('ff8c9915-0c7d-4483-ad7d-886ce12e95d1','京送僧聰歸蜀','司馬光','宋','宋诗','song-poetry','','[]','翠柏老精舍，紅塵倦帝城。',48,'全唐诗/poet.song.29000.json','["翠柏老精舍，紅塵倦帝城。", "千山一錫遠，萬里片雲輕。", "江棧紆還直，天星縱復横。", "聽猿應更喜，還是故鄉聲。"]'),
('92b28dd7-e30d-445c-9639-6df95520b381','送史館任祠部河東轉運使','司馬光','宋','宋诗','song-poetry','','[]','問望簪紳舊，恩華雨露重。',48,'全唐诗/poet.song.29000.json','["問望簪紳舊，恩華雨露重。", "圖書周內史，汾澮晉全封。", "秀發千尋壁，寒生百鍊鋒。", "歸時門有戟，惜别更從容。"]'),
('85d511a3-9710-4310-ab90-b573866941f6','送冲卿通判河中府','司馬光','宋','宋诗','song-poetry','','[]','聞道名都行有期，依然想見昔遊時。',64,'全唐诗/poet.song.29000.json','["聞道名都行有期，依然想見昔遊時。", "寒光一曲秋河轉，翠嶺三條夕照移。", "孤竹舊風民有讓，重華餘教俗無疵。", "不須到日方登歷，已在君家十二詩。"]'),
('0383beea-eaee-447a-b625-fccb2c962999','故翰林彭學士挽歌  其一','司馬光','宋','宋诗','song-poetry','','[]','夙昔遊清貫，時流籍重名。',48,'全唐诗/poet.song.29000.json','["夙昔遊清貫，時流籍重名。", "讐書石渠秘，視草玉堂榮。", "吉兆虚三鱓，凶期告兩楹。", "子雲思故國，墳樹必西傾。"]'),
('ef8677e1-cf4a-4d0f-820e-e9066896573d','故翰林彭學士挽歌  其二','司馬光','宋','宋诗','song-poetry','','[]','平生對交舊，萬日正如初。',48,'全唐诗/poet.song.29000.json','["平生對交舊，萬日正如初。", "不復知榮賤，都能忘戚疏。", "遺靈瞻素几，僞物屏塗車。", "家事何蕭索，空餘萬卷書。"]'),
('5f55d857-51b7-4abf-a57f-060bed4d5897','故翰林彭學士挽歌  其三','司馬光','宋','宋诗','song-poetry','','[]','祖奠垂將撤，笳簫儼欲行。',48,'全唐诗/poet.song.29000.json','["祖奠垂將撤，笳簫儼欲行。", "野寒嘶故馬，樹轉出新旌。", "泉路幽無底，魚燈曖不明。", "如何齎美志，鬰鬰向佳城。"]'),
('9e45d632-fd0a-4497-bc5a-5bbac178419d','景福東廂詩 夜意','司馬光','宋','宋诗','song-poetry','','[]','清夜四無譁，深嚴上帝家。',48,'全唐诗/poet.song.29000.json','["清夜四無譁，深嚴上帝家。", "星翻珠網白，斗挂玉樓斜。", "風静虚成韻，霜輕未作花。", "還疑漢津客，浩蕩寄流槎。"]'),
('fb4c394a-6d85-4fbc-a641-95b7ddc7b672','景福東廂詩 即日','司馬光','宋','宋诗','song-poetry','','[]','枍栺留深殿，倉琅秘九門。',48,'全唐诗/poet.song.29000.json','["枍栺留深殿，倉琅秘九門。", "日長人對直，風迥鷰高翻。", "林有蕭疏意，雲無片縷痕。", "鈞天真自到，不獨暫飛魂。"]'),
('d287cd50-4c74-44bb-bab5-0cde237a12de','景福東廂詩 柏','司馬光','宋','宋诗','song-poetry','','[]','落落抱高節，秀出青雲端。',48,'全唐诗/poet.song.29000.json','["落落抱高節，秀出青雲端。", "無言磵谷幽，自致宮庭難。", "芳風襲玉宇，餘露分銅槃。", "不使萬年木，嘉名高歳寒。"]'),
('17b63df5-334f-4fb6-8ebf-434c21b58ad6','御溝','司馬光','宋','宋诗','song-poetry','','[]','萬戶鬰相鉤，枝分瑟瑟流。',48,'全唐诗/poet.song.29000.json','["萬戶鬰相鉤，枝分瑟瑟流。", "縈紆通桂觀，隱見带龍樓。", "碧映千林曙，紅飄一葉秋。", "寒波長不竭，歳歳奉宸遊。"]'),
('f6f1a2fa-b41c-4064-9285-0c6dce02d35e','御溝 賜酒','司馬光','宋','宋诗','song-poetry','','[]','和氣盈金榼，恩光湛玉觴。',48,'全唐诗/poet.song.29000.json','["和氣盈金榼，恩光湛玉觴。", "應知北山羽，猶怯上林霜。", "醇味回秋色，清都近醉鄉。", "山茅霑雨露，誓極寸心長。"]'),
('b941ba77-9a17-48be-8d35-6efa2fe156a2','御溝 菊','司馬光','宋','宋诗','song-poetry','','[]','瑣瑣南陽菊，秋潭歳自開。',48,'全唐诗/poet.song.29000.json','["瑣瑣南陽菊，秋潭歳自開。", "孤根擁紅葉，落蘂媚蒼苔。", "正以參靈藥，因之植紫臺。", "願兼金掌露，同入柏梁杯。"]'),
('d86cca18-82ee-4462-973b-3f67a179566c','御溝 同范景仁寄修書諸同舍','司馬光','宋','宋诗','song-poetry','','[]','烈火非不猛，不耗百鍊金。',96,'全唐诗/poet.song.29000.json','["烈火非不猛，不耗百鍊金。", "寒霜非不嚴，不彫竹柏林。", "小人勢利合，傾覆無常心。", "君子道德親，白首猶視今。", "諸君閨臺秀，相得如璆琳。", "離羣一昔期，乃爾動悲吟。", "古風久已衰，交道日頹侵。", "願名思友操，播之清徽琴。"]'),
('3da904f1-ac02-4c0d-8025-e0a35673d54a','御溝 賜果','司馬光','宋','宋诗','song-poetry','','[]','南海荔枝來，别館蒲萄成。',48,'全唐诗/poet.song.29000.json','["南海荔枝來，别館蒲萄成。", "匪頒浹下陳，捧拜同驩榮。", "置黍敢先食，覽槃多未名。", "懷核待歸種，復愁千歳生。"]'),
('67f052c2-ec4b-4a95-85a0-d58e5aae4abd','御溝 賜書','司馬光','宋','宋诗','song-poetry','','[]','上聖固天縱，英藝皆絕倫。',180,'全唐诗/poet.song.29000.json','["上聖固天縱，英藝皆絕倫。", "時乘萬幾閑，翰動如有神。", "用之當豫遊，不忘安四民。", "匪頒及羣下，絡繹來中宸。", "毰毸靈鳯翔，鬰怒虬龍振。", "清若四海秋，熙如天下春。", "愚臣土芥微，亦受雨露均。", "願推賜書意，直以古義陳。", "士本學先王，所求誼與仁。", "農當服稼穯，昏作甽畝勤。", "百工備用器，不治刺繡文。", "萬商遷有無，不通珠翠珍。", "四業既交修，坐令風化純。", "人和衣食豐，天應殊祥臻。", "皇心正在此，非以能高人。"]'),
('b7df270d-af14-4ea3-b534-e9ecbdc41f4e','御溝 怪石','司馬光','宋','宋诗','song-poetry','','[]','昔去江湖鄉，來與松桂接。',48,'全唐诗/poet.song.29000.json','["昔去江湖鄉，來與松桂接。", "圭角老龍脊，鋒稜秋劍鋏。", "歷亂枯苔點，交横敗莎葉。", "會使成都人，更取神蓍揲。"]'),
('71c0c55b-4e56-47b9-ad52-46401e861354','御溝 未開木芙蓉','司馬光','宋','宋诗','song-poetry','','[]','木末采芙蓉，騷人歌所無。',48,'全唐诗/poet.song.29000.json','["木末采芙蓉，騷人歌所無。", "何言霜花艷，不與水芝殊。", "香苞麝臍結，茂葉桐陰敷。", "豈若龜巢類，飄零老五湖。"]'),
('2f72c7e8-8246-4439-934a-e149397c440f','御溝 讀武士策','司馬光','宋','宋诗','song-poetry','','[]','漢家求猛士，雲集未央宮。',48,'全唐诗/poet.song.29000.json','["漢家求猛士，雲集未央宮。", "天外朝星淡，山西將種空。", "奇謀紛並進，壯節凜生風。", "八陣縱横勢，依然見目中。"]'),
('ebf9a193-05bc-4fed-b456-2b96cf136755','御溝 觀試騎射','司馬光','宋','宋诗','song-poetry','','[]','閶闔風正清，觚稜日初媚。',168,'全唐诗/poet.song.29000.json','["閶闔風正清，觚稜日初媚。", "材雄集便殿，玉座親臨視。", "三河俠少兒，初識天子貴。", "天山汗血騮，蹀躞金鐶轡。", "揚鞭秋雲高，顧盼有餘銳。", "縈回勢可觀，罄控動如志。", "毫釐應心目，審固參身臂。", "鳴絃電雹驚，寸的冰瓦碎。", "龍顔薄笑春，喜色連傍侍。", "旦爲徒步人，暮作彯纓使。", "揚揚出九門，親友生意氣。", "須知天地德，慎勿忘所自。", "黠羌猶旅拒，獫狁方繁熾。", "求爲忠義臣，無負搜羅意。"]'),
('2e12b6d9-8cc1-4ed8-ae68-2cbc1d751dcb','喜景仁直秘閣','司馬光','宋','宋诗','song-poetry','','[]','延閣屹中天，積書雲漢連。',120,'全唐诗/poet.song.29000.json','["延閣屹中天，積書雲漢連。", "神宗重其選，國士此爲偏。", "夫子岷嶓秀，聲名俊造先。", "清標峻不極，勝氣駛無前。", "待價猶懷璧，臨岐肯著鞭。", "介推不求顯，張季久方遷。", "玉檻鉤陳上，丹梯北斗邊。", "帝容瞻日角，宸翰照星躔。", "職秩曾無貴，光華在得賢。", "公卿殊未晚，尚少買臣年。"]'),
('892cd5cc-9223-4983-adff-7d19fbdd76bc','興宗許菊久之未得','司馬光','宋','宋诗','song-poetry','','[]','菊栽許送定如何，庭下不堪秋草多。',32,'全唐诗/poet.song.29000.json','["菊栽許送定如何，庭下不堪秋草多。", "九日無花更無酒，便攜藜杖直相過。"]'),
('018fe853-f5c8-4532-839c-5bbd20a5084d','得菊并詩','司馬光','宋','宋诗','song-poetry','','[]','黄花小墢和煙斸，野興蕭蕭已相逐。',32,'全唐诗/poet.song.29000.json','["黄花小墢和煙斸，野興蕭蕭已相逐。", "同來更得兼詩句，久立看詩忘栽菊。"]'),
('acecd402-e950-4735-b372-30cb9e3907ac','送史館唐祠部江南西路轉運使','司馬光','宋','宋诗','song-poetry','','[]','豪傑爭唐鹿，江南號富強。',96,'全唐诗/poet.song.29000.json','["豪傑爭唐鹿，江南號富強。", "明時雖混一，餘俗尚彫傷。", "税版誅求急，詞曹牒訴忙。", "皇心愍頽弊，使節付才良。", "貧吏先投紱，姦民盡越鄉。", "閭閻無插筆，田畝有棲糧。", "漢閣歸期闊，隋河去驛長。", "風高片帆疾，鉦鼓入秋光。"]'),
('2eec088d-0faf-4a96-bf24-490815b88b38','送張寺丞知富順監','司馬光','宋','宋诗','song-poetry','','["\u52c9\u52b1", "\u53cb\u4eba", "\u9001\u522b"]','漢家五尺道，置吏撫南夷。',48,'全唐诗/poet.song.29000.json','["漢家五尺道，置吏撫南夷。", "欲使文翁教，兼令孟獲知。", "盤羞蒟醬實，歌雜竹枝辭。", "取酒須勤醉，鄉關不可思。"]'),
('6f09503c-c87d-4af1-b6ea-8d1bfd3b609b','寄題李舍人蒲中新齋','司馬光','宋','宋诗','song-poetry','','[]','隴上家聲勇氣殊，邊庭卧鼓欲安居。',64,'全唐诗/poet.song.29000.json','["隴上家聲勇氣殊，邊庭卧鼓欲安居。", "非同王翦私求宅，更似甘寧晚好書。", "劍倚寒窗風淅瀝，門無雜客柳蕭疏。", "蒲州風土平生愛，爲問旁鄰地有餘。"]'),
('26f0af6a-f51e-4201-8827-40eac6fac7c3','贈太子太傅康靖李公挽歌詞二首  其一','司馬光','宋','宋诗','song-poetry','','[]','黄髪今彫喪，蒼生欲奈何。',48,'全唐诗/poet.song.29000.json','["黄髪今彫喪，蒼生欲奈何。", "散金纔極樂，曳杖已成歌。", "十郡餘恩在，三臺故吏多。", "位崇仍有後，五福更爲多。"]'),
('34207fa3-06e9-40ee-9838-11bca6fd7274','贈太子太傅康靖李公挽歌詞二首  其二','司馬光','宋','宋诗','song-poetry','','[]','鹵簿去悠悠，西郊亂葉秋。',48,'全唐诗/poet.song.29000.json','["鹵簿去悠悠，西郊亂葉秋。", "旐翻寒日薄，笳咽斷雲愁。", "吊客門飛鶴，佳城山卧牛。", "靈車今不返，洧水日東流。"]'),
('a1e12e66-7160-4cc7-8677-6cdea4b13527','送二同年使北 呂濟叔','司馬光','宋','宋诗','song-poetry','','[]','華纓下玉除，天子寵匈奴。',48,'全唐诗/poet.song.29000.json','["華纓下玉除，天子寵匈奴。", "雖復夷風陋，猶知漢使殊。", "夜烽沈不舉，秋柝寂無虞。", "何必燕然刻，蒼生肝腦塗。"]'),
('0573e90e-8d05-44c4-b0db-378b3f43f64b','送二同年使北 李公素','司馬光','宋','宋诗','song-poetry','','[]','雲愁雪欲零，四牡出郊坰。',48,'全唐诗/poet.song.29000.json','["雲愁雪欲零，四牡出郊坰。", "古塞煙華紫，寒沙日氣青。", "金門秘雞樹，朱節燿龍庭。", "幾夜天街北，遙占漢使星。"]'),
('c0e7f497-ade3-4b4c-86fe-3ef87594f777','昌言有詠石髪詩三章模寫精楷殆難復加僕雖未睹兹物而已若識之久者輒復強爲三詩以繼其後非敢庶幾肩差適足爲前詩之輿臺耳  其一','司馬光','宋','宋诗','song-poetry','','[]','萬古風濤浸石巖，老苔垂足細䰐鬖。',32,'全唐诗/poet.song.29000.json','["萬古風濤浸石巖，老苔垂足細䰐鬖。", "傳聞海底珠無數，何事從來散不簪。"]'),
('0baf0db0-74a9-4c2b-b946-627da9b35461','昌言有詠石髪詩三章模寫精楷殆難復加僕雖未睹兹物而已若識之久者輒復強爲三詩以繼其後非敢庶幾肩差適足爲前詩之輿臺耳  其二','司馬光','宋','宋诗','song-poetry','','[]','金闕銀城仙客居，欲傳消息問麻姑。',32,'全唐诗/poet.song.29000.json','["金闕銀城仙客居，欲傳消息問麻姑。", "蓬萊無物堪爲信，剪寄蒼龍一握鬚。"]'),
('13d8ed21-f899-4263-8ff8-8bd104c47d54','昌言有詠石髪詩三章模寫精楷殆難復加僕雖未睹兹物而已若識之久者輒復強爲三詩以繼其後非敢庶幾肩差適足爲前詩之輿臺耳  其三','司馬光','宋','宋诗','song-poetry','','[]','琅菜來從若木邊，非膏非沐綠宛延。',32,'全唐诗/poet.song.29000.json','["琅菜來從若木邊，非膏非沐綠宛延。", "玉盤委積羞佳客，不是陶家無饌錢。"]'),
('7426d146-85d7-4464-827a-5ba2a8fba230','送沈寺丞知南昌縣','司馬光','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江湛湛带楓林，古木寒雲縣寺深。',64,'全唐诗/poet.song.29000.json','["長江湛湛带楓林，古木寒雲縣寺深。", "老吏不能容狡獪，細民無復有冤侵。", "洪崖丹井聞猶在，徐孺衡門說可尋。", "寧復淹留如寶劍，更令牛斗氣沈沈。"]'),
('4dd9911b-c716-4dea-977b-d94861fc32f4','酬不疑雪中書懷見寄','司馬光','宋','宋诗','song-poetry','','[]','直道免三黜，敢云羞小官。',48,'全唐诗/poet.song.29000.json','["直道免三黜，敢云羞小官。", "盤餐紅粟澀，衣桁黑貂寒。", "畫府容身易，侯門曲意難。", "荆扉盈尺雪，有客問袁安。"]'),
('968207c0-9391-4f6b-a923-9885ed258dc3','答師道對雪見寄','司馬光','宋','宋诗','song-poetry','','[]','陰風一夕驚，曉雪滿都城。',120,'全唐诗/poet.song.29000.json','["陰風一夕驚，曉雪滿都城。", "氣覆千家白，光連萬象清。", "戀空飛不下，弄態舞相縈。", "歷亂看無定，飄颻轉未成。", "綴垣時缺剝，壓竹乍欹傾。", "細隙過無滯，寒窗拂有聲。", "園林勻結練，觀閣巧彫瓊。", "草木情先喜，乾坤意亦榮。", "營魂頓疏健，病目暫虚明。", "郢曲高誰和，羞將叩缶并。"]'),
('22406d80-058f-479f-abc1-7d438fcf60fc','送王校理守瑯琊','司馬光','宋','宋诗','song-poetry','','[]','金門倦鳴玉，千騎出東方。',48,'全唐诗/poet.song.29000.json','["金門倦鳴玉，千騎出東方。", "封略依滄海，枌榆近故鄉。", "秦碑苔蝕字，鄅稻日翻芒。", "國吏遙應識，當年丞相郎。"]'),
('1a698c7a-8bec-4888-8630-0e15c99c3ffa','哭尚潁','司馬光','宋','宋诗','song-poetry','','[]','操業五常備，艱難六極全。',48,'全唐诗/poet.song.29000.json','["操業五常備，艱難六極全。", "仲尼難語命，禆竈不知天。", "弱女飄何許，遺文散莫傳。", "官輕史不錄，後世孰稱賢。"]'),
('7fce36d8-1a78-4912-9d21-d63731532891','故侍讀學士張公哀辭二首  其一','司馬光','宋','宋诗','song-poetry','','[]','喜慍與榮枯，居之悉晏如。',48,'全唐诗/poet.song.29000.json','["喜慍與榮枯，居之悉晏如。", "稍門多執筆，至老不抛書。", "常愧無能極，曾霑清論餘。", "秋風郭門外，雨泣望喪車。"]'),
('ae346d99-b959-4a9c-b4a7-cd5b9e0543fc','故侍讀學士張公哀辭二首  其二','司馬光','宋','宋诗','song-poetry','','[]','凶夢歌洹水，妖巢集戴鵀。',48,'全唐诗/poet.song.29000.json','["凶夢歌洹水，妖巢集戴鵀。", "未嘗餘俸祿，無以具衣衾。", "袁渙分倉穀，翁歸賜府金。", "佗年純固傳，寧使令名沈。"]'),
('48287c4b-ad82-4235-a08f-b65eef5771f6','錢子高挽歌二首  其一','司馬光','宋','宋诗','song-poetry','','[]','煒燁傳家學，連翩射策榮。',48,'全唐诗/poet.song.29000.json','["煒燁傳家學，連翩射策榮。", "走丸過省閣，破竹取公卿。", "埋玉嗟何早，爲山惜未成。", "空令澤宮友，相顧淚縱横。"]'),
('b48f99fe-355f-4339-ad8b-a354b6c166ae','錢子高挽歌二首  其二','司馬光','宋','宋诗','song-poetry','','[]','象設如平昔，升堂不見君。',48,'全唐诗/poet.song.29000.json','["象設如平昔，升堂不見君。", "尚疑言笑在，忽念死生分。", "清論千秋雪，浮榮一片雲。", "泉臺多少路，何處復修文。"]'),
('7ddc7fda-ccf2-4905-a8c3-ed348e9201ba','題楊中正供奉洗心堂','司馬光','宋','宋诗','song-poetry','','[]','閥閱盛山西，朱門颺戟衣。',48,'全唐诗/poet.song.29000.json','["閥閱盛山西，朱門颺戟衣。", "雅知名教樂，深笑宴遊非。", "一室琴書隘，三年園圃稀。", "異時論事業，肯復讓輕肥。"]'),
('aa9f74dd-0eda-4d03-84e1-80ec842f31a5','送龔章判官之衞州','司馬光','宋','宋诗','song-poetry','','["\u52c9\u52b1", "\u9001\u522b", "\u53cb\u60c5", "\u5fc6\u65e7"]','几硯昔年遊，於今成十秋。',48,'全唐诗/poet.song.29000.json','["几硯昔年遊，於今成十秋。", "松堅終發石，魚變即辭流。", "近郡無飛檄，清時不借籌。", "淇園春竹美，軍宴日椎牛。"]'),
('dee4f5ee-1bb0-400d-8653-bdd275252f7c','送王瓘同年河南府司錄','司馬光','宋','宋诗','song-poetry','','[]','綵服昔爲兒，隨親宦洛師。',48,'全唐诗/poet.song.29000.json','["綵服昔爲兒，隨親宦洛師。", "至今餘夢想，常記舊遊嬉。", "佐史頭應白，書樓樹已欹。", "聞君行有日，使我淚交頤。"]'),
('3b984c9a-bdee-42f8-8b84-32b21a4dbb26','送王彦臣同年通判亳州','司馬光','宋','宋诗','song-poetry','','[]','先朝御六飛，親謁瀨鄉祠。',48,'全唐诗/poet.song.29000.json','["先朝御六飛，親謁瀨鄉祠。", "牛酒當時惠，衣冠此日思。", "仙蹤丹有竈，天瑞檜生枝。", "聖主憐耆舊，題輿得吏師。"]'),
('86df00c6-8c8f-488b-b09d-6eae05715d7d','正月二十四日夜雪','司馬光','宋','宋诗','song-poetry','','[]','疊瓦浮輕雪，參差粉畫難。',48,'全唐诗/poet.song.29000.json','["疊瓦浮輕雪，參差粉畫難。", "苦欺初變柳，故壓未生蘭。", "夜色微分白，春容不受寒。", "即爲花卉奪，猶得暫供看。"]'),
('452e9ba1-9b6e-49e5-a1f3-a172429f29d9','和道粹雪夜直宿','司馬光','宋','宋诗','song-poetry','','[]','天祿凝嚴近紫臺，書幃夜對雪華開。',64,'全唐诗/poet.song.29000.json','["天祿凝嚴近紫臺，書幃夜對雪華開。", "層樓直倚寒空出，清漏還從深殿來。", "薄夢不成冰柱折，曉光先到玉花催。", "兔園終是諸侯事，虚費相如能賦才。"]'),
('5d381100-9853-44b6-81f2-c2ed076546f8','和次道大慶殿上元迎駕','司馬光','宋','宋诗','song-poetry','','[]','鳳律年華到尚新，九重氣象已成春。',64,'全唐诗/poet.song.29000.json','["鳳律年華到尚新，九重氣象已成春。", "曉雲低拂羽林仗，宿雨先清紫陌塵。", "玉殿鳴鞘傳警蹕，彤庭委珮集簪紳。", "闕前無復魚龍戲，自有驩謠億萬人。"]'),
('dd4b19e8-a6fe-467f-a593-787c7d72ca63','送茹屯田知無爲軍','司馬光','宋','宋诗','song-poetry','','[]','疊鼓鳴鐃迎候新，軍牙孑孑倚淮津。',64,'全唐诗/poet.song.29000.json','["疊鼓鳴鐃迎候新，軍牙孑孑倚淮津。", "聊應衣繡過鄉曲，不作引章驚故人。", "荻迸短芽淝水暖，荷浮圓葉漅湖春。", "使君此去榮多少，猶是當年書劍身。"]'),
('12342345-bdf7-42ee-abb0-2c9d354060a9','田横墓','司馬光','宋','宋诗','song-poetry','','[]','昔時南面並稱孤，今日還爲絳灌徒。',64,'全唐诗/poet.song.29000.json','["昔時南面並稱孤，今日還爲絳灌徒。", "忍死祗能添屈辱，偷生不足愛須臾。", "一朝從殉傾羣客，千古生風激懦夫。", "直使強顔臣漢帝，韓彭未必免同誅。"]'),
('db8067fb-a045-4806-b0e3-b8565679747e','登平陸北山回瞰陜城奉寄李八丈學士使君二十二韻','司馬光','宋','宋诗','song-poetry','','[]','漢家二千石，體望向来尊。',264,'全唐诗/poet.song.29000.json','["漢家二千石，體望向来尊。", "况復嚴徐客，從前益稷孫。", "公侯貴不絕，禮樂器長存。", "符竹臨分陜，聲光應列藩。", "親闈先契重，子舍近交敦。", "柏壟依仁域，棠陰接故園。", "懷歸聊露請，予告入推恩。", "荷祋煩彊候，停車下郡門。", "帷廧紛大館，騶騎屈朱轓。", "不以黎苗待，還將臭味論。", "森羅牢禮重，滅裂俗儀煩。", "霜霽威嚴息，春生笑語温。", "草微侵碧甃，塵不染華軒。", "日影搖雲棟，風痕過玉樽。", "落塵歌迥出，激楚褏雙翻。", "雅戲象交局，珍肴熊薦蹯。", "河梁俄首路，汾曲訪吹塤。", "舉手辭雙戟，騰装改北轅。", "烏飛城樹曉，鴈泊野蕪暄。", "耿耿清標闊，涔涔宿酒昏。", "百蟠縈阪道，数里豁川原。", "跋馬風煙外，依稀鼓吹喧。"]'),
('9c1ea2e0-e2f9-4e99-b259-2120992d38fd','員村坂','司馬光','宋','宋诗','song-poetry','','[]','穹谷鬰盤紆，河瀕陜北隅。',120,'全唐诗/poet.song.29000.json','["穹谷鬰盤紆，河瀕陜北隅。", "泉流涓不絕，岡勢儼相扶。", "初旭紛高下，空煙似有無。", "石灘醒耳快，嶠樹脊雲孤。", "天霽嵐光活，人稀草色蘇。", "牧兒歌自若，樵子遠相呼。", "壞道傍連傳，空城右指虞。", "窮巖今寂寞，蔓草只荒蕪。", "野店寒餐澀，山程瘦馬瘏。", "物華供興趣，亦是慰崎嶇。"]'),
('5896e941-5ee9-4645-b6a4-70fee53a9f07','太行','司馬光','宋','宋诗','song-poetry','','[]','象帝胚渾散，愚公轍跡開。',216,'全唐诗/poet.song.29000.json','["象帝胚渾散，愚公轍跡開。", "横行四極外，蟠據九河隈。", "岪鬰天閽近，峥嶸地軸回。", "陽崖明草樹，陰壑轉風雷。", "波沓羣峰涌，雲奔峭壁來。", "猿巖垂磊落，龍窟鬭喧豗。", "噴雨驚湍灑，跳壘巨石頽。", "平途憂屐折，跬步戒輪摧。", "覆頂千春雪，緣潭萬古苔。", "谷盤容國士，髓裂餌仙才。", "晉市飛樵札，燕郊落燒煤。", "棋圖分冀野，蟻壤認叢臺。", "在昔王塗塞，嘗聞霸略恢。", "嚴關陰伏甲，間道夜銜枚。", "挾詐揮金斗，貪功襲墨縗。", "戰場空爝火，京觀悉蒿萊。", "險易曾何變，興亡只可哀。", "隆平方恃德，襟带自崔嵬。"]'),
('5837d247-2ab0-4cd1-9a79-af47f08f1fbb','石昌言學士宰中牟日爲詩見寄久未之答今冬罷武成幕来京師此詩謝之','司馬光','宋','宋诗','song-poetry','','[]','昔年三月浪，鱗翼化雲雷。',240,'全唐诗/poet.song.29000.json','["昔年三月浪，鱗翼化雲雷。", "竹箭流俱上，芙蓉幕對開。", "瀵泉揚沸渭，泰華聳崔嵬。", "捧檄容歸省，飛觴復屢陪。", "芬芳襲芝室，嘉慶侍蘭階。", "吳璧評殘筆，隋碑讀漬苔。", "清陰依玉樹，和氣樂春臺。", "薄宦俄成别，私門忽遇災。", "一朝捐綵服，五載泣粗縗。", "季路還從仕，任安獨見哀。", "近畿須健令，劇邑試長才。", "過目全牛解，迎鋒巨枿摧。", "雉留乘蔭伏，蝗避境苗迴。", "時得鳴琴暇，仍飛麗句來。", "正知榮篋笥，無足報璿瑰。", "紞鼓俄攀鄧，安車已召枚。", "賦成平樂館，燕奉柏梁杯。", "自顧誠駑緩，于今尚草萊。", "履穿羞路雪，蓋敝怯京埃。", "儻借餘光便，炎風動死灰。"]'),
('a3449521-ecda-4ac1-a8d1-0fe6095ddf17','昌言見督詩債戲呈絕句','司馬光','宋','宋诗','song-poetry','','[]','學餒才貧杼軸勞，踰年避債負詩豪。',32,'全唐诗/poet.song.29000.json','["學餒才貧杼軸勞，踰年避債負詩豪。", "倒囊不惜償虚劵，未敵瓊瑤舊價高。"]');
